{
  "name": "LendFlow Admin",
  "description": "A secure, internal-use admin dashboard for private money lenders to manage customers, track principal changes, and generate monthly interest reports."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Customer {
  id: string;
  name: string;
  phone: string;
  address: string;
  principal: number;
  interestRate: number; // Monthly percentage
  dueDate: number; // Day of the month (1-31)
  createdAt: number;
}

export interface Payment {
  id: string;
  customerId: string;
  month: number; // 0-11
  year: number;
  amountPaid: number;
  totalDue: number;
  status: 'Paid' | 'Partial' | 'Pending';
  timestamp: number;
}

export interface PrincipalLog {
  id: string;
  customerId: string;
  amountChange: number;
  newPrincipal: number;
  reason: string;
  timestamp: number;
}

export interface AdminUser {
  email: string;
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Customers from './pages/Customers';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import Login from './pages/Login';

// Mock Auth logic for the scope of this project
// In a real environment, use firebase/auth
const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('isLoggedIn') === 'true';
  });

  const handleLogin = (success: boolean) => {
    setIsAuthenticated(success);
    if (success) localStorage.setItem('isLoggedIn', 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('isLoggedIn');
  };

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 overflow-hidden">
        <Sidebar onLogout={handleLogout} />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/customers" element={<Customers />} />
            <Route path="/customers/:id" element={<CustomerDetails />} />
            <Route path="/reports" element={<Reports />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import { NavLink } from 'react-router-dom';

interface SidebarProps {
  onLogout: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ onLogout }) => {
  const navItems = [
    { to: '/', icon: 'fa-chart-pie', label: 'Dashboard' },
    { to: '/customers', icon: 'fa-users', label: 'Customers' },
    { to: '/reports', icon: 'fa-file-invoice-dollar', label: 'Reports' },
  ];

  return (
    <aside className="w-64 bg-white border-r border-slate-200 hidden md:flex flex-col">
      <div className="p-6">
        <h1 className="text-xl font-bold text-blue-600 flex items-center gap-2">
          <i className="fas fa-hand-holding-usd"></i>
          LendFlow
        </h1>
      </div>

      <nav className="flex-1 px-4 space-y-1">
        {navItems.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            className={({ isActive }) =>
              `flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
                isActive
                  ? 'bg-blue-50 text-blue-600 font-medium'
                  : 'text-slate-600 hover:bg-slate-50'
              }`
            }
          >
            <i className={`fas ${item.icon} w-5`}></i>
            {item.label}
          </NavLink>
        ))}
      </nav>

      <div className="p-4 border-t border-slate-200">
        <button
          onClick={onLogout}
          className="flex items-center gap-3 px-4 py-3 w-full text-left rounded-lg text-red-600 hover:bg-red-50 transition-all"
        >
          <i className="fas fa-sign-out-alt w-5"></i>
          Logout
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import { Link } from 'react-router-dom';

const Dashboard: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);

  // Load mock data on mount
  useEffect(() => {
    const savedCustomers = localStorage.getItem('customers');
    const savedPayments = localStorage.getItem('payments');
    if (savedCustomers) setCustomers(JSON.parse(savedCustomers));
    if (savedPayments) setPayments(JSON.parse(savedPayments));
  }, []);

  const totalPrincipal = customers.reduce((sum, c) => sum + c.principal, 0);

  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();
  const today = new Date().getDate();

  const monthlyIncome = payments
    .filter(p => p.month === currentMonth && p.year === currentYear)
    .reduce((sum, p) => sum + p.amountPaid, 0);

  const dueToday = customers.filter(c => c.dueDate === today);

  const overdue = customers.filter(c => {
    const payment = payments.find(p => p.customerId === c.id && p.month === currentMonth && p.year === currentYear);
    const isOverdue = today > c.dueDate && (!payment || payment.status !== 'Paid');
    return isOverdue && c.principal > 0;
  });

  return (
    <div className="space-y-6">
      <header>
        <h2 className="text-2xl font-bold text-slate-800">Admin Dashboard</h2>
        <p className="text-slate-500">Business overview and task summary</p>
      </header>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          label="Total Customers" 
          value={customers.length.toString()} 
          icon="fa-users" 
          color="bg-blue-500" 
        />
        <StatCard 
          label="Outstanding Principal" 
          value={`$${totalPrincipal.toLocaleString()}`} 
          icon="fa-money-bill-wave" 
          color="bg-emerald-500" 
        />
        <StatCard 
          label="Income (This Month)" 
          value={`$${monthlyIncome.toLocaleString()}`} 
          icon="fa-hand-holding-dollar" 
          color="bg-amber-500" 
        />
        <StatCard 
          label="Overdue Loans" 
          value={overdue.length.toString()} 
          icon="fa-clock" 
          color="bg-rose-500" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Due Today Section */}
        <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <i className="fas fa-calendar-day text-blue-500"></i>
            Due Today
          </h3>
          <div className="space-y-3">
            {dueToday.length > 0 ? (
              dueToday.map(c => (
                <div key={c.id} className="flex justify-between items-center p-3 bg-slate-50 rounded-lg">
                  <div>
                    <p className="font-medium">{c.name}</p>
                    <p className="text-xs text-slate-500">{c.phone}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-semibold text-blue-600">${(c.principal * c.interestRate / 100).toLocaleString()}</p>
                    <Link to={`/customers/${c.id}`} className="text-xs text-blue-500 hover:underline">View Details</Link>
                  </div>
                </div>
              ))
            ) : (
              <p className="text-slate-400 text-center py-4">No payments due today.</p>
            )}
          </div>
        </section>

        {/* Overdue Section */}
        <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
            <i className="fas fa-exclamation-triangle text-rose-500"></i>
            Overdue Customers
          </h3>
          <div className="space-y-3">
            {overdue.length > 0 ? (
              overdue.map(c => (
                <div key={c.id} className="flex justify-between items-center p-3 bg-rose-50 rounded-lg">
                  <div>
                    <p className="font-medium text-rose-800">{c.name}</p>
                    <p className="text-xs text-rose-600">Due on: {c.dueDate}th</p>
                  </div>
                  <div className="text-right">
                    <p className="font-semibold text-rose-700">${(c.principal * c.interestRate / 100).toLocaleString()}</p>
                    <Link to={`/customers/${c.id}`} className="text-xs text-rose-500 hover:underline font-medium">Collect Now</Link>
                  </div>
                </div>
              ))
            ) : (
              <p className="text-slate-400 text-center py-4">All accounts are up to date!</p>
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: string; color: string }> = ({ label, value, icon, color }) => (
  <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm flex items-center gap-4">
    <div className={`${color} w-12 h-12 rounded-lg flex items-center justify-center text-white text-xl`}>
      <i className={`fas ${icon}`}></i>
    </div>
    <div>
      <p className="text-sm text-slate-500">{label}</p>
      <p className="text-xl font-bold text-slate-800">{value}</p>
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Customer } from '../types';

const Customers: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newCustomer, setNewCustomer] = useState<Partial<Customer>>({
    name: '', phone: '', address: '', principal: 0, interestRate: 5, dueDate: 1
  });

  useEffect(() => {
    const saved = localStorage.getItem('customers');
    if (saved) setCustomers(JSON.parse(saved));
  }, []);

  const handleAddCustomer = (e: React.FormEvent) => {
    e.preventDefault();
    const customer: Customer = {
      ...newCustomer as Customer,
      id: Date.now().toString(),
      createdAt: Date.now()
    };
    const updated = [...customers, customer];
    setCustomers(updated);
    localStorage.setItem('customers', JSON.stringify(updated));
    setIsModalOpen(false);
    setNewCustomer({ name: '', phone: '', address: '', principal: 0, interestRate: 5, dueDate: 1 });
  };

  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    c.phone.includes(searchTerm)
  );

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Customers</h2>
          <p className="text-slate-500">Manage your lender portfolio</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-blue-700 transition-colors flex items-center gap-2"
        >
          <i className="fas fa-plus"></i> Add Customer
        </button>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-200 bg-slate-50">
          <div className="relative max-w-sm">
            <i className="fas fa-search absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
            <input 
              type="text" 
              placeholder="Search by name or phone..."
              className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <table className="w-full text-left text-sm">
          <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
            <tr>
              <th className="px-6 py-3">Customer Name</th>
              <th className="px-6 py-3">Phone</th>
              <th className="px-6 py-3">Principal</th>
              <th className="px-6 py-3">Due Day</th>
              <th className="px-6 py-3">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredCustomers.map(c => (
              <tr key={c.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4">
                  <span className="font-semibold text-slate-800">{c.name}</span>
                </td>
                <td className="px-6 py-4 text-slate-600">{c.phone}</td>
                <td className="px-6 py-4 font-medium text-slate-800">${c.principal.toLocaleString()}</td>
                <td className="px-6 py-4">
                  <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded text-xs font-bold uppercase">
                    Day {c.dueDate}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    <Link to={`/customers/${c.id}`} className="text-blue-600 hover:text-blue-800">
                      <i className="fas fa-eye"></i>
                    </Link>
                    <a href={`tel:${c.phone}`} className="text-emerald-600 hover:text-emerald-800">
                      <i className="fas fa-phone"></i>
                    </a>
                  </div>
                </td>
              </tr>
            ))}
            {filteredCustomers.length === 0 && (
              <tr>
                <td colSpan={5} className="px-6 py-10 text-center text-slate-400">
                  No customers found. Click "Add Customer" to get started.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Add Customer Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl w-full max-w-md shadow-xl overflow-hidden">
            <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center">
              <h3 className="text-lg font-bold">New Customer Enrollment</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleAddCustomer} className="p-6 space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Full Name</label>
                <input required type="text" className="w-full px-3 py-2 border rounded-lg" value={newCustomer.name} onChange={e => setNewCustomer({...newCustomer, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Phone</label>
                  <input required type="tel" className="w-full px-3 py-2 border rounded-lg" value={newCustomer.phone} onChange={e => setNewCustomer({...newCustomer, phone: e.target.value})} />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Monthly Int. %</label>
                  <input required type="number" step="0.1" className="w-full px-3 py-2 border rounded-lg" value={newCustomer.interestRate} onChange={e => setNewCustomer({...newCustomer, interestRate: parseFloat(e.target.value)})} />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Initial Principal</label>
                  <input required type="number" className="w-full px-3 py-2 border rounded-lg" value={newCustomer.principal} onChange={e => setNewCustomer({...newCustomer, principal: parseFloat(e.target.value)})} />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Due Date (Day)</label>
                  <input required type="number" min="1" max="31" className="w-full px-3 py-2 border rounded-lg" value={newCustomer.dueDate} onChange={e => setNewCustomer({...newCustomer, dueDate: parseInt(e.target.value)})} />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Address</label>
                <textarea className="w-full px-3 py-2 border rounded-lg" value={newCustomer.address} onChange={e => setNewCustomer({...newCustomer, address: e.target.value})}></textarea>
              </div>
              <button type="submit" className="w-full bg-blue-600 text-white py-2 rounded-lg font-bold hover:bg-blue-700 transition-colors">
                Create Record
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Customers;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';

const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  // Principal Update State
  const [principalChange, setPrincipalChange] = useState({ amount: 0, reason: '', type: 'increase' });

  // Payment Update State
  const [paymentInput, setPaymentInput] = useState({ amount: 0, month: new Date().getMonth(), year: new Date().getFullYear() });

  useEffect(() => {
    const customersRaw = localStorage.getItem('customers');
    const paymentsRaw = localStorage.getItem('payments');
    const logsRaw = localStorage.getItem('principalLogs');

    if (customersRaw) {
      const c = JSON.parse(customersRaw).find((x: any) => x.id === id);
      if (c) setCustomer(c);
      else navigate('/customers');
    }
    if (paymentsRaw) setPayments(JSON.parse(paymentsRaw).filter((p: any) => p.customerId === id));
    if (logsRaw) setPrincipalLogs(JSON.parse(logsRaw).filter((l: any) => l.customerId === id));
  }, [id, navigate]);

  const updateGlobal = (key: string, data: any[]) => {
    const raw = localStorage.getItem(key);
    let all = raw ? JSON.parse(raw) : [];

    if (key === 'customers') {
      all = all.map((c: any) => c.id === id ? data[0] : c);
    } else {
      // For payments and logs, merge with others
      const others = all.filter((x: any) => x.customerId !== id);
      all = [...others, ...data];
    }
    localStorage.setItem(key, JSON.stringify(all));
  };

  const handleUpdatePrincipal = () => {
    if (!customer) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;

    const updatedCustomer = { ...customer, principal: newP };
    const newLog: PrincipalLog = {
      id: Date.now().toString(),
      customerId: customer.id,
      amountChange: diff,
      newPrincipal: newP,
      reason: principalChange.reason || 'Manual Adjustment',
      timestamp: Date.now()
    };

    setCustomer(updatedCustomer);
    setPrincipalLogs([...principalLogs, newLog]);
    updateGlobal('customers', [updatedCustomer]);
    updateGlobal('principalLogs', [...principalLogs, newLog]);
    setShowPrincipalModal(false);
  };

  const handleAddPayment = () => {
    if (!customer) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const newPayment: Payment = {
      id: Date.now().toString(),
      customerId: customer.id,
      month: paymentInput.month,
      year: paymentInput.year,
      amountPaid: paymentInput.amount,
      totalDue: totalDue,
      status: status,
      timestamp: Date.now()
    };

    const updatedPayments = [...payments, newPayment];
    setPayments(updatedPayments);
    updateGlobal('payments', updatedPayments);
    setShowPaymentModal(false);
  };

  if (!customer) return <div className="p-8 text-center">Loading customer...</div>;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-start">
        <div>
          <button onClick={() => navigate('/customers')} className="text-sm text-blue-600 mb-2 hover:underline flex items-center gap-1">
            <i className="fas fa-chevron-left"></i> Back to Customers
          </button>
          <h2 className="text-3xl font-bold text-slate-800">{customer.name}</h2>
          <p className="text-slate-500">{customer.address || 'No address provided'}</p>
        </div>
        <div className="flex gap-2">
          <a href={`tel:${customer.phone}`} className="bg-emerald-100 text-emerald-700 px-4 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-emerald-200">
            <i className="fas fa-phone"></i> Call
          </a>
          <button onClick={() => setShowPrincipalModal(true)} className="bg-blue-600 text-white px-4 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-blue-700">
            <i className="fas fa-edit"></i> Edit Principal
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <p className="text-xs text-slate-500 font-bold uppercase mb-1">Current Principal</p>
          <p className="text-3xl font-black text-slate-900">${customer.principal.toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <p className="text-xs text-slate-500 font-bold uppercase mb-1">Monthly Interest ({customer.interestRate}%)</p>
          <p className="text-3xl font-black text-blue-600">${((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <p className="text-xs text-slate-500 font-bold uppercase mb-1">Payment Status</p>
          <div className="mt-2">
            <span className="bg-blue-100 text-blue-700 px-3 py-1 rounded-full text-sm font-bold">
              Due on Day {customer.dueDate}
            </span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Payment History */}
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50">
            <h3 className="font-bold text-slate-800">Interest Payment History</h3>
            <button onClick={() => setShowPaymentModal(true)} className="text-blue-600 text-sm font-bold hover:underline">
              + Log Payment
            </button>
          </div>
          <table className="w-full text-sm">
            <thead className="bg-slate-50 border-b text-slate-500 text-left">
              <tr>
                <th className="px-6 py-3">Month/Year</th>
                <th className="px-6 py-3">Due</th>
                <th className="px-6 py-3">Paid</th>
                <th className="px-6 py-3">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {payments.sort((a,b) => b.timestamp - a.timestamp).map(p => (
                <tr key={p.id}>
                  <td className="px-6 py-4">{new Date(p.year, p.month).toLocaleString('default', { month: 'short', year: 'numeric' })}</td>
                  <td className="px-6 py-4">${p.totalDue.toLocaleString()}</td>
                  <td className="px-6 py-4 font-bold text-emerald-600">${p.amountPaid.toLocaleString()}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded text-xs font-bold ${
                      p.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                      p.status === 'Partial' ? 'bg-amber-100 text-amber-700' : 'bg-rose-100 text-rose-700'
                    }`}>
                      {p.status}
                    </span>
                  </td>
                </tr>
              ))}
              {payments.length === 0 && (
                <tr><td colSpan={4} className="p-8 text-center text-slate-400 italic">No payment history found.</td></tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Principal Logs */}
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-slate-200 bg-slate-50">
            <h3 className="font-bold text-slate-800">Principal Audit Log</h3>
          </div>
          <table className="w-full text-sm">
            <thead className="bg-slate-50 border-b text-slate-500 text-left">
              <tr>
                <th className="px-6 py-3">Date</th>
                <th className="px-6 py-3">Adjustment</th>
                <th className="px-6 py-3">New Balance</th>
                <th className="px-6 py-3">Reason</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {principalLogs.sort((a,b) => b.timestamp - a.timestamp).map(l => (
                <tr key={l.id}>
                  <td className="px-6 py-4 text-slate-500">{new Date(l.timestamp).toLocaleDateString()}</td>
                  <td className={`px-6 py-4 font-bold ${l.amountChange > 0 ? 'text-blue-600' : 'text-rose-600'}`}>
                    {l.amountChange > 0 ? '+' : ''}{l.amountChange.toLocaleString()}
                  </td>
                  <td className="px-6 py-4">${l.newPrincipal.toLocaleString()}</td>
                  <td className="px-6 py-4 text-slate-600">{l.reason}</td>
                </tr>
              ))}
              {principalLogs.length === 0 && (
                <tr><td colSpan={4} className="p-8 text-center text-slate-400 italic">No principal changes recorded.</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modals */}
      {showPrincipalModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl w-full max-w-sm p-6 shadow-xl">
            <h3 className="text-lg font-bold mb-4">Update Principal Amount</h3>
            <div className="space-y-4">
              <div className="flex gap-2 p-1 bg-slate-100 rounded-lg">
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'increase'})}
                  className={`flex-1 py-1 rounded ${principalChange.type === 'increase' ? 'bg-white shadow-sm text-blue-600 font-bold' : 'text-slate-500'}`}
                >Add (Loan)</button>
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'decrease'})}
                  className={`flex-1 py-1 rounded ${principalChange.type === 'decrease' ? 'bg-white shadow-sm text-rose-600 font-bold' : 'text-slate-500'}`}
                >Reduce (Pay)</button>
              </div>
              <input type="number" placeholder="Amount" className="w-full p-2 border rounded-lg" onChange={e => setPrincipalChange({...principalChange, amount: parseFloat(e.target.value)})} />
              <input type="text" placeholder="Reason (e.g. Extra 5k taken)" className="w-full p-2 border rounded-lg" onChange={e => setPrincipalChange({...principalChange, reason: e.target.value})} />
              <div className="flex gap-2">
                <button onClick={() => setShowPrincipalModal(false)} className="flex-1 py-2 text-slate-500 font-bold">Cancel</button>
                <button onClick={handleUpdatePrincipal} className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-bold">Update</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showPaymentModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-xl w-full max-w-sm p-6 shadow-xl">
            <h3 className="text-lg font-bold mb-4">Log Interest Payment</h3>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-2">
                <select className="p-2 border rounded-lg" value={paymentInput.month} onChange={e => setPaymentInput({...paymentInput, month: parseInt(e.target.value)})}>
                  {Array.from({length: 12}).map((_, i) => <option key={i} value={i}>{new Date(0, i).toLocaleString('default', {month: 'long'})}</option>)}
                </select>
                <select className="p-2 border rounded-lg" value={paymentInput.year} onChange={e => setPaymentInput({...paymentInput, year: parseInt(e.target.value)})}>
                  <option value={2024}>2024</option>
                  <option value={2025}>2025</option>
                </select>
              </div>
              <div>
                <p className="text-xs text-slate-500 mb-1">Recommended Interest Due: <strong>${((customer.principal * customer.interestRate)/100).toLocaleString()}</strong></p>
                <input type="number" placeholder="Amount Paid" className="w-full p-2 border rounded-lg" onChange={e => setPaymentInput({...paymentInput, amount: parseFloat(e.target.value)})} />
              </div>
              <div className="flex gap-2">
                <button onClick={() => setShowPaymentModal(false)} className="flex-1 py-2 text-slate-500 font-bold">Cancel</button>
                <button onClick={handleAddPayment} className="flex-1 py-2 bg-emerald-600 text-white rounded-lg font-bold">Log Payment</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

