import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

const Reports: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  useEffect(() => {
    const c = localStorage.getItem('customers');
    const p = localStorage.getItem('payments');
    if (c) setCustomers(JSON.parse(c));
    if (p) setPayments(JSON.parse(p));
  }, []);

  const generatePDF = () => {
    const doc = new jsPDF();
    const monthName = new Date(selectedYear, selectedMonth).toLocaleString('default', { month: 'long' });

    doc.setFontSize(20);
    doc.text('Monthly Interest Report', 14, 22);
    doc.setFontSize(12);
    doc.text(`Period: ${monthName} ${selectedYear}`, 14, 30);

    const tableData = customers.map(c => {
      const payment = payments.find(p => p.customerId === c.id && p.month === selectedMonth && p.year === selectedYear);
      const interestDue = (c.principal * c.interestRate) / 100;
      return [
        c.name,
        `$${c.principal.toLocaleString()}`,
        `$${interestDue.toLocaleString()}`,
        payment ? `$${payment.amountPaid.toLocaleString()}` : '$0',
        payment ? payment.status : (c.principal > 0 ? 'Pending' : 'N/A')
      ];
    });

    autoTable(doc, {
      startY: 40,
      head: [['Customer Name', 'Capital Balance', 'Interest Due', 'Interest Paid', 'Status']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: [37, 99, 235] }
    });

    // Summary Calculations
    const totalCollected = payments
      .filter(p => p.month === selectedMonth && p.year === selectedYear)
      .reduce((sum, p) => sum + p.amountPaid, 0);

    const totalDue = customers.reduce((sum, c) => sum + (c.principal * c.interestRate / 100), 0);
    const totalOutstanding = customers.reduce((sum, c) => sum + c.principal, 0);

    const finalY = (doc as any).lastAutoTable.finalY + 10;
    doc.setFontSize(14);
    doc.text('Summary Statement', 14, finalY);
    doc.setFontSize(11);
    doc.text(`Total Monthly Income (Interest Collected): $${totalCollected.toLocaleString()}`, 14, finalY + 10);
    doc.text(`Total Pending Interest: $${(totalDue - totalCollected).toLocaleString()}`, 14, finalY + 18);
    doc.text(`Total Outstanding Capital: $${totalOutstanding.toLocaleString()}`, 14, finalY + 26);

    doc.save(`LendFlow_Report_${monthName}_${selectedYear}.pdf`);
  };

  return (
    <div className="space-y-6">
      <header>
        <h2 className="text-2xl font-bold text-slate-800">Financial Reports</h2>
        <p className="text-slate-500">Generate and export monthly interest statements</p>
      </header>

      <div className="bg-white p-8 rounded-xl border border-slate-200 shadow-sm max-w-2xl mx-auto">
        <div className="text-center mb-8">
          <i className="fas fa-file-pdf text-6xl text-rose-500 mb-4"></i>
          <h3 className="text-xl font-bold">Monthly PDF Statement</h3>
          <p className="text-slate-500">Select the period to generate a detailed repayment report for all active customers.</p>
        </div>

        <div className="grid grid-cols-2 gap-4 mb-8">
          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase">Month</label>
            <select 
              className="w-full p-3 border rounded-lg bg-slate-50"
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
            >
              {Array.from({length: 12}).map((_, i) => (
                <option key={i} value={i}>{new Date(0, i).toLocaleString('default', {month: 'long'})}</option>
              ))}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase">Year</label>
            <select 
              className="w-full p-3 border rounded-lg bg-slate-50"
              value={selectedYear}
              onChange={(e) => setSelectedYear(parseInt(e.target.value))}
            >
              <option value={2024}>2024</option>
              <option value={2025}>2025</option>
            </select>
          </div>
        </div>

        <button 
          onClick={generatePDF}
          className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-blue-700 transition-all flex items-center justify-center gap-3"
        >
          <i className="fas fa-download"></i>
          Generate & Download Report
        </button>

        <p className="text-center text-slate-400 text-xs mt-4 italic">
          Report includes: Customer list, Capital balance, Interest tracking, and Portfolio summary.
        </p>
      </div>
    </div>
  );
};

export default Reports;

