    doc.text(`$${(totalDue - totalCollected).toLocaleString()}`, 150, finalY + 27, { align: 'right' });

    doc.text(`Total Active Capital (Outstanding):`, 20, finalY + 34);
    doc.text(`$${totalOutstanding.toLocaleString()}`, 150, finalY + 34, { align: 'right' });

    doc.save(`LendFlow_${monthName}_${selectedYear}.pdf`);
  };

  return (
    <div className="space-y-8 animate-in">
      <header className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Reports</h2>
          <p className="text-slate-500 font-medium">Portfolio insights and financial PDF exports</p>
        </div>
        <button 
          onClick={resetToCurrent}
          className="text-sm font-bold text-violet-600 hover:bg-violet-50 px-4 py-2 rounded-xl transition-all"
        >
          Reset to Current Month
        </button>
      </header>

      <div className="bg-white p-12 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 max-w-2xl mx-auto text-center relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-violet-50 rounded-full -mr-16 -mt-16 opacity-50"></div>

        <div className="relative z-10">
          <div className="w-24 h-24 bg-violet-100 text-violet-600 rounded-3xl flex items-center justify-center text-4xl mx-auto mb-6 shadow-lg shadow-violet-100">
            <i className="fas fa-file-invoice"></i>
          </div>
          <h3 className="text-2xl font-black text-slate-900 mb-2">Monthly Statement</h3>
          <p className="text-slate-500 mb-10 max-w-sm mx-auto font-medium">Select a month and year to download the complete repayment and balance report.</p>

          <div className="grid grid-cols-2 gap-6 mb-10">
            <div className="text-left space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Period</label>
              <select 
                className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-violet-200 focus:border-violet-400 transition-all font-bold text-slate-700"
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              >
                {Array.from({length: 12}).map((_, i) => (
                  <option key={i} value={i}>{new Date(0, i).toLocaleString('default', {month: 'long'})}</option>
                ))}
              </select>
            </div>
            <div className="text-left space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Year</label>
              <select 
                className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-violet-200 focus:border-violet-400 transition-all font-bold text-slate-700"
                value={selectedYear}
                onChange={(e) => setSelectedYear(parseInt(e.target.value))}
              >
                <option value={2024}>2024</option>
                <option value={2025}>2025</option>
              </select>
            </div>
          </div>

          <button 
            onClick={generatePDF}
            className="w-full bg-violet-600 text-white py-5 rounded-2xl font-black text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 flex items-center justify-center gap-3 active:scale-[0.98]"
          >
            <i className="fas fa-cloud-download-alt"></i>
