          <table className="w-full">
            <thead className="bg-slate-50/50 border-b text-slate-400 text-left">
              <tr>
                <th className="px-8 py-4 text-[10px] font-black uppercase tracking-widest">Timestamp</th>
                <th className="px-8 py-4 text-[10px] font-black uppercase tracking-widest">Adjustment</th>
                <th className="px-8 py-4 text-[10px] font-black uppercase tracking-widest">New Balance</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
