import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';

const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [principalChange, setPrincipalChange] = useState({ amount: 0, reason: '', type: 'increase' });
  const [paymentInput, setPaymentInput] = useState({ amount: 0, month: new Date().getMonth(), year: new Date().getFullYear() });

  useEffect(() => {
    const customersRaw = localStorage.getItem('customers');
    const paymentsRaw = localStorage.getItem('payments');
    const logsRaw = localStorage.getItem('principalLogs');

    if (customersRaw) {
      const c = JSON.parse(customersRaw).find((x: any) => x.id === id);
      if (c) setCustomer(c);
      else navigate('/customers');
    }
    if (paymentsRaw) setPayments(JSON.parse(paymentsRaw).filter((p: any) => p.customerId === id));
    if (logsRaw) setPrincipalLogs(JSON.parse(logsRaw).filter((l: any) => l.customerId === id));
  }, [id, navigate]);

  const updateGlobal = (key: string, data: any[]) => {
    const raw = localStorage.getItem(key);
    let all = raw ? JSON.parse(raw) : [];
    if (key === 'customers') {
      all = all.map((c: any) => c.id === id ? data[0] : c);
    } else {
      const others = all.filter((x: any) => x.customerId !== id);
      all = [...others, ...data];
    }
    localStorage.setItem(key, JSON.stringify(all));
  };

  const handleUpdatePrincipal = () => {
    if (!customer) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;
    const updatedCustomer = { ...customer, principal: newP };
    const newLog: PrincipalLog = { id: Date.now().toString(), customerId: customer.id, amountChange: diff, newPrincipal: newP, reason: principalChange.reason || 'Manual Adjustment', timestamp: Date.now() };
    setCustomer(updatedCustomer);
    setPrincipalLogs([...principalLogs, newLog]);
    updateGlobal('customers', [updatedCustomer]);
    updateGlobal('principalLogs', [...principalLogs, newLog]);
    setShowPrincipalModal(false);
  };

  const handleAddPayment = () => {
    if (!customer) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');
    const newPayment: Payment = { id: Date.now().toString(), customerId: customer.id, month: paymentInput.month, year: paymentInput.year, amountPaid: paymentInput.amount, totalDue: totalDue, status: status, timestamp: Date.now() };
    const updatedPayments = [...payments, newPayment];
    setPayments(updatedPayments);
    updateGlobal('payments', updatedPayments);
    setShowPaymentModal(false);
  };

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4">
        <div className="space-y-2">
          <button onClick={() => navigate('/customers')} className="text-[10px] font-black text-violet-600 hover:bg-violet-50 px-3 py-1.5 rounded-lg uppercase tracking-widest transition-all">
            <i className="fas fa-arrow-left mr-2"></i> Portfolio
          </button>
          <h2 className="text-2xl md:text-4xl font-black text-slate-900 tracking-tight">{customer.name}</h2>
          <p className="text-sm text-slate-500 font-medium flex items-center gap-2">
            <i className="fas fa-location-dot text-slate-300"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a href={`tel:${customer.phone}`} className="bg-emerald-100 text-emerald-700 w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center hover:bg-emerald-200 transition-all shadow-lg shadow-emerald-50">
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button onClick={() => setShowPrincipalModal(true)} className="flex-1 md:flex-none bg-violet-600 text-white px-6 py-3 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-sm md:text-base">
            <i className="fas fa-coins"></i> Manage Capital
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 md:gap-8">
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Principal</p>
          <p className="text-2xl md:text-4xl font-black text-slate-900 leading-none">${customer.principal.toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-2">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Interest ({customer.interestRate}%)</p>
          <p className="text-2xl md:text-4xl font-black text-violet-600 leading-none">${((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-3">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Next Billing</p>
