import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import { Link } from 'react-router-dom';

const Dashboard: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);

  useEffect(() => {
    const savedCustomers = localStorage.getItem('customers');
    const savedPayments = localStorage.getItem('payments');
    if (savedCustomers) setCustomers(JSON.parse(savedCustomers));
    if (savedPayments) setPayments(JSON.parse(savedPayments));
  }, []);

  const totalPrincipal = customers.reduce((sum, c) => sum + c.principal, 0);
  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();
  const today = new Date().getDate();

  const monthlyIncome = payments
    .filter(p => p.month === currentMonth && p.year === currentYear)
    .reduce((sum, p) => sum + p.amountPaid, 0);

  const dueToday = customers.filter(c => c.dueDate === today);
  const overdue = customers.filter(c => {
    const payment = payments.find(p => p.customerId === c.id && p.month === currentMonth && p.year === currentYear);
    const isOverdue = today > c.dueDate && (!payment || payment.status !== 'Paid');
    return isOverdue && c.principal > 0;
  });

  return (
    <div className="space-y-6 md:space-y-8 animate-in">
      <header>
        <h2 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tight">Overview</h2>
        <p className="text-slate-500 font-medium text-sm md:text-base">Portfolio summary and alerts.</p>
      </header>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        <StatCard label="Active" value={customers.length.toString()} icon="fa-users" color="bg-violet-600" delay="delay-1" />
        <StatCard label="Capital" value={`₹${totalPrincipal.toLocaleString()}`} icon="fa-money-bill-wave" color="bg-slate-900" delay="delay-2" />
        <StatCard label="Income" value={`₹${monthlyIncome.toLocaleString()}`} icon="fa-hand-holding-dollar" color="bg-violet-500" delay="delay-3" />
        <StatCard label="Action" value={overdue.length.toString()} icon="fa-clock" color="bg-rose-500" delay="delay-1" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <section className="bg-white p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-100 shadow-sm animate-in delay-2">
          <h3 className="text-lg md:text-xl font-bold mb-4 md:mb-6 flex items-center gap-3">
            <span className="w-8 h-8 md:w-10 md:h-10 rounded-full bg-violet-100 text-violet-600 flex items-center justify-center">
              <i className="fas fa-calendar-day text-sm md:text-base"></i>
            </span>
            Due Today
          </h3>
          <div className="space-y-3">
            {dueToday.length > 0 ? (
              dueToday.map(c => (
                <div key={c.id} className="flex justify-between items-center p-3 md:p-4 hover:bg-slate-50 rounded-xl md:rounded-2xl border border-transparent hover:border-slate-100 transition-all">
                  <div>
                    <p className="font-bold text-slate-800 text-sm md:text-base">{c.name}</p>
                    <p className="text-xs text-slate-400">{c.phone}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-violet-600 text-sm md:text-base">₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                    <Link to={`/customers/${c.id}`} className="text-[10px] font-bold text-slate-400 hover:text-violet-600 uppercase tracking-widest">Details</Link>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-6 md:py-10">
                <p className="text-slate-300 font-medium text-sm">No repayments due today.</p>
              </div>
            )}
          </div>
        </section>

        <section className="bg-white p-6 md:p-8 rounded-2xl md:rounded-3xl border border-slate-100 shadow-sm animate-in delay-3">
          <h3 className="text-lg md:text-xl font-bold mb-4 md:mb-6 flex items-center gap-3">
            <span className="w-8 h-8 md:w-10 md:h-10 rounded-full bg-rose-100 text-rose-600 flex items-center justify-center">
              <i className="fas fa-exclamation-triangle text-sm md:text-base"></i>
            </span>
            Overdue
          </h3>
          <div className="space-y-3">
            {overdue.length > 0 ? (
              overdue.map(c => (
                <div key={c.id} className="flex justify-between items-center p-3 md:p-4 bg-rose-50/50 rounded-xl md:rounded-2xl border border-rose-100 transition-all">
                  <div>
                    <p className="font-bold text-rose-900 text-sm md:text-base">{c.name}</p>
                    <p className="text-[10px] font-bold text-rose-400 uppercase tracking-wider">Due: {c.dueDate}th</p>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-rose-700 text-sm md:text-base">₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                    <Link to={`/customers/${c.id}`} className="text-[10px] font-bold text-rose-500 hover:underline uppercase tracking-widest">Collect</Link>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-6 md:py-10">
                <p className="text-slate-300 font-medium text-sm">All accounts current!</p>
              </div>
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

