              </thead>
              <tbody className="divide-y divide-slate-50">
                {principalLogs.sort((a,b) => b.timestamp - a.timestamp).map(l => (
                  <tr key={l.id}>
                    <td className="px-6 md:px-8 py-4 text-slate-400 text-[11px] md:text-sm font-medium">
