                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="flex gap-2 w-full md:w-auto">
              <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex-1 md:flex-none px-5 py-3 rounded-xl border font-bold text-xs uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${
