                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Interest % (M)</label>
                  <input required type="number" step="0.1" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.interestRate} onChange={e => setNewCustomer({...newCustomer, interestRate: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Auto Due Day (1-31)</label>
                  <input required type="number" min="1" max="31" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.dueDate} onChange={e => setNewCustomer({...newCustomer, dueDate: parseInt(e.target.value)})} />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Opening Capital</label>
                <input required type="number" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-violet-600 text-sm" value={newCustomer.principal} onChange={e => setNewCustomer({...newCustomer, principal: parseFloat(e.target.value)})} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Residential Address</label>
                <textarea rows={2} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.address} onChange={e => setNewCustomer({...newCustomer, address: e.target.value})}></textarea>
              </div>

              <button type="submit" className="w-full bg-violet-600 text-white py-4 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 shrink-0">
                Enroll Borrower
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Customers;

import React, { useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Customers from './pages/Customers';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import Login from './pages/Login';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('isLoggedIn') === 'true';
  });
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const handleLogin = (success: boolean) => {
    setIsAuthenticated(success);
    if (success) localStorage.setItem('isLoggedIn', 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('isLoggedIn');
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);
  const closeSidebar = () => setIsSidebarOpen(false);

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-transparent overflow-hidden relative">
        {/* Mobile Header */}
        <div className="md:hidden fixed top-0 left-0 right-0 h-16 bg-white/80 backdrop-blur-md border-b border-slate-100 flex items-center justify-between px-4 z-40">
          <h1 className="text-xl font-black text-violet-600 tracking-tighter uppercase">LendFlow</h1>
          <button 
            onClick={toggleSidebar} 
            className="w-10 h-10 flex items-center justify-center text-slate-500"
            title={isSidebarOpen ? "Close navigation menu" : "Open navigation menu"}
          >
            <i className={`fas ${isSidebarOpen ? 'fa-times' : 'fa-bars'} text-xl`}></i>
          </button>
        </div>

        {/* Sidebar Overlay for Mobile */}
        {isSidebarOpen && (
          <div 
            className="md:hidden fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 transition-opacity"
            onClick={closeSidebar}
          />
        )}

        <Sidebar 
          onLogout={handleLogout} 
          isOpen={isSidebarOpen} 
          onClose={closeSidebar} 
        />

        <main className="flex-1 overflow-y-auto pt-20 md:pt-8 px-4 pb-12 md:px-8">
          <div className="max-w-7xl mx-auto">
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/customers" element={<Customers />} />
              <Route path="/customers/:id" element={<CustomerDetails />} />
              <Route path="/reports" element={<Reports />} />
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </div>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

