              <i className="fas fa-exclamation-triangle text-sm md:text-base"></i>
            </span>
            Overdue
          </h3>
          <div className="space-y-3">
            {overdue.length > 0 ? (
              overdue.map(c => (
                <div key={c.id} className="flex justify-between items-center p-3 md:p-4 bg-rose-50/50 rounded-xl md:rounded-2xl border border-rose-100 transition-all">
                  <div>
                    <p className="font-bold text-rose-900 text-sm md:text-base">{c.name}</p>
                    <p className="text-[10px] font-bold text-rose-400 uppercase tracking-wider">Due: {c.dueDate}th</p>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-rose-700 text-sm md:text-base">₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                    <Link 
                      to={`/customers/${c.id}`} 
