                  <td colSpan={4} className="px-8 py-16 text-center">
                    <div className="max-w-xs mx-auto space-y-2">
                      <div className="w-12 h-12 bg-slate-50 rounded-full flex items-center justify-center mx-auto text-slate-300">
                        <i className="fas fa-search"></i>
                      </div>
                      <p className="text-slate-400 font-bold text-sm">No accounts found.</p>
                      <p className="text-slate-300 text-xs">Try adjusting your filters or search terms.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Enrollment Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-start md:items-center justify-center p-4 z-50 animate-in overflow-y-auto">
          <div className="my-auto bg-white rounded-[2rem] md:rounded-[2.5rem] w-full max-w-lg shadow-2xl overflow-hidden border border-white flex flex-col max-h-[90vh]">
            <div className="px-6 md:px-8 py-5 md:py-6 bg-violet-600 flex justify-between items-center text-white shrink-0">
              <div>
                <h3 className="text-lg md:text-xl font-black uppercase tracking-tighter">Enrollment</h3>
                <p className="text-[10px] font-bold text-violet-100 opacity-80 uppercase tracking-widest">Borrower details</p>
              </div>
              <button 
                onClick={() => setIsModalOpen(false)} 
                title="Cancel enrollment and close window"
                className="w-10 h-10 rounded-xl bg-white/20 hover:bg-white/40 transition-colors flex items-center justify-center"
              >
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleAddCustomer} className="p-6 md:p-8 space-y-4 md:space-y-6 overflow-y-auto">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Full Legal Name</label>
                <input required type="text" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.name} onChange={e => setNewCustomer({...newCustomer, name: e.target.value})} />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contact No.</label>
                  <input required type="tel" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.phone} onChange={e => setNewCustomer({...newCustomer, phone: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Loan Start Date (Calendar)</label>
                  <input 
                    required 
                    type="date" 
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" 
                    value={new Date(newCustomer.startDate || Date.now()).toISOString().split('T')[0]} 
                    onChange={e => {
                      const date = new Date(e.target.value);
                      setNewCustomer({...newCustomer, startDate: date.getTime(), dueDate: date.getDate()})
                    }} 
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Interest % (M)</label>
                  <input required type="number" step="0.1" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.interestRate} onChange={e => setNewCustomer({...newCustomer, interestRate: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Auto Due Day (1-31)</label>
                  <input required type="number" min="1" max="31" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.dueDate} onChange={e => setNewCustomer({...newCustomer, dueDate: parseInt(e.target.value)})} />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Opening Capital</label>
                <input required type="number" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-violet-600 text-sm" value={newCustomer.principal} onChange={e => setNewCustomer({...newCustomer, principal: parseFloat(e.target.value)})} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Residential Address</label>
                <textarea rows={2} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.address} onChange={e => setNewCustomer({...newCustomer, address: e.target.value})}></textarea>
              </div>

              <button type="submit" className="w-full bg-violet-600 text-white py-4 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 shrink-0">
                Enroll Borrower
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Customers;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';

const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  // Principal Change State
  const [principalChange, setPrincipalChange] = useState({ 
    amount: 0, 
    reason: '', 
    type: 'increase',
    date: new Date().toISOString().split('T')[0]
  });

  // Payment Input State
  const [paymentInput, setPaymentInput] = useState({ 
    amount: 0, 
    month: new Date().getMonth(), 
    year: new Date().getFullYear(),
    collectionDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    const customersRaw = localStorage.getItem('customers');
    const paymentsRaw = localStorage.getItem('payments');
    const logsRaw = localStorage.getItem('principalLogs');

    if (customersRaw) {
      const c = JSON.parse(customersRaw).find((x: any) => x.id === id);
      if (c) setCustomer(c);
      else navigate('/customers');
    }
    if (paymentsRaw) setPayments(JSON.parse(paymentsRaw).filter((p: any) => p.customerId === id));
    if (logsRaw) setPrincipalLogs(JSON.parse(logsRaw).filter((l: any) => l.customerId === id));
  }, [id, navigate]);

  const updateGlobal = (key: string, data: any[]) => {
    const raw = localStorage.getItem(key);
    let all = raw ? JSON.parse(raw) : [];
    if (key === 'customers') {
      all = all.map((c: any) => c.id === id ? data[0] : c);
    } else {
      const others = all.filter((x: any) => x.customerId !== id);
      all = [...others, ...data];
    }
    localStorage.setItem(key, JSON.stringify(all));
  };

  const handleUpdatePrincipal = () => {
    if (!customer) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;
    const updatedCustomer = { ...customer, principal: newP };

    const timestamp = new Date(principalChange.date).getTime();

    const newLog: PrincipalLog = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      amountChange: diff, 
      newPrincipal: newP, 
      reason: principalChange.reason || 'Manual Adjustment', 
      timestamp: timestamp 
    };

    setCustomer(updatedCustomer);
    setPrincipalLogs([...principalLogs, newLog]);
    updateGlobal('customers', [updatedCustomer]);
    updateGlobal('principalLogs', [...principalLogs, newLog]);
    setShowPrincipalModal(false);
  };

  const handleAddPayment = () => {
    if (!customer) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const timestamp = new Date(paymentInput.collectionDate).getTime();

    const newPayment: Payment = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      month: paymentInput.month, 
      year: paymentInput.year, 
      amountPaid: paymentInput.amount, 
      totalDue: totalDue, 
      status: status, 
      timestamp: timestamp 
    };

    const updatedPayments = [...payments, newPayment];
    setPayments(updatedPayments);
    updateGlobal('payments', updatedPayments);
    setShowPaymentModal(false);
  };

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4">
        <div className="space-y-2">
          <button 
            onClick={() => navigate('/customers')} 
            title="Return to the main customer list"
            className="text-[10px] font-black text-violet-600 hover:bg-violet-50 px-3 py-1.5 rounded-lg uppercase tracking-widest transition-all"
          >
            <i className="fas fa-arrow-left mr-2"></i> Portfolio
          </button>
          <h2 className="text-2xl md:text-4xl font-black text-slate-900 tracking-tight">{customer.name}</h2>
          <p className="text-sm text-slate-500 font-medium flex items-center gap-2">
            <i className="fas fa-location-dot text-slate-300"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a 
            href={`tel:${customer.phone}`} 
            title={`Start a phone call with ${customer.name}`}
            className="bg-emerald-100 text-emerald-700 w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center hover:bg-emerald-200 transition-all shadow-lg shadow-emerald-50"
          >
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button 
            onClick={() => setShowPrincipalModal(true)} 
            title="Add to the current loan amount or record a principal repayment"
            className="flex-1 md:flex-none bg-violet-600 text-white px-6 py-3 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-sm md:text-base"
          >
            <i className="fas fa-coins"></i> Manage Capital
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-4 gap-4 md:gap-8">
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Principal</p>
          <p className="text-2xl md:text-4xl font-black text-slate-900 leading-none">₹{customer.principal.toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-2">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Interest ({customer.interestRate}%)</p>
          <p className="text-2xl md:text-4xl font-black text-violet-600 leading-none">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-3">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Billing Day</p>
          <div 
            className="inline-flex items-center gap-2 bg-violet-50 text-violet-600 px-3 py-1.5 md:px-4 md:py-2 rounded-xl font-black text-[10px] md:text-sm uppercase tracking-widest"
            title="Payments are collected on this day every month"
          >
            Day {customer.dueDate}
          </div>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Started On</p>
          <p className="text-lg md:text-xl font-black text-slate-700">
            {customer.startDate ? new Date(customer.startDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' }) : 'N/A'}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in delay-2">
          <div className="px-6 md:px-8 py-4 md:py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
            <h3 className="font-black text-slate-800 uppercase tracking-tighter text-sm md:text-base">Interest Ledger</h3>
            <button 
              onClick={() => setShowPaymentModal(true)} 
              title="Record a new interest payment collection"
              className="bg-violet-600 text-white w-7 h-7 md:w-8 md:h-8 rounded-lg flex items-center justify-center shadow-lg shadow-violet-100 transition-transform hover:scale-110"
            >
              <i className="fas fa-plus text-[10px]"></i>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full min-w-[350px]">
              <thead className="bg-slate-50/50 border-b text-slate-400 text-left">
                <tr>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest">Period</th>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest text-right">Paid</th>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest text-right">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {payments.sort((a,b) => b.timestamp - a.timestamp).map(p => (
                  <tr key={p.id}>
                    <td className="px-6 md:px-8 py-4 font-bold text-slate-600 text-[11px] md:text-sm">
                      <div className="flex flex-col">
                        <span>{new Date(p.year, p.month).toLocaleString('default', { month: 'short', year: 'numeric' })}</span>
                        <span className="text-[8px] text-slate-400 uppercase tracking-widest font-medium">Rec'd: {new Date(p.timestamp).toLocaleDateString()}</span>
                      </div>
                    </td>
                    <td className="px-6 md:px-8 py-4 font-black text-violet-600 text-[11px] md:text-sm text-right">₹{p.amountPaid.toLocaleString()}</td>
                    <td className="px-6 md:px-8 py-4 text-right">
                      <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest ${
                        p.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                        p.status === 'Partial' ? 'bg-amber-100 text-amber-700' : 'bg-rose-100 text-rose-700'
                      }`}>
                        {p.status}
                      </span>
                    </td>
                  </tr>
                ))}
                {payments.length === 0 && (
                  <tr><td colSpan={3} className="p-10 text-center text-slate-300 font-medium italic text-xs">No records.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in delay-3">
          <div className="px-6 md:px-8 py-4 md:py-6 border-b border-slate-50 bg-slate-50/50">
            <h3 className="font-black text-slate-800 uppercase tracking-tighter text-sm md:text-base">Adjustment Audit</h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full min-w-[350px]">
              <thead className="bg-slate-50/50 border-b text-slate-400 text-left">
                <tr>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest">Date</th>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest text-right">Diff</th>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest text-right">New Balance</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {principalLogs.sort((a,b) => b.timestamp - a.timestamp).map(l => (
                  <tr key={l.id}>
                    <td className="px-6 md:px-8 py-4 text-slate-400 text-[11px] md:text-sm font-medium">
                      <div className="flex flex-col">
                        <span>{new Date(l.timestamp).toLocaleDateString()}</span>
                        <span className="text-[8px] text-slate-300 uppercase truncate max-w-[100px]">{l.reason}</span>
                      </div>
                    </td>
                    <td className={`px-6 md:px-8 py-4 font-black text-[11px] md:text-sm text-right ${l.amountChange > 0 ? 'text-violet-600' : 'text-rose-600'}`}>
                      {l.amountChange > 0 ? '+' : ''}{l.amountChange.toLocaleString()}
                    </td>
                    <td className="px-6 md:px-8 py-4 font-black text-slate-900 text-[11px] md:text-sm text-right">₹{l.newPrincipal.toLocaleString()}</td>
                  </tr>
                ))}
                {principalLogs.length === 0 && (
                  <tr><td colSpan={3} className="p-10 text-center text-slate-300 font-medium italic text-xs">No balance history.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Principal Adjustment Modal with Calendar Picker */}
      {showPrincipalModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-start md:items-center justify-center p-4 z-50 animate-in overflow-y-auto">
          <div className="my-auto bg-white rounded-[2rem] md:rounded-[2.5rem] w-full max-w-sm p-6 md:p-8 shadow-2xl overflow-hidden border border-white">
            <h3 className="text-xl font-black text-slate-900 mb-6 uppercase tracking-tighter">Adjustment</h3>
            <div className="space-y-4 md:space-y-6">
              <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl">
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'increase'})} 
                  title="Record an additional amount lent to the borrower"
                  className={`flex-1 py-2 rounded-xl transition-all font-black text-[10px] uppercase tracking-widest ${principalChange.type === 'increase' ? 'bg-white shadow-md text-violet-600' : 'text-slate-400'}`}
                >
                  Lend
                </button>
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'decrease'})} 
                  title="Record a repayment of the principal amount"
                  className={`flex-1 py-2 rounded-xl transition-all font-black text-[10px] uppercase tracking-widest ${principalChange.type === 'decrease' ? 'bg-white shadow-md text-rose-600' : 'text-slate-400'}`}
                >
                  Recover
                </button>
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Transaction Date</label>
                <input 
                  type="date" 
                  title="The actual date this capital change occurred"
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-700 outline-none text-sm" 
                  value={principalChange.date}
                  onChange={e => setPrincipalChange({...principalChange, date: e.target.value})} 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Amount</label>
                <input 
                  type="number" 
                  placeholder="0.00" 
                  title="Enter the change in principal balance"
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700 outline-none text-sm" 
                  onChange={e => setPrincipalChange({...principalChange, amount: parseFloat(e.target.value)})} 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Notes</label>
                <input 
                  type="text" 
                  placeholder="e.g. Additional loan" 
                  title="Provide a brief reason for this adjustment"
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-500 outline-none text-sm" 
                  onChange={e => setPrincipalChange({...principalChange, reason: e.target.value})} 
                />
              </div>

              <div className="flex gap-4 pt-2">
                <button 
                  onClick={() => setShowPrincipalModal(false)} 
                  title="Discard changes and exit"
                  className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest"
                >
                  Back
                </button>
                <button onClick={handleUpdatePrincipal} className="flex-1 py-4 bg-violet-600 text-white rounded-2xl font-black shadow-lg shadow-violet-100 text-sm">Save</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Interest Entry Modal with Calendar Picker */}
      {showPaymentModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-start md:items-center justify-center p-4 z-50 animate-in overflow-y-auto">
          <div className="my-auto bg-white rounded-[2rem] md:rounded-[2.5rem] w-full max-w-sm p-6 md:p-8 shadow-2xl overflow-hidden border border-white">
            <h3 className="text-xl font-black text-slate-900 mb-6 uppercase tracking-tighter">Interest Entry</h3>
            <div className="space-y-4 md:space-y-6">
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Billing Period</label>
                <div className="grid grid-cols-2 gap-3">
                  <select 
                    title="Select the month this payment covers"
                    className="p-3 md:p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-600 text-xs md:text-sm" 
                    value={paymentInput.month} 
                    onChange={e => setPaymentInput({...paymentInput, month: parseInt(e.target.value)})}
                  >
                    {Array.from({length: 12}).map((_, i) => <option key={i} value={i}>{new Date(0, i).toLocaleString('default', {month: 'long'})}</option>)}
                  </select>
                  <select 
                    title="Select the year this payment covers"
                    className="p-3 md:p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-600 text-xs md:text-sm" 
                    value={paymentInput.year} 
                    onChange={e => setPaymentInput({...paymentInput, year: parseInt(e.target.value)})}
                  >
                    <option value={2024}>2024</option>
                    <option value={2025}>2025</option>
                    <option value={2026}>2026</option>
                  </select>
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Collection Date (Calendar)</label>
                <input 
                  type="date" 
                  title="The date you physically received the cash or transfer"
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-700 outline-none text-sm" 
                  value={paymentInput.collectionDate}
                  onChange={e => setPaymentInput({...paymentInput, collectionDate: e.target.value})} 
                />
              </div>

              <div className="p-4 bg-violet-50 rounded-2xl">
                <p className="text-[9px] font-black text-violet-400 uppercase tracking-widest mb-1">Expected Interest</p>
                <p className="text-lg md:text-xl font-black text-violet-600">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Amount Collected</label>
                <input 
                  type="number" 
                  placeholder="0.00" 
                  title="Enter the total amount of interest received for this period"
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700 outline-none text-sm" 
                  onChange={e => setPaymentInput({...paymentInput, amount: parseFloat(e.target.value)})} 
                />
              </div>

              <div className="flex gap-4 pt-2">
                <button 
                  onClick={() => setShowPaymentModal(false)} 
                  title="Cancel and close entry form"
                  className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest"
                >
                  Back
                </button>
                <button onClick={handleAddPayment} className="flex-1 py-4 bg-violet-600 text-white rounded-2xl font-black shadow-lg shadow-violet-100 text-sm">Submit</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CustomerDetails;

import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

const Reports: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  useEffect(() => {
    const c = localStorage.getItem('customers');
    const p = localStorage.getItem('payments');
    if (c) setCustomers(JSON.parse(c));
    if (p) setPayments(JSON.parse(p));
  }, []);

  const resetToCurrent = () => {
    setSelectedMonth(new Date().getMonth());
    setSelectedYear(new Date().getFullYear());
  };

  const generatePDF = (m: number = selectedMonth, y: number = selectedYear) => {
    const doc = new jsPDF();
    const monthName = new Date(y, m).toLocaleString('default', { month: 'long' });

    doc.setFontSize(22);
    doc.setTextColor(124, 58, 237); // Violet-600
    doc.text('LendFlow Portfolio Report', 14, 22);
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139); // Slate-500
    doc.text(`Generated on: ${new Date().toLocaleDateString()} | Billing Period: ${monthName} ${y}`, 14, 30);

    const tableData = customers.map(c => {
      const payment = payments.find(p => p.customerId === c.id && p.month === m && p.year === y);
      const interestDue = (c.principal * c.interestRate) / 100;
      return [
        c.name,
        `₹${c.principal.toLocaleString()}`,
        `₹${interestDue.toLocaleString()}`,
        payment ? `₹${payment.amountPaid.toLocaleString()}` : '₹0',
        payment ? payment.status : (c.principal > 0 ? 'Pending' : 'N/A')
      ];
    });

    autoTable(doc, {
      startY: 40,
      head: [['Customer Name', 'Capital Balance', 'Interest Due', 'Interest Paid', 'Status']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: [124, 58, 237] }, // Violet-600
      styles: { fontSize: 9 }
    });

    const totalCollected = payments
      .filter(p => p.month === m && p.year === y)
      .reduce((sum, p) => sum + p.amountPaid, 0);

    const totalDue = customers.reduce((sum, c) => sum + (c.principal * c.interestRate / 100), 0);
    const totalOutstanding = customers.reduce((sum, c) => sum + c.principal, 0);

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFillColor(245, 243, 255); // Violet-50
    doc.rect(14, finalY, 182, 40, 'F');

    doc.setFontSize(14);
    doc.setTextColor(124, 58, 237);
    doc.text('Monthly Financial Summary', 20, finalY + 10);

    doc.setFontSize(10);
    doc.setTextColor(30, 41, 59);
    doc.text(`Total Monthly Interest Collected:`, 20, finalY + 20);
    doc.text(`₹${totalCollected.toLocaleString()}`, 150, finalY + 20, { align: 'right' });

    doc.text(`Total Pending Interest:`, 20, finalY + 27);
    doc.text(`₹${(totalDue - totalCollected).toLocaleString()}`, 150, finalY + 27, { align: 'right' });

    doc.text(`Total Active Capital (Outstanding):`, 20, finalY + 34);
    doc.text(`₹${totalOutstanding.toLocaleString()}`, 150, finalY + 34, { align: 'right' });

    doc.save(`LendFlow_${monthName}_${y}.pdf`);
  };

  const handleQuickExport = () => {
    const now = new Date();
    generatePDF(now.getMonth(), now.getFullYear());
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-end gap-2">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tight uppercase">Exports</h2>
          <p className="text-slate-500 font-medium text-sm md:text-base">Portfolio financial reports.</p>
        </div>
        <button 
          onClick={resetToCurrent}
          title="Reset selections back to the current month and year"
          className="text-xs font-black text-violet-600 hover:bg-violet-50 px-3 py-1.5 rounded-xl transition-all uppercase tracking-widest"
        >
          Reset Filters
        </button>
      </header>

      <div className="bg-white p-6 md:p-12 rounded-2xl md:rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 max-w-2xl mx-auto text-center relative overflow-hidden">
        <div className="hidden md:block absolute top-0 right-0 w-32 h-32 bg-violet-50 rounded-full -mr-16 -mt-16 opacity-50"></div>

        <div className="relative z-10">
          <div className="w-16 h-16 md:w-24 md:h-24 bg-violet-100 text-violet-600 rounded-2xl md:rounded-3xl flex items-center justify-center text-2xl md:text-4xl mx-auto mb-4 md:mb-6 shadow-lg shadow-violet-100">
            <i className="fas fa-file-invoice"></i>
          </div>
          <h3 className="text-xl md:text-2xl font-black text-slate-900 mb-2">Statement Center</h3>
          <p className="text-xs md:text-sm text-slate-500 mb-8 max-w-sm mx-auto font-medium">Download the complete portfolio status for any billing period.</p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6 mb-8 md:mb-10">
            <div className="text-left space-y-1 md:space-y-2">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Period Month</label>
              <select 
                title="Filter the report by a specific month"
                className="w-full p-3 md:p-4 bg-slate-50 border border-slate-100 rounded-xl md:rounded-2xl outline-none focus:ring-2 focus:ring-violet-200 font-bold text-slate-700 text-sm"
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              >
                {Array.from({length: 12}).map((_, i) => (
                  <option key={i} value={i}>{new Date(0, i).toLocaleString('default', {month: 'long'})}</option>
                ))}
              </select>
            </div>
            <div className="text-left space-y-1 md:space-y-2">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Calendar Year</label>
              <select 
                title="Filter the report by a specific year"
                className="w-full p-3 md:p-4 bg-slate-50 border border-slate-100 rounded-xl md:rounded-2xl outline-none focus:ring-2 focus:ring-violet-200 font-bold text-slate-700 text-sm"
                value={selectedYear}
                onChange={(e) => setSelectedYear(parseInt(e.target.value))}
              >
                <option value={2024}>2024</option>
                <option value={2025}>2025</option>
                <option value={2026}>2026</option>
              </select>
            </div>
          </div>

          <div className="flex flex-col gap-3 md:gap-4">
            <button 
              onClick={() => generatePDF()}
              title="Download a professional PDF statement including capital balance and interest status for all borrowers"
              className="w-full bg-violet-600 text-white py-4 md:py-5 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 flex items-center justify-center gap-3 active:scale-[0.98]"
            >
              <i className="fas fa-file-export"></i>
              Export PDF
            </button>

            <button 
              onClick={handleQuickExport}
              title={`Instantly export the report for the current month (${new Date().toLocaleString('default', { month: 'short', year: 'numeric' })})`}
              className="w-full bg-white text-violet-600 border-2 border-violet-100 py-3 md:py-4 rounded-2xl font-black text-xs md:text-base hover:bg-violet-50 transition-all flex items-center justify-center gap-2 active:scale-[0.98]"
            >
              <i className="fas fa-bolt text-[10px] md:text-xs"></i>
              Quick Export: Current Month
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reports;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';

const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  // Principal Change State
  const [principalChange, setPrincipalChange] = useState({ 
    amount: 0, 
    reason: '', 
    type: 'increase',
    date: new Date().toISOString().split('T')[0]
  });

  // Payment Input State
  const [paymentInput, setPaymentInput] = useState({ 
    amount: 0, 
    month: new Date().getMonth(), 
    year: new Date().getFullYear(),
    collectionDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    const customersRaw = localStorage.getItem('customers');
    const paymentsRaw = localStorage.getItem('payments');
    const logsRaw = localStorage.getItem('principalLogs');

    if (customersRaw) {
      const c = JSON.parse(customersRaw).find((x: any) => x.id === id);
      if (c) setCustomer(c);
      else navigate('/customers');
    }
    if (paymentsRaw) setPayments(JSON.parse(paymentsRaw).filter((p: any) => p.customerId === id));
    if (logsRaw) setPrincipalLogs(JSON.parse(logsRaw).filter((l: any) => l.customerId === id));
  }, [id, navigate]);

  const updateGlobal = (key: string, data: any[]) => {
    const raw = localStorage.getItem(key);
    let all = raw ? JSON.parse(raw) : [];
    if (key === 'customers') {
      all = all.map((c: any) => c.id === id ? data[0] : c);
    } else {
      const others = all.filter((x: any) => x.customerId !== id);
      all = [...others, ...data];
    }
    localStorage.setItem(key, JSON.stringify(all));
  };

  const handleUpdatePrincipal = () => {
    if (!customer) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;
    const updatedCustomer = { ...customer, principal: newP };

    const timestamp = new Date(principalChange.date).getTime();

    const newLog: PrincipalLog = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      amountChange: diff, 
      newPrincipal: newP, 
      reason: principalChange.reason || 'Manual Adjustment', 
      timestamp: timestamp 
    };

    setCustomer(updatedCustomer);
    setPrincipalLogs([...principalLogs, newLog]);
    updateGlobal('customers', [updatedCustomer]);
    updateGlobal('principalLogs', [...principalLogs, newLog]);
    setShowPrincipalModal(false);
  };

  const handleAddPayment = () => {
    if (!customer) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const timestamp = new Date(paymentInput.collectionDate).getTime();

    const newPayment: Payment = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      month: paymentInput.month, 
      year: paymentInput.year, 
      amountPaid: paymentInput.amount, 
      totalDue: totalDue, 
      status: status, 
      timestamp: timestamp 
    };

    const updatedPayments = [...payments, newPayment];
    setPayments(updatedPayments);
    updateGlobal('payments', updatedPayments);
    setShowPaymentModal(false);
  };

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4">
        <div className="space-y-2">
          <button 
            onClick={() => navigate('/customers')} 
            title="Return to the main customer list"
            className="text-[10px] font-black text-violet-600 hover:bg-violet-50 px-3 py-1.5 rounded-lg uppercase tracking-widest transition-all"
          >
            <i className="fas fa-arrow-left mr-2"></i> Portfolio
          </button>
          <h2 className="text-2xl md:text-4xl font-black text-slate-900 tracking-tight">{customer.name}</h2>
          <p className="text-sm text-slate-500 font-medium flex items-center gap-2">
            <i className="fas fa-location-dot text-slate-300"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a 
            href={`tel:${customer.phone}`} 
            title={`Start a phone call with ${customer.name}`}
            className="bg-emerald-100 text-emerald-700 w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center hover:bg-emerald-200 transition-all shadow-lg shadow-emerald-50"
          >
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button 
            onClick={() => setShowPrincipalModal(true)} 
            title="Add to the current loan amount or record a principal repayment"
            className="flex-1 md:flex-none bg-violet-600 text-white px-6 py-3 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-sm md:text-base"
          >
            <i className="fas fa-coins"></i> Manage Capital
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-4 gap-4 md:gap-8">
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Principal</p>
          <p className="text-2xl md:text-4xl font-black text-slate-900 leading-none">₹{customer.principal.toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-2">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Interest ({customer.interestRate}%)</p>
          <p className="text-2xl md:text-4xl font-black text-violet-600 leading-none">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-3">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Billing Day</p>
          <div 
            className="inline-flex items-center gap-2 bg-violet-50 text-violet-600 px-3 py-1.5 md:px-4 md:py-2 rounded-xl font-black text-[10px] md:text-sm uppercase tracking-widest"
            title="Payments are collected on this day every month"
          >
            Day {customer.dueDate}
          </div>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2 md:mb-3">Started On</p>
          <p className="text-lg md:text-xl font-black text-slate-700">
            {customer.startDate ? new Date(customer.startDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' }) : 'N/A'}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in delay-2">
          <div className="px-6 md:px-8 py-4 md:py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
            <h3 className="font-black text-slate-800 uppercase tracking-tighter text-sm md:text-base">Interest Ledger</h3>
            <button 
              onClick={() => setShowPaymentModal(true)} 
              title="Record a new interest payment collection"
              className="bg-violet-600 text-white w-7 h-7 md:w-8 md:h-8 rounded-lg flex items-center justify-center shadow-lg shadow-violet-100 transition-transform hover:scale-110"
            >
              <i className="fas fa-plus text-[10px]"></i>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full min-w-[350px]">
              <thead className="bg-slate-50/50 border-b text-slate-400 text-left">
                <tr>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest">Period</th>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest text-right">Paid</th>
                  <th className="px-6 md:px-8 py-3 md:py-4 text-[9px] font-black uppercase tracking-widest text-right">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {payments.sort((a,b) => b.timestamp - a.timestamp).map(p => (
                  <tr key={p.id}>
                    <td className="px-6 md:px-8 py-4 font-bold text-slate-600 text-[11px] md:text-sm">
                      <div className="flex flex-col">
                        <span>{new Date(p.year, p.month).toLocaleString('default', { month: 'short', year: 'numeric' })}</span>
                        <span className="text-[8px] text-slate-400 uppercase tracking-widest font-medium">Rec'd: {new Date(p.timestamp).toLocaleDateString()}</span>
                      </div>
                    </td>
                    <td className="px-6 md:px-8 py-4 font-black text-violet-600 text-[11px] md:text-sm text-right">₹{p.amountPaid.toLocaleString()}</td>
                    <td className="px-6 md:px-8 py-4 text-right">
                      <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase tracking-widest ${
                        p.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
