              </div>
            </div>
          </div>
        </div>
      )}

      {/* Interest Entry Modal with Calendar Picker */}
      {showPaymentModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-start md:items-center justify-center p-4 z-50 animate-in overflow-y-auto">
