                  title="The date you physically received the cash or transfer"
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-700 outline-none text-sm" 
                  value={paymentInput.collectionDate}
                  onChange={e => setPaymentInput({...paymentInput, collectionDate: e.target.value})} 
                />
              </div>

              <div className="p-4 bg-violet-50 rounded-2xl">
                <p className="text-[9px] font-black text-violet-400 uppercase tracking-widest mb-1">Expected Interest</p>
                <p className="text-lg md:text-xl font-black text-violet-600">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
              </div>

              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Amount Collected</label>
                <input 
                  type="number" 
                  placeholder="0.00" 
                  title="Enter the total amount of interest received for this period"
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700 outline-none text-sm" 
                  onChange={e => setPaymentInput({...paymentInput, amount: parseFloat(e.target.value)})} 
                />
              </div>

              <div className="flex gap-4 pt-2">
                <button 
                  onClick={() => setShowPaymentModal(false)} 
                  title="Cancel and close entry form"
                  className="flex-1 py-4 text-slate-400 font-black uppercase text-[10px] tracking-widest"
                >
                  Back
                </button>
                <button onClick={handleAddPayment} className="flex-1 py-4 bg-violet-600 text-white rounded-2xl font-black shadow-lg shadow-violet-100 text-sm">Submit</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

