          onClick={() => setIsModalOpen(true)}
          className="w-full md:w-auto bg-violet-600 text-white px-6 py-3.5 rounded-2xl font-bold shadow-lg shadow-violet-200 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 active:scale-95"
