import React, { useState, createContext, useContext, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Customers from './pages/Customers';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import Login from './pages/Login';
import { Language, translations } from './translations';

interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: keyof typeof translations.en) => string;
}

export const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const useTranslation = () => {
  const context = useContext(LanguageContext);
  if (!context) throw new Error('useTranslation must be used within LanguageProvider');
  return context;
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem('isLoggedIn') === 'true';
  });
  const [language, setLanguageState] = useState<Language>(() => {
    return (localStorage.getItem('appLang') as Language) || 'en';
  });
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const setLanguage = (lang: Language) => {
    setLanguageState(lang);
    localStorage.setItem('appLang', lang);
  };

  const t = (key: keyof typeof translations.en) => {
    return translations[language][key] || translations.en[key];
  };

  const handleLogin = (success: boolean) => {
    setIsAuthenticated(success);
    if (success) localStorage.setItem('isLoggedIn', 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('isLoggedIn');
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);
  const closeSidebar = () => setIsSidebarOpen(false);

  if (!isAuthenticated) {
    return (
      <LanguageContext.Provider value={{ language, setLanguage, t }}>
        <Login onLogin={handleLogin} />
      </LanguageContext.Provider>
    );
  }

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      <HashRouter>
        <div className="flex h-screen bg-transparent overflow-hidden relative">
          {/* Language Toggle Button - Top Right Corner (Adjusted for mobile header) */}
          <div className="fixed top-3 right-14 md:top-6 md:right-8 z-[60] flex items-center">
            <button
              onClick={() => setLanguage(language === 'en' ? 'ta' : 'en')}
              className="bg-white/90 backdrop-blur-md border border-slate-200 px-3 py-1.5 md:px-4 md:py-2 rounded-full shadow-lg hover:shadow-violet-200 transition-all flex items-center gap-2 group active:scale-95"
              title={language === 'en' ? 'தமிழ் மொழிக்கு மாற்றவும்' : 'Switch to English'}
            >
              <div className="w-5 h-5 md:w-6 md:h-6 rounded-full bg-violet-600 text-white flex items-center justify-center text-[8px] md:text-[10px] font-black uppercase">
                {language === 'en' ? 'EN' : 'தமிழ்'}
              </div>
              <span className="text-[10px] md:text-xs font-black text-slate-600 uppercase tracking-widest hidden sm:inline">
                {language === 'en' ? 'தமிழ்' : 'English'}
              </span>
            </button>
          </div>

          {/* Mobile Header */}
          <div className="md:hidden fixed top-0 left-0 right-0 h-16 bg-white/90 backdrop-blur-md border-b border-slate-100 flex items-center justify-between px-4 z-40">
            <h1 className="text-xl font-black text-violet-600 tracking-tighter uppercase">LendFlow</h1>
            <button 
              onClick={toggleSidebar} 
              className="w-10 h-10 flex items-center justify-center text-slate-500"
              title={isSidebarOpen ? "Close navigation menu" : "Open navigation menu"}
            >
              <i className={`fas ${isSidebarOpen ? 'fa-times' : 'fa-bars'} text-xl`}></i>
            </button>
          </div>

          {/* Sidebar Overlay for Mobile */}
          {isSidebarOpen && (
            <div 
              className="md:hidden fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 transition-opacity"
              onClick={closeSidebar}
            />
          )}

          <Sidebar 
            onLogout={handleLogout} 
            isOpen={isSidebarOpen} 
            onClose={closeSidebar} 
          />

          <main className="flex-1 overflow-y-auto pt-20 md:pt-12 px-4 pb-12 md:px-8">
            <div className="max-w-7xl mx-auto">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/customers" element={<Customers />} />
                <Route path="/customers/:id" element={<CustomerDetails />} />
                <Route path="/reports" element={<Reports />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </div>
          </main>
        </div>
      </HashRouter>
    </LanguageContext.Provider>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import { Link } from 'react-router-dom';
import { useTranslation } from '../App';

const Dashboard: React.FC = () => {
  const { t } = useTranslation();
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);

  useEffect(() => {
    const savedCustomers = localStorage.getItem('customers');
    const savedPayments = localStorage.getItem('payments');
    if (savedCustomers) setCustomers(JSON.parse(savedCustomers));
    if (savedPayments) setPayments(JSON.parse(savedPayments));
  }, []);

  const totalPrincipal = customers.reduce((sum, c) => sum + c.principal, 0);
  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();
  const today = new Date().getDate();

  const monthlyIncome = payments
    .filter(p => p.month === currentMonth && p.year === currentYear)
    .reduce((sum, p) => sum + p.amountPaid, 0);

  const dueToday = customers.filter(c => c.dueDate === today);
  const overdue = customers.filter(c => {
    const payment = payments.find(p => p.customerId === c.id && p.month === currentMonth && p.year === currentYear);
    const isOverdue = today > c.dueDate && (!payment || payment.status !== 'Paid');
    return isOverdue && c.principal > 0;
  });

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-8">
      <header className="px-1">
        <h2 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tight">{t('overview')}</h2>
        <p className="text-slate-500 font-medium text-xs md:text-base">{t('portfolioSummary')}</p>
      </header>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-6">
        <StatCard label={t('active')} value={customers.length.toString()} icon="fa-users" color="bg-violet-600" delay="delay-1" tooltip="Total borrowers" />
        <StatCard label={t('capital')} value={`₹${totalPrincipal.toLocaleString()}`} icon="fa-money-bill-wave" color="bg-slate-900" delay="delay-2" tooltip="Total outstanding principal" />
        <StatCard label={t('income')} value={`₹${monthlyIncome.toLocaleString()}`} icon="fa-hand-holding-dollar" color="bg-violet-500" delay="delay-3" tooltip="Interest collected this month" />
        <StatCard label={t('action')} value={overdue.length.toString()} icon="fa-clock" color="bg-rose-500" delay="delay-1" tooltip="Overdue accounts" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <section className="bg-white p-5 md:p-8 rounded-[1.5rem] md:rounded-3xl border border-slate-100 shadow-sm animate-in delay-2">
          <h3 className="text-lg md:text-xl font-bold mb-4 md:mb-6 flex items-center gap-3">
            <span className="w-8 h-8 md:w-10 md:h-10 rounded-full bg-violet-100 text-violet-600 flex items-center justify-center">
              <i className="fas fa-calendar-day text-sm"></i>
            </span>
            {t('dueToday')}
          </h3>
          <div className="space-y-2 md:space-y-3">
            {dueToday.length > 0 ? (
              dueToday.map(c => (
                <div key={c.id} className="flex justify-between items-center p-3 md:p-4 hover:bg-slate-50 rounded-xl md:rounded-2xl border border-transparent hover:border-slate-100 transition-all">
                  <div className="min-w-0 flex-1">
                    <p className="font-bold text-slate-800 text-sm md:text-base truncate">{c.name}</p>
                    <p className="text-[10px] md:text-xs text-slate-400">{c.phone}</p>
                  </div>
                  <div className="text-right ml-2">
                    <p className="font-black text-violet-600 text-sm md:text-base">₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                    <Link 
                      to={`/customers/${c.id}`} 
                      className="text-[9px] md:text-[10px] font-bold text-slate-400 hover:text-violet-600 uppercase tracking-widest"
                      title={t('details')}
                    >
                      {t('details')}
                    </Link>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-8 md:py-10">
                <p className="text-slate-300 font-medium text-xs md:text-sm">No repayments due today.</p>
              </div>
            )}
          </div>
        </section>

        <section className="bg-white p-5 md:p-8 rounded-[1.5rem] md:rounded-3xl border border-slate-100 shadow-sm animate-in delay-3">
          <h3 className="text-lg md:text-xl font-bold mb-4 md:mb-6 flex items-center gap-3">
            <span className="w-8 h-8 md:w-10 md:h-10 rounded-full bg-rose-100 text-rose-600 flex items-center justify-center">
              <i className="fas fa-exclamation-triangle text-sm"></i>
            </span>
            {t('overdue')}
          </h3>
          <div className="space-y-2 md:space-y-3">
            {overdue.length > 0 ? (
              overdue.map(c => (
                <div key={c.id} className="flex justify-between items-center p-3 md:p-4 bg-rose-50/50 rounded-xl md:rounded-2xl border border-rose-100 transition-all">
                  <div className="min-w-0 flex-1">
                    <p className="font-bold text-rose-900 text-sm md:text-base truncate">{c.name}</p>
                    <p className="text-[10px] font-bold text-rose-400 uppercase tracking-wider">{t('due')}: {c.dueDate}th</p>
                  </div>
                  <div className="text-right ml-2">
                    <p className="font-black text-rose-700 text-sm md:text-base">₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
