                      </div>
                    </div>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <p className="font-black text-slate-900 text-xs md:text-sm">₹{c.principal.toLocaleString()}</p>
                    <p className="text-[8px] md:text-[9px] text-slate-400 font-bold uppercase tracking-widest">{c.interestRate}% Int.</p>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <span className="bg-white text-violet-600 border border-violet-100 px-2 py-1 md:px-2.5 md:py-1.5 rounded-lg text-[8px] md:text-[10px] font-black uppercase tracking-widest whitespace-nowrap">
                      {t('due')} {c.dueDate}
                    </span>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6 text-right">
                    <Link to={`/customers/${c.id}`} className="inline-flex w-8 h-8 md:w-10 md:h-10 rounded-xl bg-white border border-slate-100 items-center justify-center text-violet-600 hover:bg-violet-600 hover:text-white transition-all shadow-sm">
                      <i className="fas fa-eye text-xs md:text-sm"></i>
                    </Link>
                  </td>
                </tr>
              ))}
              {filteredCustomers.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-8 py-16 text-center text-slate-300 font-medium">No results found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-3 md:p-4 z-50 animate-in overflow-y-auto">
          <div className="bg-white rounded-[1.5rem] md:rounded-[2rem] w-full max-w-lg shadow-2xl overflow-hidden border border-white flex flex-col max-h-[95vh]">
            <div className="px-6 py-4 md:px-8 md:py-6 bg-violet-600 flex justify-between items-center text-white shrink-0">
              <h3 className="text-lg md:text-xl font-black uppercase tracking-tighter">{t('enrollment')}</h3>
              <button onClick={() => setIsModalOpen(false)} className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/20">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleAddCustomer} className="p-5 md:p-8 space-y-4 md:space-y-6 overflow-y-auto">
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('fullName')}</label>
                <input required type="text" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.name} onChange={e => setNewCustomer({...newCustomer, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('contactNo')}</label>
                  <input required type="tel" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.phone} onChange={e => setNewCustomer({...newCustomer, phone: e.target.value})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('startDate')}</label>
                  <input required type="date" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" onChange={e => setNewCustomer({...newCustomer, startDate: new Date(e.target.value).getTime()})} />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('interestRate')}</label>
                  <input required type="number" step="0.1" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.interestRate} onChange={e => setNewCustomer({...newCustomer, interestRate: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('autoDueDay')}</label>
                  <input required type="number" min="1" max="31" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.dueDate} onChange={e => setNewCustomer({...newCustomer, dueDate: parseInt(e.target.value)})} />
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('openingCapital')}</label>
                <input required type="number" className="w-full px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-violet-600 text-sm" value={newCustomer.principal} onChange={e => setNewCustomer({...newCustomer, principal: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('address')}</label>
                <textarea rows={2} className="w-full px-4 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm" value={newCustomer.address} onChange={e => setNewCustomer({...newCustomer, address: e.target.value})}></textarea>
              </div>
              <button type="submit" className="w-full bg-violet-600 text-white py-4 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 mt-2">
                {t('enrollBtn')}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Customers;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';
import { useTranslation } from '../App';

const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { t } = useTranslation();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  // Principal Change State
  const [principalChange, setPrincipalChange] = useState({ 
    amount: 0, 
    reason: '', 
    type: 'increase',
    date: new Date().toISOString().split('T')[0]
  });

  // Payment Input State
  const [paymentInput, setPaymentInput] = useState({ 
    amount: 0, 
    month: new Date().getMonth(), 
    year: new Date().getFullYear(),
    collectionDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    const customersRaw = localStorage.getItem('customers');
    const paymentsRaw = localStorage.getItem('payments');
    const logsRaw = localStorage.getItem('principalLogs');

    if (customersRaw) {
      const c = JSON.parse(customersRaw).find((x: any) => x.id === id);
      if (c) setCustomer(c);
      else navigate('/customers');
    }
    if (paymentsRaw) setPayments(JSON.parse(paymentsRaw).filter((p: any) => p.customerId === id));
    if (logsRaw) setPrincipalLogs(JSON.parse(logsRaw).filter((l: any) => l.customerId === id));
  }, [id, navigate]);

  const updateGlobal = (key: string, data: any[]) => {
    const raw = localStorage.getItem(key);
    let all = raw ? JSON.parse(raw) : [];
    if (key === 'customers') {
      all = all.map((c: any) => c.id === id ? data[0] : c);
    } else {
      const others = all.filter((x: any) => x.customerId !== id);
      all = [...others, ...data];
    }
    localStorage.setItem(key, JSON.stringify(all));
  };

  const handleUpdatePrincipal = () => {
    if (!customer) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;
    const updatedCustomer = { ...customer, principal: newP };

    const timestamp = new Date(principalChange.date).getTime();

    const newLog: PrincipalLog = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      amountChange: diff, 
      newPrincipal: newP, 
      reason: principalChange.reason || 'Manual Adjustment', 
      timestamp: timestamp 
    };

    setCustomer(updatedCustomer);
    setPrincipalLogs([...principalLogs, newLog]);
    updateGlobal('customers', [updatedCustomer]);
    updateGlobal('principalLogs', [...principalLogs, newLog]);
    setShowPrincipalModal(false);
  };

  const handleAddPayment = () => {
    if (!customer) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const timestamp = new Date(paymentInput.collectionDate).getTime();

    const newPayment: Payment = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      month: paymentInput.month, 
      year: paymentInput.year, 
      amountPaid: paymentInput.amount, 
      totalDue: totalDue, 
      status: status, 
      timestamp: timestamp 
    };

    const updatedPayments = [...payments, newPayment];
    setPayments(updatedPayments);
    updateGlobal('payments', updatedPayments);
    setShowPaymentModal(false);
  };

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4 px-1">
        <div className="space-y-1.5 md:space-y-2 w-full">
          <button 
            onClick={() => navigate('/customers')} 
            className="text-[9px] md:text-[10px] font-black text-violet-600 hover:bg-violet-50 px-2 py-1 md:px-3 md:py-1.5 rounded-lg uppercase tracking-widest transition-all mb-1"
          >
            <i className="fas fa-arrow-left mr-2"></i> {t('ledger')}
          </button>
          <h2 className="text-2xl md:text-4xl font-black text-slate-900 tracking-tight truncate">{customer.name}</h2>
          <p className="text-xs md:text-sm text-slate-500 font-medium flex items-center gap-2">
            <i className="fas fa-location-dot text-slate-300"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a 
            href={`tel:${customer.phone}`} 
            className="bg-emerald-100 text-emerald-700 w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center hover:bg-emerald-200 transition-all shadow-lg shadow-emerald-50 shrink-0"
          >
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button 
            onClick={() => setShowPrincipalModal(true)} 
            className="flex-1 md:flex-none bg-violet-600 text-white px-5 py-3 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-xs md:text-base"
          >
            <i className="fas fa-coins"></i> {t('adjustment')}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-8">
        <div className="bg-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 md:mb-3">{t('capital')}</p>
          <p className="text-lg md:text-3xl font-black text-slate-900 leading-none truncate">₹{customer.principal.toLocaleString()}</p>
        </div>
        <div className="bg-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-2">
          <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 md:mb-3">Interest ({customer.interestRate}%)</p>
          <p className="text-lg md:text-3xl font-black text-violet-600 leading-none truncate">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
        </div>
        <div className="bg-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-3">
          <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 md:mb-3">{t('due')}</p>
          <div className="inline-flex items-center gap-2 bg-violet-50 text-violet-600 px-2 py-1 md:px-4 md:py-2 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm uppercase tracking-widest">
            Day {customer.dueDate}
          </div>
        </div>
        <div className="bg-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 md:mb-3">{t('startDate')}</p>
          <p className="text-sm md:text-xl font-black text-slate-700 truncate">
            {customer.startDate ? new Date(customer.startDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short' }) : 'N/A'}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in delay-2">
          <div className="px-5 md:px-8 py-4 md:py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
            <h3 className="font-black text-slate-800 uppercase tracking-tighter text-xs md:text-base">{t('interestLedger')}</h3>
            <button 
              onClick={() => setShowPaymentModal(true)} 
              className="bg-violet-600 text-white w-7 h-7 md:w-8 md:h-8 rounded-lg flex items-center justify-center shadow-lg shadow-violet-100 transition-transform hover:scale-110"
            >
              <i className="fas fa-plus text-[10px]"></i>
            </button>
          </div>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full min-w-[320px]">
              <thead className="bg-slate-50/50 border-b text-slate-400 text-left">
                <tr>
                  <th className="px-5 md:px-8 py-3 text-[8px] md:text-[9px] font-black uppercase tracking-widest">{t('month')}</th>
                  <th className="px-5 md:px-8 py-3 text-[8px] md:text-[9px] font-black uppercase tracking-widest text-right">{t('collect')}</th>
                  <th className="px-5 md:px-8 py-3 text-[8px] md:text-[9px] font-black uppercase tracking-widest text-right">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {payments.sort((a,b) => b.timestamp - a.timestamp).map(p => (
                  <tr key={p.id}>
                    <td className="px-5 md:px-8 py-4 font-bold text-slate-600 text-[10px] md:text-sm">
                      <div className="flex flex-col">
                        <span>{new Date(p.year, p.month).toLocaleString('default', { month: 'short' })} '{p.year.toString().slice(-2)}</span>
                        <span className="text-[7px] md:text-[8px] text-slate-300 uppercase truncate">Rec'd: {new Date(p.timestamp).toLocaleDateString()}</span>
                      </div>
                    </td>
                    <td className="px-5 md:px-8 py-4 font-black text-violet-600 text-[10px] md:text-sm text-right">₹{p.amountPaid.toLocaleString()}</td>
                    <td className="px-5 md:px-8 py-4 text-right">
                      <span className={`px-2 py-0.5 rounded-lg text-[7px] md:text-[8px] font-black uppercase tracking-widest inline-block ${
                        p.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                        p.status === 'Partial' ? 'bg-amber-100 text-amber-700' : 'bg-rose-100 text-rose-700'
                      }`}>
                        {p.status}
                        {p.status !== 'Paid' && ` (Due: ₹${(p.totalDue - p.amountPaid).toLocaleString()})`}
                      </span>
                    </td>
                  </tr>
                ))}
                {payments.length === 0 && (
                  <tr><td colSpan={3} className="p-10 text-center text-slate-200 font-bold italic text-xs">No records.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in delay-3">
          <div className="px-5 md:px-8 py-4 md:py-6 border-b border-slate-50 bg-slate-50/50">
            <h3 className="font-black text-slate-800 uppercase tracking-tighter text-xs md:text-base">{t('audit')}</h3>
          </div>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full min-w-[320px]">
              <thead className="bg-slate-50/50 border-b text-slate-400 text-left">
                <tr>
                  <th className="px-5 md:px-8 py-3 text-[8px] md:text-[9px] font-black uppercase tracking-widest">Date</th>
                  <th className="px-5 md:px-8 py-3 text-[8px] md:text-[9px] font-black uppercase tracking-widest text-right">Diff</th>
                  <th className="px-5 md:px-8 py-3 text-[8px] md:text-[9px] font-black uppercase tracking-widest text-right">Balance</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {principalLogs.sort((a,b) => b.timestamp - a.timestamp).map(l => (
                  <tr key={l.id}>
                    <td className="px-5 md:px-8 py-4 text-slate-400 text-[10px] md:text-sm font-medium">
                      <div className="flex flex-col">
                        <span>{new Date(l.timestamp).toLocaleDateString()}</span>
                        <span className="text-[7px] md:text-[8px] text-slate-300 uppercase truncate max-w-[80px]">{l.reason}</span>
                      </div>
                    </td>
                    <td className={`px-5 md:px-8 py-4 font-black text-[10px] md:text-sm text-right ${l.amountChange > 0 ? 'text-violet-600' : 'text-rose-600'}`}>
                      {l.amountChange > 0 ? '+' : ''}{l.amountChange.toLocaleString()}
                    </td>
                    <td className="px-5 md:px-8 py-4 font-black text-slate-900 text-[10px] md:text-sm text-right">₹{l.newPrincipal.toLocaleString()}</td>
                  </tr>
                ))}
                {principalLogs.length === 0 && (
                  <tr><td colSpan={3} className="p-10 text-center text-slate-200 font-bold italic text-xs">No balance history.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Modals with enhanced mobile padding and scrolling */}
      {showPrincipalModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in overflow-y-auto">
          <div className="bg-white rounded-[1.5rem] md:rounded-[2rem] w-full max-w-sm p-6 md:p-8 shadow-2xl border border-white">
            <h3 className="text-lg md:text-xl font-black text-slate-900 mb-5 md:mb-6 uppercase tracking-tighter">{t('adjustment')}</h3>
            <div className="space-y-4 md:space-y-6">
              <div className="flex gap-2 p-1 bg-slate-100 rounded-xl">
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'increase'})} 
                  className={`flex-1 py-2 rounded-lg transition-all font-black text-[9px] md:text-[10px] uppercase tracking-widest ${principalChange.type === 'increase' ? 'bg-white shadow-sm text-violet-600' : 'text-slate-400'}`}
                >
                  {t('lend')}
                </button>
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'decrease'})} 
                  className={`flex-1 py-2 rounded-lg transition-all font-black text-[9px] md:text-[10px] uppercase tracking-widest ${principalChange.type === 'decrease' ? 'bg-white shadow-sm text-rose-600' : 'text-slate-400'}`}
                >
                  {t('recover')}
                </button>
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Date</label>
                <input type="date" className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-slate-700 outline-none text-sm" value={principalChange.date} onChange={e => setPrincipalChange({...principalChange, date: e.target.value})} />
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('amount')}</label>
                <input type="number" placeholder="0" className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl font-black text-slate-700 outline-none text-sm" onChange={e => setPrincipalChange({...principalChange, amount: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('notes')}</label>
                <input type="text" className="w-full p-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-slate-500 outline-none text-sm" onChange={e => setPrincipalChange({...principalChange, reason: e.target.value})} />
              </div>
              <div className="flex gap-3 pt-2">
                <button onClick={() => setShowPrincipalModal(false)} className="flex-1 py-3 text-slate-400 font-black uppercase text-[10px] tracking-widest">{t('back')}</button>
                <button onClick={handleUpdatePrincipal} className="flex-1 py-3 bg-violet-600 text-white rounded-xl font-black text-sm shadow-lg shadow-violet-100">{t('save')}</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {showPaymentModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in overflow-y-auto">
          <div className="bg-white rounded-[1.5rem] md:rounded-[2rem] w-full max-w-sm p-6 md:p-8 shadow-2xl border border-white">
            <h3 className="text-lg md:text-xl font-black text-slate-900 mb-5 md:mb-6 uppercase tracking-tighter">{t('collect')}</h3>
            <div className="space-y-4 md:space-y-6">
              <div className="grid grid-cols-2 gap-2">
