      name: 'LendFlow Admin',
      logoUrl: '',
      backgroundUrl: 'https://images.unsplash.com/photo-1561059488-916d69792237?q=80&w=2600&auto=format&fit=crop'
    };
  });

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    document.body.style.backgroundImage = `url('${settings.backgroundUrl}')`;
  }, [settings.backgroundUrl]);

  const setLanguage = (lang: Language) => {
    setLanguageState(lang);
    localStorage.setItem('appLang', lang);
  };

  const updateSettings = (newSettings: FinanceSettings) => {
    setSettings(newSettings);
    localStorage.setItem('financeSettings', JSON.stringify(newSettings));
  };

  const t = (key: keyof typeof translations.en) => {
    return translations[language][key] || translations.en[key];
  };

  const handleLogin = (success: boolean) => {
    setIsAuthenticated(success);
    if (success) localStorage.setItem('isLoggedIn', 'true');
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    localStorage.removeItem('isLoggedIn');
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);
  const closeSidebar = () => setIsSidebarOpen(false);

  if (!isAuthenticated) {
    return (
      <AppContext.Provider value={{ language, setLanguage, t, settings, updateSettings }}>
        <Login onLogin={handleLogin} />
      </AppContext.Provider>
    );
  }

  return (
    <AppContext.Provider value={{ language, setLanguage, t, settings, updateSettings }}>
      <HashRouter>
        <div className="flex h-screen bg-transparent overflow-hidden relative">
          <div className="fixed top-3 right-14 md:top-6 md:right-8 z-[60] flex items-center">
            <button
              onClick={() => setLanguage(language === 'en' ? 'ta' : 'en')}
              className="bg-white/90 backdrop-blur-md border border-slate-200 px-3 py-1.5 md:px-4 md:py-2 rounded-full shadow-lg hover:shadow-violet-200 transition-all flex items-center gap-2 group active:scale-95"
              title={language === 'en' ? 'தமிழ் மொழிக்கு மாற்றவும்' : 'Switch to English'}
            >
              <div className="w-5 h-5 md:w-6 md:h-6 rounded-full bg-violet-600 text-white flex items-center justify-center text-[8px] md:text-[10px] font-black uppercase">
                {language === 'en' ? 'EN' : 'தமிழ்'}
              </div>
              <span className="text-[10px] md:text-xs font-black text-slate-600 uppercase tracking-widest hidden sm:inline">
                {language === 'en' ? 'தமிழ்' : 'English'}
              </span>
            </button>
          </div>

          <div className="md:hidden fixed top-0 left-0 right-0 h-16 bg-white/90 backdrop-blur-md border-b border-slate-100 flex items-center justify-between px-4 z-40">
            <h1 className="text-xl font-black text-violet-600 tracking-tighter uppercase truncate max-w-[150px]">
              {settings.name}
            </h1>
            <button 
              onClick={toggleSidebar} 
              className="w-10 h-10 flex items-center justify-center text-slate-500"
            >
              <i className={`fas ${isSidebarOpen ? 'fa-times' : 'fa-bars'} text-xl`}></i>
            </button>
          </div>

          {isSidebarOpen && (
            <div 
              className="md:hidden fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 transition-opacity"
              onClick={closeSidebar}
            />
          )}

          <Sidebar 
            onLogout={handleLogout} 
            isOpen={isSidebarOpen} 
            onClose={closeSidebar} 
          />

          <main className="flex-1 overflow-y-auto pt-20 md:pt-12 px-4 pb-12 md:px-8">
            <div className="max-w-7xl mx-auto">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/customers" element={<Customers />} />
                <Route path="/customers/:id" element={<CustomerDetails />} />
                <Route path="/reports" element={<Reports />} />
                <Route path="/settings" element={<Settings />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </div>
          </main>
        </div>
      </HashRouter>
    </AppContext.Provider>
  );
};

