import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { useApp } from '../App';

const Reports: React.FC = () => {
  const { t, settings } = useApp();
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  useEffect(() => {
    const c = localStorage.getItem('customers');
    const p = localStorage.getItem('payments');
    if (c) setCustomers(JSON.parse(c));
    if (p) setPayments(JSON.parse(p));
  }, []);

  const resetToCurrent = () => {
    setSelectedMonth(new Date().getMonth());
    setSelectedYear(new Date().getFullYear());
  };

  const generatePDF = async (m: number = selectedMonth, y: number = selectedYear) => {
    const doc = new jsPDF();
    const monthName = new Date(y, m).toLocaleString('default', { month: 'long' });

    // Add Logo if exists
    let startY = 22;
    if (settings.logoUrl) {
      try {
        // We try to add the image. Note: External URLs might have CORS issues.
        // In a real app, you'd proxy these or use base64.
        doc.addImage(settings.logoUrl, 'JPEG', 14, 10, 15, 15);
        startY = 32;
      } catch (e) {
        console.error("Could not load logo for PDF", e);
      }
    }

    doc.setFontSize(22);
    doc.setTextColor(124, 58, 237); // Violet-600
    doc.text(settings.name, settings.logoUrl ? 32 : 14, startY);

    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139); // Slate-500
    doc.text(`Portfolio Report | Generated: ${new Date().toLocaleDateString()} | Billing: ${monthName} ${y}`, 14, startY + 8);

    const tableData = customers.map(c => {
      const payment = payments.find(p => p.customerId === c.id && p.month === m && p.year === y);
      const interestDue = (c.principal * c.interestRate) / 100;
      return [
        c.name,
        `₹${c.principal.toLocaleString()}`,
        `₹${interestDue.toLocaleString()}`,
        payment ? `₹${payment.amountPaid.toLocaleString()}` : '₹0',
        payment ? payment.status : (c.principal > 0 ? 'Pending' : 'N/A')
      ];
    });

    autoTable(doc, {
      startY: startY + 15,
      head: [['Customer Name', 'Capital Balance', 'Interest Due', 'Interest Paid', 'Status']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: [124, 58, 237] }, // Violet-600
      styles: { fontSize: 9 }
    });

    const totalCollected = payments
      .filter(p => p.month === m && p.year === y)
      .reduce((sum, p) => sum + p.amountPaid, 0);

    const totalDue = customers.reduce((sum, c) => sum + (c.principal * c.interestRate / 100), 0);
    const totalOutstanding = customers.reduce((sum, c) => sum + c.principal, 0);

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFillColor(245, 243, 255); // Violet-50
    doc.rect(14, finalY, 182, 40, 'F');

    doc.setFontSize(14);
    doc.setTextColor(124, 58, 237);
    doc.text('Financial Summary', 20, finalY + 10);

    doc.setFontSize(10);
    doc.setTextColor(30, 41, 59);
    doc.text(`Interest Collected:`, 20, finalY + 20);
    doc.text(`₹${totalCollected.toLocaleString()}`, 150, finalY + 20, { align: 'right' });

    doc.text(`Pending Interest:`, 20, finalY + 27);
    doc.text(`₹${(totalDue - totalCollected).toLocaleString()}`, 150, finalY + 27, { align: 'right' });

    doc.text(`Total Capital:`, 20, finalY + 34);
    doc.text(`₹${totalOutstanding.toLocaleString()}`, 150, finalY + 34, { align: 'right' });

    doc.save(`${settings.name.replace(/\s/g, '_')}_${monthName}_${y}.pdf`);
  };

  const handleQuickExport = () => {
    const now = new Date();
    generatePDF(now.getMonth(), now.getFullYear());
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-end gap-2 px-1">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tight uppercase">{t('exports')}</h2>
          <p className="text-slate-500 font-medium text-xs md:text-base">Portfolio financial reports.</p>
        </div>
        <button 
          onClick={resetToCurrent}
          className="text-[10px] font-black text-violet-600 hover:bg-violet-50 px-3 py-1.5 rounded-xl transition-all uppercase tracking-widest"
        >
          {t('clear')}
        </button>
      </header>

      <div className="bg-white p-6 md:p-12 rounded-[2rem] md:rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50 max-w-xl mx-auto text-center relative overflow-hidden">
        <div className="hidden md:block absolute top-0 right-0 w-32 h-32 bg-violet-50 rounded-full -mr-16 -mt-16 opacity-50"></div>

        <div className="relative z-10">
          <div className="w-16 h-16 md:w-20 md:h-20 bg-violet-100 text-violet-600 rounded-2xl md:rounded-3xl flex items-center justify-center text-2xl md:text-3xl mx-auto mb-4 md:mb-6 shadow-lg shadow-violet-100">
            {settings.logoUrl ? (
               <img src={settings.logoUrl} className="w-full h-full object-contain rounded-2xl" />
            ) : (
               <i className="fas fa-file-invoice"></i>
            )}
          </div>
          <h3 className="text-xl md:text-2xl font-black text-slate-900 mb-1.5 uppercase tracking-tight">{t('statementCenter')}</h3>
          <p className="text-[11px] md:text-sm text-slate-400 mb-8 max-w-xs mx-auto font-medium">Download the complete portfolio status for any billing period.</p>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 md:gap-6 mb-8 md:mb-10">
            <div className="text-left space-y-1.5">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('month')}</label>
              <select 
                className="w-full p-3 md:p-4 bg-slate-50 border border-slate-100 rounded-xl md:rounded-2xl outline-none focus:ring-2 focus:ring-violet-200 font-bold text-slate-700 text-sm"
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              >
                {Array.from({length: 12}).map((_, i) => (
                  <option key={i} value={i}>{new Date(0, i).toLocaleString('default', {month: 'long'})}</option>
                ))}
              </select>
            </div>
            <div className="text-left space-y-1.5">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('year')}</label>
              <select 
                className="w-full p-3 md:p-4 bg-slate-50 border border-slate-100 rounded-xl md:rounded-2xl outline-none focus:ring-2 focus:ring-violet-200 font-bold text-slate-700 text-sm"
                value={selectedYear}
                onChange={(e) => setSelectedYear(parseInt(e.target.value))}
              >
                <option value={2024}>2024</option>
                <option value={2025}>2025</option>
                <option value={2026}>2026</option>
              </select>
            </div>
          </div>

          <div className="flex flex-col gap-3 md:gap-4">
            <button 
              onClick={() => generatePDF()}
              className="w-full bg-violet-600 text-white py-4 md:py-5 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 flex items-center justify-center gap-3 active:scale-[0.98]"
            >
              <i className="fas fa-file-export"></i>
              {t('exportPdf')}
            </button>

            <button 
              onClick={handleQuickExport}
              className="w-full bg-white text-violet-600 border-2 border-violet-100 py-3 md:py-4 rounded-2xl font-black text-xs md:text-base hover:bg-violet-50 transition-all flex items-center justify-center gap-2"
            >
              <i className="fas fa-bolt text-[10px] md:text-xs"></i>
              {t('quickExport')}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

