export default Sidebar;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';
import { useApp } from '../App';

// CustomerDetails component handles viewing and updating a specific borrower's loan details
const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { t } = useApp();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  const [principalChange, setPrincipalChange] = useState({ 
    amount: 0, 
    reason: '', 
    type: 'increase',
    date: new Date().toISOString().split('T')[0]
  });

  const [paymentInput, setPaymentInput] = useState({ 
    amount: 0, 
    month: new Date().getMonth(), 
    year: new Date().getFullYear(),
    collectionDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    const customersRaw = localStorage.getItem('customers');
    const paymentsRaw = localStorage.getItem('payments');
    const logsRaw = localStorage.getItem('principalLogs');

    if (customersRaw) {
      const allCustomers = JSON.parse(customersRaw);
      const c = allCustomers.find((x: any) => x.id === id);
      if (c) setCustomer(c);
      else navigate('/customers');
    }
    if (paymentsRaw) setPayments(JSON.parse(paymentsRaw).filter((p: any) => p.customerId === id));
    if (logsRaw) setPrincipalLogs(JSON.parse(logsRaw).filter((l: any) => l.customerId === id));
  }, [id, navigate]);

  const updateGlobal = (key: string, data: any[]) => {
    const raw = localStorage.getItem(key);
    let all = raw ? JSON.parse(raw) : [];
    if (key === 'customers') {
      all = all.map((c: any) => c.id === id ? data[0] : c);
    } else {
      const others = all.filter((x: any) => x.customerId !== id);
      all = [...others, ...data];
    }
    localStorage.setItem(key, JSON.stringify(all));
  };

  const handleUpdatePrincipal = () => {
    if (!customer) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;
    const updatedCustomer = { ...customer, principal: newP };

    const timestamp = new Date(principalChange.date).getTime();

    const newLog: PrincipalLog = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      amountChange: diff, 
      newPrincipal: newP, 
      reason: principalChange.reason || 'Manual Adjustment', 
      timestamp: timestamp 
    };

    setCustomer(updatedCustomer);
    const updatedLogs = [...principalLogs, newLog];
    setPrincipalLogs(updatedLogs);
    updateGlobal('customers', [updatedCustomer]);
    updateGlobal('principalLogs', updatedLogs);
    setShowPrincipalModal(false);
    setPrincipalChange({ ...principalChange, amount: 0, reason: '' });
  };

  const handleAddPayment = () => {
    if (!customer) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const timestamp = new Date(paymentInput.collectionDate).getTime();

    const newPayment: Payment = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      month: paymentInput.month, 
      year: paymentInput.year, 
      amountPaid: paymentInput.amount, 
      totalDue: totalDue, 
      status: status as 'Paid' | 'Partial' | 'Pending', 
      timestamp: timestamp 
    };

    const updatedPayments = [...payments, newPayment];
    setPayments(updatedPayments);
    updateGlobal('payments', updatedPayments);
    setShowPaymentModal(false);
    setPaymentInput({ ...paymentInput, amount: 0 });
  };

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4 px-1">
        <div className="space-y-1.5 md:space-y-2 w-full">
          <button 
            onClick={() => navigate('/customers')} 
            className="text-[9px] md:text-[10px] font-black text-violet-600 hover:bg-violet-50 px-2 py-1 md:px-3 md:py-1.5 rounded-lg uppercase tracking-widest transition-all mb-1"
          >
            <i className="fas fa-arrow-left mr-2"></i> {t('ledger')}
          </button>
          <h2 className="text-2xl md:text-4xl font-black text-slate-900 tracking-tight truncate">{customer.name}</h2>
          <p className="text-xs md:text-sm text-slate-500 font-medium flex items-center gap-2">
            <i className="fas fa-location-dot text-slate-300"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a 
            href={`tel:${customer.phone}`} 
            className="bg-emerald-100 text-emerald-700 w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center hover:bg-emerald-200 transition-all shadow-lg shadow-emerald-50 shrink-0"
          >
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button 
            onClick={() => setShowPrincipalModal(true)} 
            className="flex-1 md:flex-none bg-violet-600 text-white px-5 py-3 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-xs md:text-base"
          >
            <i className="fas fa-coins"></i> {t('adjustment')}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-8">
        <div className="bg-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 md:mb-3">{t('capital')}</p>
          <p className="text-lg md:text-3xl font-black text-slate-900 leading-none truncate">₹{customer.principal.toLocaleString()}</p>
        </div>
        <div className="bg-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-2">
          <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 md:mb-3">Interest ({customer.interestRate}%)</p>
          <p className="text-lg md:text-3xl font-black text-violet-600 leading-none truncate">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
        </div>
        <div className="bg-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-3">
          <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 md:mb-3">{t('due')}</p>
          <div className="inline-flex items-center gap-2 bg-violet-50 text-violet-600 px-2 py-1 md:px-4 md:py-2 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm uppercase tracking-widest">
            Day {customer.dueDate}
          </div>
        </div>
        <div className="bg-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 md:mb-3">{t('startDate')}</p>
          <p className="text-sm md:text-xl font-black text-slate-700 truncate">
            {customer.startDate ? new Date(customer.startDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short' }) : 'N/A'}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in delay-2">
          <div className="px-5 md:px-8 py-4 md:py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
            <h3 className="font-black text-slate-800 uppercase tracking-tighter text-xs md:text-base">{t('interestLedger')}</h3>
            <button 
              onClick={() => setShowPaymentModal(true)} 
              className="bg-violet-600 text-white w-7 h-7 md:w-8 md:h-8 rounded-lg flex items-center justify-center shadow-lg shadow-violet-100 transition-transform hover:scale-110 active:scale-95"
            >
              <i className="fas fa-plus text-[10px] md:text-xs"></i>
            </button>
          </div>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full text-left min-w-[400px]">
              <thead className="bg-slate-50/50 text-slate-400 font-black text-[8px] md:text-[10px] uppercase tracking-widest border-b border-slate-50">
                <tr>
                  <th className="px-5 md:px-8 py-3 md:py-4">{t('month')}</th>
                  <th className="px-5 md:px-8 py-3 md:py-4">{t('amount')}</th>
                  <th className="px-5 md:px-8 py-3 md:py-4">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {payments.sort((a,b) => b.timestamp - a.timestamp).map(p => (
                  <tr key={p.id} className="text-xs md:text-sm hover:bg-slate-50/50 transition-colors">
                    <td className="px-5 md:px-8 py-3 md:py-4 font-bold text-slate-600">
                      {new Date(0, p.month).toLocaleString('default', { month: 'short' })} {p.year}
                    </td>
                    <td className="px-5 md:px-8 py-3 md:py-4 font-black text-slate-900">₹{p.amountPaid.toLocaleString()}</td>
                    <td className="px-5 md:px-8 py-3 md:py-4">
                      <span className={`px-2 py-1 rounded-md text-[8px] md:text-[10px] font-black uppercase tracking-tighter ${
                        p.status === 'Paid' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'
                      }`}>
                        {p.status}
                      </span>
                    </td>
                  </tr>
                ))}
                {payments.length === 0 && (
                  <tr>
                    <td colSpan={3} className="px-8 py-12 text-center text-slate-300 font-medium italic">No payments recorded.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in delay-3 flex flex-col">
           <div className="px-5 md:px-8 py-4 md:py-6 border-b border-slate-50 bg-slate-50/50">
            <h3 className="font-black text-slate-800 uppercase tracking-tighter text-xs md:text-base">{t('audit')}</h3>
          </div>
          <div className="flex-1 overflow-y-auto max-h-[400px] scrollbar-hide">
            <div className="p-5 md:p-8 space-y-4">
              {principalLogs.sort((a,b) => b.timestamp - a.timestamp).map(log => (
                <div key={log.id} className="relative pl-6 border-l-2 border-slate-100 py-1">
                  <div className={`absolute left-[-9px] top-2 w-4 h-4 rounded-full border-2 border-white shadow-sm ${log.amountChange > 0 ? 'bg-violet-600' : 'bg-rose-500'}`}></div>
                  <div className="flex justify-between items-start gap-2">
                    <p className="text-[10px] md:text-xs font-black text-slate-800 uppercase tracking-tight truncate max-w-[150px]">{log.reason}</p>
                    <p className="text-[8px] md:text-[9px] font-bold text-slate-400 whitespace-nowrap">{new Date(log.timestamp).toLocaleDateString()}</p>
                  </div>
                  <p className={`text-xs md:text-sm font-black ${log.amountChange > 0 ? 'text-violet-600' : 'text-rose-600'}`}>
                    {log.amountChange > 0 ? '+' : ''}{log.amountChange.toLocaleString()}
                  </p>
                  <p className="text-[8px] md:text-[9px] text-slate-400 font-medium">New Balance: ₹{log.newPrincipal.toLocaleString()}</p>
                </div>
              ))}
              {principalLogs.length === 0 && (
                <p className="text-center py-10 text-slate-300 italic text-sm">No adjustments logged yet.</p>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Principal Modal */}
      {showPrincipalModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in">
          <div className="bg-white rounded-[2rem] w-full max-w-md shadow-2xl overflow-hidden border border-white">
            <div className="p-6 md:p-8 bg-violet-600 text-white flex justify-between items-center">
              <h3 className="text-lg md:text-xl font-black uppercase tracking-tighter">{t('adjustment')}</h3>
              <button onClick={() => setShowPrincipalModal(false)} className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/20 hover:bg-white/30 transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 md:p-8 space-y-6">
              <div className="flex p-1 bg-slate-100 rounded-xl">
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'increase'})}
                  className={`flex-1 py-2 rounded-lg font-black text-[10px] uppercase tracking-widest transition-all ${principalChange.type === 'increase' ? 'bg-white text-violet-600 shadow-sm' : 'text-slate-400'}`}
                >
                  {t('lend')}
                </button>
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'decrease'})}
                  className={`flex-1 py-2 rounded-lg font-black text-[10px] uppercase tracking-widest transition-all ${principalChange.type === 'decrease' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-400'}`}
                >
                  {t('recover')}
                </button>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('amount')}</label>
                <input 
                  type="number" 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-black text-lg text-slate-800" 
                  value={principalChange.amount} 
                  onChange={e => setPrincipalChange({...principalChange, amount: parseFloat(e.target.value) || 0})}
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('notes')}</label>
                <input 
                  type="text" 
                  placeholder="Reason for adjustment..."
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm text-slate-800" 
                  value={principalChange.reason} 
                  onChange={e => setPrincipalChange({...principalChange, reason: e.target.value})}
                />
              </div>
              <button onClick={handleUpdatePrincipal} className="w-full bg-violet-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-violet-100 hover:bg-violet-700 active:scale-[0.98] transition-all">
                {t('submit')}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Payment Modal */}
      {showPaymentModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in">
          <div className="bg-white rounded-[2rem] w-full max-w-md shadow-2xl overflow-hidden border border-white">
            <div className="p-6 md:p-8 bg-violet-600 text-white flex justify-between items-center">
              <h3 className="text-lg md:text-xl font-black uppercase tracking-tighter">{t('collect')}</h3>
              <button onClick={() => setShowPaymentModal(false)} className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/20">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 md:p-8 space-y-5">
              <div className="p-4 bg-violet-50 rounded-2xl border border-violet-100">
                <p className="text-[9px] font-black text-violet-400 uppercase tracking-[0.2em] mb-1">{t('expectedInterest')}</p>
                <p className="text-xl font-black text-violet-600">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('month')}</label>
                  <select 
                    className="w-full px-3 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm"
                    value={paymentInput.month}
                    onChange={e => setPaymentInput({...paymentInput, month: parseInt(e.target.value)})}
                  >
                    {Array.from({length: 12}).map((_, i) => (
                      <option key={i} value={i}>{new Date(0, i).toLocaleString('default', { month: 'long' })}</option>
                    ))}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('year')}</label>
                  <select 
                    className="w-full px-3 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm"
                    value={paymentInput.year}
                    onChange={e => setPaymentInput({...paymentInput, year: parseInt(e.target.value)})}
                  >
                    {[2024, 2025, 2026].map(y => (
                      <option key={y} value={y}>{y}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('amount')}</label>
                <input 
                  type="number" 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl font-black text-lg text-emerald-600" 
                  value={paymentInput.amount} 
                  onChange={e => setPaymentInput({...paymentInput, amount: parseFloat(e.target.value) || 0})}
                />
              </div>
              <button onClick={handleAddPayment} className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-emerald-50 hover:bg-emerald-700 active:scale-[0.98] transition-all">
                {t('collect')}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default CustomerDetails;

