      const allCustomers = JSON.parse(customersRaw);
      const c = allCustomers.find((x: any) => x.id === id);
      if (c) setCustomer(c);
      else navigate('/customers');
    }
    if (paymentsRaw) setPayments(JSON.parse(paymentsRaw).filter((p: any) => p.customerId === id));
    if (logsRaw) setPrincipalLogs(JSON.parse(logsRaw).filter((l: any) => l.customerId === id));
  }, [id, navigate]);

  const updateGlobal = (key: string, data: any[]) => {
    const raw = localStorage.getItem(key);
    let all = raw ? JSON.parse(raw) : [];
    if (key === 'customers') {
      all = all.map((c: any) => c.id === id ? data[0] : c);
    } else {
      const others = all.filter((x: any) => x.customerId !== id);
      all = [...others, ...data];
    }
    localStorage.setItem(key, JSON.stringify(all));
  };

  const handleUpdatePrincipal = () => {
    if (!customer) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;
    const updatedCustomer = { ...customer, principal: newP };

    const timestamp = new Date(principalChange.date).getTime();

    const newLog: PrincipalLog = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      amountChange: diff, 
      newPrincipal: newP, 
      reason: principalChange.reason || 'Manual Adjustment', 
      timestamp: timestamp 
    };

    setCustomer(updatedCustomer);
    const updatedLogs = [...principalLogs, newLog];
    setPrincipalLogs(updatedLogs);
    updateGlobal('customers', [updatedCustomer]);
    updateGlobal('principalLogs', updatedLogs);
    setShowPrincipalModal(false);
    setPrincipalChange({ ...principalChange, amount: 0, reason: '' });
  };

  const handleAddPayment = () => {
    if (!customer) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const timestamp = new Date(paymentInput.collectionDate).getTime();

    const newPayment: Payment = { 
      id: Date.now().toString(), 
      customerId: customer.id, 
      month: paymentInput.month, 
      year: paymentInput.year, 
      amountPaid: paymentInput.amount, 
      totalDue: totalDue, 
      status: status as 'Paid' | 'Partial' | 'Pending', 
      timestamp: timestamp 
    };

    const updatedPayments = [...payments, newPayment];
    setPayments(updatedPayments);
    updateGlobal('payments', updatedPayments);
    setShowPaymentModal(false);
    setPaymentInput({ ...paymentInput, amount: 0 });
  };

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4 px-1">
        <div className="space-y-1 md:space-y-2 w-full">
          <button 
            onClick={() => navigate('/customers')} 
            className="text-[10px] font-black text-violet-600 hover:bg-violet-50 px-3 py-1.5 rounded-xl uppercase tracking-widest transition-all mb-2 flex items-center w-fit"
          >
            <i className="fas fa-arrow-left mr-2"></i> {t('ledger')}
          </button>
          <h2 className="text-3xl md:text-4xl font-black text-slate-900 tracking-tight truncate">{customer.name}</h2>
          <p className="text-sm text-slate-500 font-medium flex items-center gap-2">
            <i className="fas fa-location-dot text-slate-300"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a 
            href={`tel:${customer.phone}`} 
            className="bg-emerald-100 text-emerald-700 w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center hover:bg-emerald-200 transition-all shadow-lg shadow-emerald-50 shrink-0"
          >
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button 
            onClick={() => setShowPrincipalModal(true)} 
            className="flex-1 md:flex-none bg-violet-600 text-white px-6 py-3.5 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-sm md:text-base active:scale-95"
          >
            <i className="fas fa-coins"></i> {t('adjustment')}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-6">
        <div className="bg-white p-5 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">{t('capital')}</p>
          <p className="text-xl md:text-3xl font-black text-slate-900 leading-none truncate">₹{customer.principal.toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-2">
          <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">Interest ({customer.interestRate}%)</p>
          <p className="text-xl md:text-3xl font-black text-violet-600 leading-none truncate">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-3">
          <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">{t('due')}</p>
          <div className="inline-flex items-center gap-2 bg-violet-50 text-violet-600 px-3 py-1.5 rounded-xl font-black text-[10px] md:text-sm uppercase tracking-widest">
            Day {customer.dueDate}
          </div>
        </div>
        <div className="bg-white p-5 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border border-slate-100 shadow-sm animate-in delay-1">
          <p className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-2">{t('startDate')}</p>
          <p className="text-base md:text-xl font-black text-slate-700 truncate">
            {customer.startDate ? new Date(customer.startDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' }) : 'N/A'}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
