            >
              <i className="fas fa-plus text-xs md:text-sm"></i>
            </button>
          </div>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full text-left min-w-[450px]">
              <thead className="bg-slate-50/50 text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-widest border-b border-slate-50">
                <tr>
                  <th className="px-6 md:px-8 py-4">{t('month')}</th>
                  <th className="px-6 md:px-8 py-4">{t('amount')}</th>
                  <th className="px-6 md:px-8 py-4">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {payments.sort((a,b) => b.timestamp - a.timestamp).map(p => {
                   const dueAmount = p.totalDue - p.amountPaid;
                   return (
                    <tr key={p.id} className="text-xs md:text-sm hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 md:px-8 py-4 font-bold text-slate-600">
