        </div>

        <div className="bg-white rounded-[1.5rem] md:rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden animate-in delay-3 flex flex-col min-h-[400px]">
           <div className="px-6 py-5 md:px-8 md:py-6 border-b border-slate-50 bg-slate-50/50">
