                  </div>
                  <p className={`text-sm md:text-base font-black ${log.amountChange > 0 ? 'text-violet-600' : 'text-rose-600'}`}>
                    {log.amountChange > 0 ? '+' : ''}₹{Math.abs(log.amountChange).toLocaleString()}
                  </p>
                  <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest mt-0.5">New Balance: ₹{log.newPrincipal.toLocaleString()}</p>
                </div>
              ))}
              {principalLogs.length === 0 && (
                <div className="text-center py-20">
                  <i className="fas fa-history text-slate-100 text-5xl mb-4"></i>
