                  value={principalChange.reason} 
                  onChange={e => setPrincipalChange({...principalChange, reason: e.target.value})}
                />
              </div>
              <button onClick={handleUpdatePrincipal} className="w-full bg-violet-600 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-violet-200 hover:bg-violet-700 active:scale-[0.98] transition-all">
                {t('submit')}
              </button>
            </div>
          </div>
        </div>
      )}

      {showPaymentModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in">
          <div className="bg-white rounded-[2rem] w-full max-w-sm shadow-2xl overflow-hidden border border-white">
            <div className="p-6 bg-violet-600 text-white flex justify-between items-center">
              <h3 className="text-lg font-black uppercase tracking-tighter">{t('collect')}</h3>
              <button onClick={() => setShowPaymentModal(false)} className="w-9 h-9 flex items-center justify-center rounded-xl bg-white/20">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 md:p-8 space-y-5">
              <div className="p-5 bg-violet-50 rounded-[1.5rem] border border-violet-100">
                <p className="text-[10px] font-black text-violet-400 uppercase tracking-[0.2em] mb-1">{t('expectedInterest')}</p>
                <p className="text-2xl font-black text-violet-600">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('month')}</label>
