                    className="w-full px-3 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none"
                    value={paymentInput.month}
                    onChange={e => setPaymentInput({...paymentInput, month: parseInt(e.target.value)})}
                  >
                    {Array.from({length: 12}).map((_, i) => (
                      <option key={i} value={i}>{new Date(0, i).toLocaleString('default', { month: 'short' })}</option>
                    ))}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('year')}</label>
                  <select 
                    className="w-full px-3 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm outline-none"
                    value={paymentInput.year}
                    onChange={e => setPaymentInput({...paymentInput, year: parseInt(e.target.value)})}
                  >
                    {[2024, 2025, 2026].map(y => (
                      <option key={y} value={y}>{y}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('amount')}</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 font-black text-emerald-400">₹</span>
                  <input 
                    type="number" 
                    className="w-full pl-9 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-xl text-emerald-600 outline-none focus:ring-4 focus:ring-emerald-50 transition-all" 
                    value={paymentInput.amount || ''} 
                    onChange={e => setPaymentInput({...paymentInput, amount: parseFloat(e.target.value) || 0})}
                  />
                </div>
              </div>
              <button onClick={handleAddPayment} className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-emerald-50 hover:bg-emerald-700 active:scale-[0.98] transition-all">
                {t('collect')}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

