                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${isDark ? 'left-7' : 'left-1'}`} />
              </button>
              <span className={`text-[10px] font-black uppercase tracking-widest ${isDark ? 'text-violet-400' : 'text-slate-500'}`}>Dark</span>
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
            {themePresets.map(preset => (
              <button
                key={preset.name}
                type="button"
                onClick={() => setFormData({ ...formData, backgroundUrl: preset.url, themeMode: preset.mode as any })}
                className={`group relative h-24 md:h-28 rounded-2xl overflow-hidden border-4 transition-all ${formData.backgroundUrl === preset.url ? 'border-violet-600 scale-[1.02] shadow-xl' : `border-transparent ${isDark ? 'hover:border-slate-600' : 'hover:border-violet-200'}`}`}
              >
                <img src={preset.url} className="w-full h-full object-cover" alt={preset.name} />
                <div className={`absolute inset-0 bg-black/50 flex flex-col items-center justify-center transition-opacity ${formData.backgroundUrl === preset.url ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
                   <span className="text-white text-[8px] font-black uppercase tracking-widest text-center px-2">{preset.name}</span>
                   <span className="text-white/60 text-[7px] font-bold uppercase mt-1">{preset.mode}</span>
                </div>
              </button>
            ))}
          </div>

          <div className="space-y-2 pt-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Custom Wallpaper URL</label>
            <input 
              type="text" 
              className={`w-full px-5 py-4 ${isDark ? 'bg-slate-800 border-slate-700 text-slate-300' : 'bg-slate-50 border-slate-100 text-slate-600'} border rounded-2xl font-bold outline-none text-sm`}
              value={formData.backgroundUrl}
              onChange={e => setFormData({ ...formData, backgroundUrl: e.target.value })}
            />
          </div>
        </div>

        <button 
          type="submit" 
          className="w-full bg-violet-600 text-white py-5 rounded-[1.5rem] font-black text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 active:scale-95"
        >
          {t('updateBranding')}
        </button>
      </form>
    </div>
  );
};

export default Settings;

import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import { Link } from 'react-router-dom';
import { useApp } from '../App';

const Dashboard: React.FC = () => {
  const { t, settings } = useApp();
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);

  useEffect(() => {
    const savedCustomers = localStorage.getItem('customers');
    const savedPayments = localStorage.getItem('payments');
    if (savedCustomers) setCustomers(JSON.parse(savedCustomers));
    if (savedPayments) setPayments(JSON.parse(savedPayments));
  }, []);

  const totalPrincipal = customers.reduce((sum, c) => sum + c.principal, 0);
  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();
  const today = new Date().getDate();

  const monthlyIncome = payments
    .filter(p => p.month === currentMonth && p.year === currentYear)
    .reduce((sum, p) => sum + p.amountPaid, 0);

  const dueToday = customers.filter(c => c.dueDate === today && c.principal > 0);
  const overdue = customers.filter(c => {
    const payment = payments.find(p => p.customerId === c.id && p.month === currentMonth && p.year === currentYear);
    const isOverdue = today > c.dueDate && (!payment || payment.status !== 'Paid');
    return isOverdue && c.principal > 0;
  });

  const isDark = settings.themeMode === 'dark';

  return (
    <div className="space-y-6 md:space-y-10 animate-in pb-12">
      <header className="px-1 text-center md:text-left">
        <h2 className={`text-3xl md:text-4xl font-black tracking-tight uppercase ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{t('overview')}</h2>
        <p className={`${isDark ? 'text-slate-400' : 'text-slate-500'} font-medium text-sm md:text-base`}>{t('portfolioSummary')}</p>
      </header>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        <StatCard isDark={isDark} label={t('active')} value={customers.length.toString()} icon="fa-users" color="bg-violet-600" delay="delay-1" tooltip="Total borrowers" />
        <StatCard isDark={isDark} label={t('capital')} value={`₹${totalPrincipal.toLocaleString()}`} icon="fa-money-bill-wave" color={isDark ? 'bg-slate-700' : 'bg-slate-900'} delay="delay-2" tooltip="Total outstanding principal" />
        <StatCard isDark={isDark} label={t('income')} value={`₹${monthlyIncome.toLocaleString()}`} icon="fa-hand-holding-dollar" color="bg-violet-500" delay="delay-3" tooltip="Interest collected this month" />
        <StatCard isDark={isDark} label={t('action')} value={overdue.length.toString()} icon="fa-clock" color="bg-rose-500" delay="delay-1" tooltip="Overdue accounts" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <section className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-6 md:p-8 rounded-[2rem] border shadow-sm animate-in delay-2`}>
          <h3 className={`text-xl font-black mb-6 flex items-center gap-3 uppercase tracking-tight ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>
            <span className={`w-10 h-10 rounded-xl ${isDark ? 'bg-violet-900/40 text-violet-400' : 'bg-violet-100 text-violet-600'} flex items-center justify-center`}>
              <i className="fas fa-calendar-day text-sm"></i>
            </span>
            {t('dueToday')}
          </h3>
          <div className="space-y-3">
            {dueToday.length > 0 ? (
              dueToday.map(c => (
                <div key={c.id} className={`flex justify-between items-center p-4 rounded-2xl border border-transparent transition-all active:scale-[0.98] ${isDark ? 'hover:bg-slate-800 hover:border-slate-700' : 'hover:bg-slate-50 hover:border-slate-100'}`}>
                  <div className="min-w-0 flex-1 pr-2">
                    <p className={`font-black text-sm md:text-base truncate ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{c.name}</p>
                    <p className={`text-[10px] md:text-xs font-bold tracking-widest uppercase ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>{c.phone}</p>
                  </div>
                  <div className="text-right shrink-0">
                    <p className="font-black text-violet-600 text-sm md:text-base">₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                    <Link 
                      to={`/customers/${c.id}`} 
                      className={`text-[10px] font-black uppercase tracking-widest transition-colors ${isDark ? 'text-slate-500 hover:text-violet-400' : 'text-slate-300 hover:text-violet-600'}`}
                    >
                      {t('details')}
                    </Link>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-12">
                <p className={`font-black uppercase tracking-widest text-xs ${isDark ? 'text-slate-600' : 'text-slate-300'}`}>Clear for today!</p>
              </div>
            )}
          </div>
        </section>

        <section className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-6 md:p-8 rounded-[2rem] border shadow-sm animate-in delay-3`}>
          <h3 className={`text-xl font-black mb-6 flex items-center gap-3 uppercase tracking-tight ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>
            <span className={`w-10 h-10 rounded-xl ${isDark ? 'bg-rose-900/40 text-rose-400' : 'bg-rose-100 text-rose-600'} flex items-center justify-center`}>
              <i className="fas fa-exclamation-triangle text-sm"></i>
            </span>
            {t('overdue')}
          </h3>
          <div className="space-y-3">
            {overdue.length > 0 ? (
              overdue.map(c => (
                <div key={c.id} className={`flex justify-between items-center p-4 rounded-2xl border transition-all active:scale-[0.98] ${isDark ? 'bg-rose-900/20 border-rose-900/40' : 'bg-rose-50/40 border-rose-100'}`}>
                  <div className="min-w-0 flex-1 pr-2">
                    <p className={`font-black text-sm md:text-base truncate ${isDark ? 'text-rose-100' : 'text-rose-900'}`}>{c.name}</p>
                    <p className={`text-[10px] font-black uppercase tracking-widest ${isDark ? 'text-rose-400/60' : 'text-rose-400'}`}>{t('due')}: {c.dueDate}th</p>
                  </div>
                  <div className="text-right shrink-0">
                    <p className={`font-black text-sm md:text-base ${isDark ? 'text-rose-400' : 'text-rose-700'}`}>₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                    <Link 
                      to={`/customers/${c.id}`} 
                      className={`text-[10px] font-black uppercase tracking-widest ${isDark ? 'text-rose-300 hover:text-rose-200' : 'text-rose-500 hover:underline'}`}
                    >
                      {t('collect')}
                    </Link>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-12">
                <p className={`font-black uppercase tracking-widest text-xs ${isDark ? 'text-slate-600' : 'text-slate-300'}`}>All caught up!</p>
              </div>
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: string; color: string; delay?: string; tooltip?: string; isDark: boolean }> = ({ label, value, icon, color, delay, tooltip, isDark }) => (
  <div 
    className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-5 md:p-8 rounded-[1.5rem] md:rounded-[2.5rem] border shadow-sm flex flex-col items-center justify-center gap-3 animate-in ${delay} hover:shadow-xl transition-all group`}
    title={tooltip}
  >
    <div className={`${color} w-12 h-12 md:w-16 md:h-16 rounded-2xl flex items-center justify-center text-white text-xl md:text-2xl shadow-lg transition-transform group-hover:scale-110`}>
      <i className={`fas ${icon}`}></i>
    </div>
    <div className="text-center min-w-0 w-full">
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 truncate">{label}</p>
      <p className={`text-base md:text-2xl font-black leading-tight truncate ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{value}</p>
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Customer } from '../types';
import { useApp } from '../App';

const Customers: React.FC = () => {
  const { t, settings } = useApp();
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  const [searchTerm, setSearchTerm] = useState('');
  const [minPrincipal, setMinPrincipal] = useState<string>('');
  const [maxPrincipal, setMaxPrincipal] = useState<string>('');

  const [newCustomer, setNewCustomer] = useState<Partial<Customer>>({
    name: '', 
    phone: '', 
    address: '', 
    principal: 0, 
    interestRate: 5, 
    dueDate: new Date().getDate(),
    startDate: Date.now()
  });

  useEffect(() => {
    const saved = localStorage.getItem('customers');
    if (saved) setCustomers(JSON.parse(saved));
  }, []);

  const handleAddCustomer = (e: React.FormEvent) => {
    e.preventDefault();
    const customer: Customer = {
      ...newCustomer as Customer,
      id: Date.now().toString(),
      createdAt: Date.now()
    };
    const updated = [...customers, customer];
    setCustomers(updated);
    localStorage.setItem('customers', JSON.stringify(updated));
    setIsModalOpen(false);
    setNewCustomer({ 
      name: '', 
      phone: '', 
      address: '', 
      principal: 0, 
      interestRate: 5, 
      dueDate: new Date().getDate(),
      startDate: Date.now()
    });
  };

  const clearFilters = () => {
    setSearchTerm('');
    setMinPrincipal('');
    setMaxPrincipal('');
  };

  const filteredCustomers = customers.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         c.phone.includes(searchTerm);
    const min = minPrincipal === '' ? 0 : parseFloat(minPrincipal);
    const max = maxPrincipal === '' ? Infinity : parseFloat(maxPrincipal);
    return matchesSearch && c.principal >= min && c.principal <= max;
  });

  const isDark = settings.themeMode === 'dark';

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 px-1">
        <div>
