import React, { useState } from 'react';
import { useApp } from '../App';

interface LoginProps {
  onLogin: (success: boolean) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const { settings } = useApp();
  const [view, setView] = useState<'login' | 'reset'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isResetSent, setIsResetSent] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 800));

    if (view === 'login') {
      if ((email === 'admin@lendflow.com' || email === 'owner@lendflow.com') && password === 'admin123') {
        onLogin(true);
      } else {
        setError('Invalid credentials or not authorized.');
      }
    } else {
      // Simulate password reset logic
      if (email.includes('@')) {
        setIsResetSent(true);
      } else {
        setError('Please enter a valid administrative email.');
      }
    }
    setIsLoading(false);
  };

  return (
    <div className="min-h-screen bg-transparent flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white/90 backdrop-blur-xl rounded-[2.5rem] shadow-2xl shadow-violet-200/50 overflow-hidden animate-in border border-white/50">
        <div className="bg-violet-600 p-8 md:p-12 text-center text-white relative">
          <div className="absolute top-0 left-0 w-full h-full opacity-10 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-white via-transparent to-transparent"></div>
          <div className="relative z-10">
            <div className="w-12 h-12 md:w-16 md:h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 md:mb-6 backdrop-blur-md overflow-hidden border-2 border-white/20 shadow-inner">
              {settings.logoUrl ? (
                <img src={settings.logoUrl} className="w-full h-full object-cover" />
              ) : (
                <i className="fas fa-om text-2xl md:text-3xl text-violet-600"></i>
              )}
            </div>
            <h1 className="text-2xl md:text-3xl font-black tracking-tighter mb-1 uppercase truncate">
              {view === 'login' ? settings.name : 'Recovery'}
            </h1>
            <p className="text-violet-100 text-[9px] md:text-[10px] font-bold tracking-[0.2em] uppercase opacity-80">
              {view === 'login' ? 'Secure Admin Access' : 'Administrative Support'}
            </p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-7 md:p-10 space-y-6">
          {error && (
            <div className="p-4 bg-rose-50/80 backdrop-blur-md text-rose-600 text-xs rounded-xl md:rounded-2xl border border-rose-100 flex items-center gap-3 font-bold animate-in">
              <i className="fas fa-circle-exclamation text-sm"></i>
              {error}
            </div>
          )}

          {isResetSent ? (
            <div className="space-y-6 text-center py-4 animate-in">
              <div className="w-16 h-16 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mx-auto mb-4 border border-emerald-100">
                <i className="fas fa-paper-plane text-xl"></i>
              </div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Recovery Link Sent</h3>
              <p className="text-sm text-slate-500 font-medium leading-relaxed">
                Check your inbox at <span className="font-bold text-violet-600">{email}</span>. Use the secure link to regain access to the portal.
              </p>
              <button 
                type="button"
                onClick={() => { setView('login'); setIsResetSent(false); }}
                className="w-full bg-slate-100 text-slate-600 py-4 rounded-2xl font-black text-sm hover:bg-slate-200 transition-all active:scale-[0.98]"
              >
                Back to Login
              </button>
            </div>
          ) : (
            <>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Identity</label>
                <div className="relative group">
                  <i className="fas fa-user absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-violet-400 transition-colors"></i>
                  <input 
                    type="email" 
                    required
                    className="w-full pl-11 pr-4 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-violet-100 transition-all font-bold text-slate-700 text-sm" 
                    placeholder="admin@yourfinance.com"
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                  />
                </div>
              </div>

              {view === 'login' && (
                <div className="space-y-2">
                  <div className="flex justify-between items-center px-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Access Code</label>
                    <button 
                      type="button"
                      onClick={() => { setView('reset'); setError(''); }}
                      className="text-[10px] font-black text-violet-600 hover:text-violet-700 transition-colors uppercase tracking-widest"
                    >
                      Forgot?
                    </button>
                  </div>
                  <div className="relative group">
                    <i className="fas fa-key absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-violet-400 transition-colors"></i>
                    <input 
                      type="password" 
                      required
                      className="w-full pl-11 pr-4 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-violet-100 transition-all font-bold text-slate-700 text-sm" 
                      placeholder="••••••••"
                      value={password}
                      onChange={e => setPassword(e.target.value)}
                    />
                  </div>
                </div>
              )}

              <button 
                type="submit" 
                disabled={isLoading}
                className={`w-full bg-violet-600 text-white py-4 md:py-5 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 active:scale-[0.98] flex items-center justify-center gap-3 ${isLoading ? 'opacity-70 cursor-not-allowed' : ''}`}
              >
                {isLoading ? (
                  <i className="fas fa-circle-notch fa-spin"></i>
                ) : (
                  view === 'login' ? 'Sign In' : 'Send Reset Link'
                )}
              </button>

              {view === 'reset' && (
                <button 
                  type="button"
                  onClick={() => { setView('login'); setError(''); }}
                  className="w-full text-slate-400 font-black text-[10px] uppercase tracking-[0.2em] py-2 hover:text-slate-600 transition-colors"
                >
                  <i className="fas fa-arrow-left mr-2"></i> Return to Sign In
                </button>
              )}
            </>
          )}

          <div className="text-center pt-4">
            <span className="text-slate-300 text-[9px] font-bold uppercase tracking-widest">
              Authorized Personnel Only
            </span>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Login;

payload.text:
To implement a secure, multi-tenant system where each owner (admin) has their own isolated data, we will integrate **Firebase Authentication** (Email/Password) and **Cloud Firestore**. 

### Technical Specification

1.  **Logical Data Isolation**: Instead of separate physical databases (which is costly and hard to manage), we use **User-ID (UID) paths** in Firestore. Every user's data will live under a root document named after their unique Firebase UID: `/users/{uid}/customers/...`.
2.  **Firebase Security Rules**: To guarantee "none of the data can go to another user," you must deploy the following rules in your Firebase Console:
    ```javascript
    service cloud.firestore {
      match /databases/{database}/documents {
        match /users/{userId}/{document=**} {
          allow read, write: if request.auth != null && request.auth.uid == userId;
        }
      }
    }
    ```
    *This ensures even if someone knows another user's ID, they cannot access the data via the API.*
3.  **Authentication**: We will replace the mock login with `signInWithEmailAndPassword`. Users are "assigned" credentials by you (the super admin) simply by creating their accounts in the **Firebase Console > Authentication > Users** tab.
4.  **Data Persistence**: We move away from `localStorage` to real-time Firestore synchronization. Data is fetched only after a successful login and tied strictly to the `currentUser.uid`.

### Required Code Updates

