import React, { useState, createContext, useContext, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Customers from './pages/Customers';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import Settings from './pages/Settings';
import Profile from './pages/Profile';
import Login from './pages/Login';
import { Language, translations } from './translations';
import { FinanceSettings, ProfileSettings } from './types';
import { auth, db } from './firebase';
import { onAuthStateChanged, signOut, User } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js';
import { doc, getDoc, setDoc, onSnapshot } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js';

interface AppContextType {
  user: User | null;
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: keyof typeof translations.en) => string;
  settings: FinanceSettings;
  updateSettings: (newSettings: FinanceSettings) => void;
  profile: ProfileSettings;
  updateProfile: (newProfile: ProfileSettings) => void;
  loading: boolean;
}

export const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [language, setLanguageState] = useState<Language>(() => (localStorage.getItem('appLang') as Language) || 'en');

  const [settings, setSettings] = useState<FinanceSettings>({
    name: 'LendFlow Admin',
    logoUrl: '',
    backgroundUrl: 'https://images.unsplash.com/photo-1561059488-916d69792237?q=80&w=2600',
    themeMode: 'light',
    primaryColor: '#7c3aed'
  });

  const [profile, setProfile] = useState<ProfileSettings>({
    displayName: 'New Owner',
    email: '',
    avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=admin',
    role: 'Owner'
  });

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        // Fetch User-specific Settings and Profile from Firestore
        const settingsRef = doc(db, 'users', currentUser.uid, 'config', 'settings');
        const profileRef = doc(db, 'users', currentUser.uid, 'config', 'profile');

        const [settingsSnap, profileSnap] = await Promise.all([
          getDoc(settingsRef),
          getDoc(profileRef)
        ]);

        if (settingsSnap.exists()) setSettings(settingsSnap.data() as FinanceSettings);
        if (profileSnap.exists()) setProfile(profileSnap.data() as ProfileSettings);
        else {
          // Initialize default profile if first time
          const initProfile = { ...profile, email: currentUser.email || '' };
          await setDoc(profileRef, initProfile);
          setProfile(initProfile);
        }
      }
      setAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    document.body.style.backgroundImage = `url('${settings.backgroundUrl}')`;
    document.body.className = `text-slate-900 selection:bg-violet-100 selection:text-violet-900 font-sans theme-${settings.themeMode}`;
    if (settings.themeMode === 'dark') {
      document.body.classList.add('text-slate-100');
      document.body.classList.remove('text-slate-900');
    } else {
      document.body.classList.add('text-slate-900');
      document.body.classList.remove('text-slate-100');
    }
  }, [settings.backgroundUrl, settings.themeMode]);

  const setLanguage = (lang: Language) => {
    setLanguageState(lang);
    localStorage.setItem('appLang', lang);
  };

  const updateSettings = async (newSettings: FinanceSettings) => {
    if (!user) return;
    setSettings(newSettings);
    await setDoc(doc(db, 'users', user.uid, 'config', 'settings'), newSettings);
  };

  const updateProfile = async (newProfile: ProfileSettings) => {
    if (!user) return;
    setProfile(newProfile);
    await setDoc(doc(db, 'users', user.uid, 'config', 'profile'), newProfile);
  };

  const t = (key: keyof typeof translations.en) => translations[language][key] || translations.en[key];

  const handleLogout = async () => {
    await signOut(auth);
  };

  if (authLoading) {
    return <div className="h-screen flex items-center justify-center bg-slate-50 text-violet-600 font-black animate-pulse">Initializing Security...</div>;
  }

  if (!user) {
    return (
      <AppContext.Provider value={{ user, language, setLanguage, t, settings, updateSettings, profile, updateProfile, loading: authLoading }}>
        <Login onLogin={() => {}} />
      </AppContext.Provider>
    );
  }

  return (
    <AppContext.Provider value={{ user, language, setLanguage, t, settings, updateSettings, profile, updateProfile, loading: authLoading }}>
      <HashRouter>
        <div className="flex h-screen bg-transparent overflow-hidden relative">
          <div className="fixed top-3 right-14 md:top-6 md:right-8 z-[60] flex items-center">
            <button
              onClick={() => setLanguage(language === 'en' ? 'ta' : 'en')}
              className={`${settings.themeMode === 'dark' ? 'bg-slate-800 border-slate-700 text-slate-100' : 'bg-white/90 border-slate-200 text-slate-600'} backdrop-blur-md border px-3 py-1.5 rounded-full shadow-lg hover:shadow-violet-200 transition-all flex items-center gap-2 group active:scale-95`}
            >
              <div className="w-5 h-5 rounded-full bg-violet-600 text-white flex items-center justify-center text-[8px] font-black">{language === 'en' ? 'EN' : 'TA'}</div>
              <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">{language === 'en' ? 'தமிழ்' : 'English'}</span>
            </button>
          </div>

          <Sidebar onLogout={handleLogout} isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />

          <main className="flex-1 overflow-y-auto pt-20 md:pt-12 px-4 pb-12 md:px-8">
            <div className="max-w-7xl mx-auto">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/customers" element={<Customers />} />
                <Route path="/customers/:id" element={<CustomerDetails />} />
                <Route path="/reports" element={<Reports />} />
                <Route path="/settings" element={<Settings />} />
                <Route path="/profile" element={<Profile />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </div>
          </main>
        </div>
      </HashRouter>
    </AppContext.Provider>
  );
};

export default App;

import React, { useState } from 'react';
import { useApp } from '../App';
import { auth } from '../firebase';
import { signInWithEmailAndPassword, sendPasswordResetEmail } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js';

interface LoginProps {
  onLogin: (success: boolean) => void;
}

const Login: React.FC<LoginProps> = () => {
  const { settings } = useApp();
  const [view, setView] = useState<'login' | 'reset'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isResetSent, setIsResetSent] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      if (view === 'login') {
        await signInWithEmailAndPassword(auth, email, password);
      } else {
        await sendPasswordResetEmail(auth, email);
        setIsResetSent(true);
      }
    } catch (err: any) {
      setError(err.message || 'Authentication failed. Please check your credentials.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-transparent flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white/90 backdrop-blur-xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in border border-white/50">
        <div className="bg-violet-600 p-8 md:p-12 text-center text-white relative">
          <div className="relative z-10">
            <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-inner overflow-hidden">
              {settings.logoUrl ? <img src={settings.logoUrl} className="w-full h-full object-cover" /> : <i className="fas fa-om text-3xl text-violet-600"></i>}
            </div>
            <h1 className="text-2xl md:text-3xl font-black tracking-tighter mb-1 uppercase">{view === 'login' ? settings.name : 'Recovery'}</h1>
            <p className="text-violet-100 text-[10px] font-bold tracking-[0.2em] uppercase opacity-80">Owner Access Only</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="p-7 md:p-10 space-y-6">
          {error && <div className="p-4 bg-rose-50 text-rose-600 text-xs rounded-xl border border-rose-100 flex items-center gap-3 font-bold"><i className="fas fa-circle-exclamation"></i>{error}</div>}

          {isResetSent ? (
            <div className="text-center space-y-6">
              <i className="fas fa-paper-plane text-emerald-500 text-4xl"></i>
              <h3 className="text-xl font-black">Link Sent</h3>
              <p className="text-sm text-slate-500">Check your inbox to reset your password.</p>
              <button type="button" onClick={() => { setView('login'); setIsResetSent(false); }} className="w-full bg-slate-100 py-4 rounded-2xl font-black">Return to Login</button>
            </div>
          ) : (
            <>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Owner Email</label>
                <input type="email" required className="w-full px-5 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-violet-100 font-bold text-sm" placeholder="owner@finance.com" value={email} onChange={e => setEmail(e.target.value)} />
              </div>

              {view === 'login' && (
                <div className="space-y-2">
                  <div className="flex justify-between items-center px-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Access Key</label>
                    <button type="button" onClick={() => setView('reset')} className="text-[10px] font-black text-violet-600 uppercase">Forgot?</button>
                  </div>
                  <input type="password" required className="w-full px-5 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-violet-100 font-bold text-sm" placeholder="••••••••" value={password} onChange={e => setPassword(e.target.value)} />
                </div>
              )}

              <button type="submit" disabled={isLoading} className="w-full bg-violet-600 text-white py-4 md:py-5 rounded-2xl font-black text-lg shadow-xl hover:bg-violet-700 active:scale-95 flex items-center justify-center gap-3 disabled:opacity-50">
                {isLoading ? <i className="fas fa-circle-notch fa-spin"></i> : (view === 'login' ? 'Sign In' : 'Send Reset Link')}
              </button>

              {view === 'reset' && (
                <button type="button" onClick={() => setView('login')} className="w-full text-slate-400 font-black text-[10px] uppercase tracking-[0.2em] py-2 hover:text-slate-600">Return to Sign In</button>
              )}
            </>
          )}
        </form>
      </div>
    </div>
  );
};

