import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { useApp } from '../App';
import { db } from '../firebase';
import { collection, onSnapshot } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js';

const Reports: React.FC = () => {
  const { t, settings, user } = useApp();
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth());
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  useEffect(() => {
    if (!user) return;

    const customersRef = collection(db, 'users', user.uid, 'customers');
    const paymentsRef = collection(db, 'users', user.uid, 'payments');

    const unsubC = onSnapshot(customersRef, (snap) => {
      setCustomers(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Customer)));
    });

    const unsubP = onSnapshot(paymentsRef, (snap) => {
      setPayments(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Payment)));
    });

    return () => { unsubC(); unsubP(); };
  }, [user]);

  const resetToCurrent = () => {
    setSelectedMonth(new Date().getMonth());
    setSelectedYear(new Date().getFullYear());
  };

  const hexToRgb = (hex: string): [number, number, number] => {
    const r = parseInt(hex.slice(1, 3), 16);
    const g = parseInt(hex.slice(3, 5), 16);
    const b = parseInt(hex.slice(5, 7), 16);
    return [r, g, b];
  };

  const generatePDF = async (m: number = selectedMonth, y: number = selectedYear) => {
    const doc = new jsPDF();
    const monthName = new Date(y, m).toLocaleString('default', { month: 'long' });
    const primaryRGB = hexToRgb(settings.primaryColor || '#7c3aed');

    let startY = 22;

    // Helper to load image as base64 for PDF
    const getBase64ImageFromURL = (url: string): Promise<string> => {
      return new Promise((resolve, reject) => {
        const img = new Image();
        img.setAttribute("crossOrigin", "anonymous");
        img.onload = () => {
          const canvas = document.createElement("canvas");
          canvas.width = img.width;
          canvas.height = img.height;
          const ctx = canvas.getContext("2d");
          ctx?.drawImage(img, 0, 0);
          const dataURL = canvas.toDataURL("image/png");
          resolve(dataURL);
        };
        img.onerror = error => reject(error);
        img.src = url;
      });
    };

    // Add Logo if exists
    if (settings.logoUrl) {
      try {
        const base64Logo = await getBase64ImageFromURL(settings.logoUrl);
        doc.addImage(base64Logo, 'PNG', 14, 10, 15, 15);
        startY = 32;
      } catch (e) {
        console.warn("Could not load logo for PDF. Check CORS or URL.", e);
        // Fallback to text only if image fails
      }
    }

    // Title and Header info
    doc.setFontSize(22);
    doc.setTextColor(primaryRGB[0], primaryRGB[1], primaryRGB[2]); 
    doc.text(settings.name, settings.logoUrl ? 32 : 14, startY);

    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139); // Slate-500
    doc.text(`${monthName} ${y} Portfolio Report | Generated: ${new Date().toLocaleDateString()}`, 14, startY + 8);

    const tableData = customers.map(c => {
      const payment = payments.find(p => p.customerId === c.id && p.month === m && p.year === y);
      const interestDue = (c.principal * c.interestRate) / 100;
      return [
        c.name,
        `₹${c.principal.toLocaleString()}`,
        `₹${interestDue.toLocaleString()}`,
        payment ? `₹${payment.amountPaid.toLocaleString()}` : '₹0',
        payment ? payment.status : (c.principal > 0 ? 'Pending' : 'N/A')
      ];
    });

    autoTable(doc, {
      startY: startY + 15,
      head: [['Customer Name', 'Capital Balance', 'Interest Due', 'Interest Paid', 'Status']],
      body: tableData,
      theme: 'grid',
      headStyles: { fillColor: primaryRGB }, 
      styles: { fontSize: 9, cellPadding: 4 },
      columnStyles: {
        1: { halign: 'right' },
        2: { halign: 'right' },
        3: { halign: 'right' }
      }
    });

    // Financial Summaries
    const totalCollected = payments
      .filter(p => p.month === m && p.year === y)
      .reduce((sum, p) => sum + p.amountPaid, 0);

    const totalDue = customers.reduce((sum, c) => sum + (c.principal * c.interestRate / 100), 0);
    const totalOutstanding = customers.reduce((sum, c) => sum + c.principal, 0);

    const finalY = (doc as any).lastAutoTable.finalY + 15;

    // Summary Box
    doc.setFillColor(primaryRGB[0], primaryRGB[1], primaryRGB[2]);
    doc.rect(14, finalY, 182, 35, 'F');
    // Draw white text on primary background
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text('Monthly Financial Summary', 20, finalY + 10);

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Interest Collected: ₹${totalCollected.toLocaleString()}`, 20, finalY + 20);
    doc.text(`Pending Interest: ₹${(totalDue - totalCollected).toLocaleString()}`, 20, finalY + 27);

    // Capital info in a different alignment
    doc.setFont('helvetica', 'bold');
    doc.text(`Total Portfolio Capital: ₹${totalOutstanding.toLocaleString()}`, 190, finalY + 20, { align: 'right' });

    doc.save(`${settings.name.replace(/\s/g, '_')}_${monthName}_${y}.pdf`);
  };

  const handleQuickExport = () => {
    const now = new Date();
    generatePDF(now.getMonth(), now.getFullYear());
  };

  const isDark = settings.themeMode === 'dark';

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-end gap-2 px-1">
        <div>
          <h2 className={`text-2xl md:text-3xl font-black tracking-tight uppercase ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{t('exports')}</h2>
          <p className={`${isDark ? 'text-slate-400' : 'text-slate-500'} font-medium text-xs md:text-base`}>Portfolio financial reports.</p>
        </div>
        <button 
          onClick={resetToCurrent}
          className={`text-[10px] font-black hover:bg-violet-50 px-3 py-1.5 rounded-xl transition-all uppercase tracking-widest ${isDark ? 'text-violet-400 hover:bg-slate-800' : 'text-violet-600'}`}
        >
          {t('clear')}
        </button>
      </header>

      <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100'} p-6 md:p-12 rounded-[2rem] md:rounded-[2.5rem] border shadow-xl max-w-xl mx-auto text-center relative overflow-hidden`}>
        <div className="hidden md:block absolute top-0 right-0 w-32 h-32 bg-violet-500/5 rounded-full -mr-16 -mt-16 opacity-50"></div>

        <div className="relative z-10">
          <div className={`w-16 h-16 md:w-20 md:h-20 ${isDark ? 'bg-violet-900/30' : 'bg-violet-100'} text-violet-600 rounded-2xl md:rounded-3xl flex items-center justify-center text-2xl md:text-3xl mx-auto mb-4 md:mb-6 shadow-lg overflow-hidden`}>
            {settings.logoUrl ? (
               <img src={settings.logoUrl} className="w-full h-full object-contain" />
            ) : (
               <i className="fas fa-file-invoice"></i>
            )}
          </div>
          <h3 className={`text-xl md:text-2xl font-black mb-1.5 uppercase tracking-tight ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{t('statementCenter')}</h3>
          <p className={`text-[11px] md:text-sm mb-8 max-w-xs mx-auto font-medium ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>Download the complete portfolio status for any billing period.</p>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 md:gap-6 mb-8 md:mb-10">
            <div className="text-left space-y-1.5">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('month')}</label>
              <select 
                className={`w-full p-3 md:p-4 border rounded-xl md:rounded-2xl outline-none focus:ring-2 focus:ring-violet-200 font-bold text-sm ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100' : 'bg-slate-50 border-slate-100 text-slate-700'}`}
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(parseInt(e.target.value))}
              >
                {Array.from({length: 12}).map((_, i) => (
                  <option key={i} value={i}>{new Date(0, i).toLocaleString('default', {month: 'long'})}</option>
                ))}
              </select>
            </div>
            <div className="text-left space-y-1.5">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('year')}</label>
              <select 
                className={`w-full p-3 md:p-4 border rounded-xl md:rounded-2xl outline-none focus:ring-2 focus:ring-violet-200 font-bold text-sm ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100' : 'bg-slate-50 border-slate-100 text-slate-700'}`}
                value={selectedYear}
                onChange={(e) => setSelectedYear(parseInt(e.target.value))}
              >
                {[2024, 2025, 2026].map(y => (
                  <option key={y} value={y}>{y}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="flex flex-col gap-3 md:gap-4">
            <button 
              onClick={() => generatePDF()}
              className="w-full bg-violet-600 text-white py-4 md:py-5 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 flex items-center justify-center gap-3 active:scale-[0.98]"
            >
              <i className="fas fa-file-export"></i>
              {t('exportPdf')}
            </button>

            <button 
              onClick={handleQuickExport}
              className={`w-full py-3 md:py-4 rounded-2xl font-black text-xs md:text-base border-2 transition-all flex items-center justify-center gap-2 ${isDark ? 'bg-slate-800 text-violet-400 border-slate-700 hover:bg-slate-700' : 'bg-white text-violet-600 border-violet-100 hover:bg-violet-50'}`}
            >
              <i className="fas fa-bolt text-[10px] md:text-xs"></i>
              {t('quickExport')}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reports;

import React, { useState, useEffect } from 'react';
