  const [maxPrincipal, setMaxPrincipal] = useState<string>('');

  const [newCustomer, setNewCustomer] = useState<Partial<Customer>>({
    name: '', 
    phone: '', 
    address: '', 
    principal: 0, 
    interestRate: 5, 
    dueDate: new Date().getDate(),
    startDate: Date.now()
  });

  useEffect(() => {
    if (!user) return;
    const q = collection(db, 'users', user.uid, 'customers');
    const unsub = onSnapshot(q, (snap) => {
      setCustomers(snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Customer)));
    });
    return () => unsub();
  }, [user]);

  const handleAddCustomer = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

