                type="text" 
                placeholder={t('searchPlaceholder')}
                className={`w-full pl-11 pr-4 py-3 rounded-xl border outline-none text-sm font-medium transition-all shadow-inner ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="flex gap-2 w-full md:w-auto">
              <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex-1 md:flex-none px-5 py-3 rounded-xl border font-bold text-[10px] md:text-xs uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${
                  showFilters 
                    ? (isDark ? 'bg-violet-900/40 border-violet-800 text-violet-400' : 'bg-violet-50 border-violet-200 text-violet-600') 
                    : (isDark ? 'bg-slate-800 border-slate-700 text-slate-400' : 'bg-white border-slate-200 text-slate-500')
                }`}
              >
                <i className="fas fa-sliders text-[10px]"></i>
                {t('filters')}
              </button>
              {(searchTerm || minPrincipal || maxPrincipal) && (
                <button onClick={clearFilters} className={`px-4 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-colors shrink-0 ${isDark ? 'text-slate-500 hover:text-rose-400' : 'text-slate-400 hover:text-rose-500'}`}>
                  {t('clear')}
                </button>
              )}
            </div>
          </div>

          {showFilters && (
            <div className={`mt-4 pt-4 border-t ${isDark ? 'border-slate-800' : 'border-slate-100'} grid grid-cols-1 md:grid-cols-2 gap-4 animate-in`}>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Min Principal (₹)</label>
                <input 
                  type="number" 
                  className={`w-full px-4 py-2.5 rounded-xl border outline-none text-xs font-bold ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                  value={minPrincipal}
                  onChange={(e) => setMinPrincipal(e.target.value)}
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Max Principal (₹)</label>
                <input 
                  type="number" 
                  className={`w-full px-4 py-2.5 rounded-xl border outline-none text-xs font-bold ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                  value={maxPrincipal}
                  onChange={(e) => setMaxPrincipal(e.target.value)}
                />
              </div>
            </div>
          )}
        </div>

        <div className="overflow-x-auto scrollbar-hide">
          <table className="w-full text-left min-w-[500px]">
            <thead className={`text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-[0.2em] border-b ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
              <tr>
                <th className="px-4 md:px-8 py-4">{t('borrower')}</th>
                <th className="px-4 md:px-8 py-4">{t('capital')}</th>
                <th className="px-4 md:px-8 py-4">{t('due')}</th>
                <th className="px-4 md:px-8 py-4 text-right">{t('action')}</th>
              </tr>
            </thead>
            <tbody className={`divide-y text-sm ${isDark ? 'divide-slate-800' : 'divide-slate-50'}`}>
              {filteredCustomers.map(c => (
                <tr key={c.id} className={`transition-colors group ${isDark ? 'hover:bg-slate-800/40' : 'hover:bg-violet-50/30'}`}>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <div className="flex items-center gap-2 md:gap-3">
                      <div className={`w-8 h-8 md:w-10 md:h-10 rounded-xl flex items-center justify-center font-black text-xs shrink-0 ${isDark ? 'bg-violet-900/40 text-violet-400' : 'bg-violet-100 text-violet-600'}`}>
                        {c.name.charAt(0)}
                      </div>
                      <div className="min-w-0">
                        <p className={`font-bold text-xs md:text-sm truncate max-w-[120px] md:max-w-none ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{c.name}</p>
                        <p className={`text-[9px] md:text-[10px] font-medium ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>{c.phone}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <p className={`font-black text-xs md:text-sm ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>₹{c.principal.toLocaleString()}</p>
                    <p className={`text-[8px] md:text-[9px] font-bold uppercase tracking-widest ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>{c.interestRate}% Int.</p>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <span className={`border px-2 py-1 md:px-2.5 md:py-1.5 rounded-lg text-[8px] md:text-[10px] font-black uppercase tracking-tight whitespace-nowrap ${isDark ? 'bg-slate-800 text-violet-400 border-violet-900/30' : 'bg-white text-violet-600 border-violet-100'}`}>
                      {t('due')} {c.dueDate}
                    </span>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6 text-right">
                    <Link to={`/customers/${c.id}`} className={`inline-flex w-8 h-8 md:w-10 md:h-10 rounded-xl items-center justify-center transition-all shadow-sm border ${isDark ? 'bg-slate-800 border-slate-700 text-violet-400 hover:bg-violet-900/50' : 'bg-white border-slate-100 text-violet-600 hover:bg-violet-600 hover:text-white'}`}>
                      <i className="fas fa-eye text-xs md:text-sm"></i>
                    </Link>
                  </td>
                </tr>
              ))}
              {filteredCustomers.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-8 py-16 text-center text-slate-300 font-medium">No results found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-3 md:p-4 z-50 animate-in overflow-y-auto">
          <div className={`${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-white'} rounded-[1.5rem] md:rounded-[2rem] w-full max-w-lg shadow-2xl overflow-hidden border flex flex-col max-h-[95vh]`}>
            <div className="px-6 py-4 md:px-8 md:py-6 bg-violet-600 flex justify-between items-center text-white shrink-0">
              <h3 className="text-lg md:text-xl font-black uppercase tracking-tighter">{t('enrollment')}</h3>
              <button onClick={() => setIsModalOpen(false)} className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/20">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleAddCustomer} className="p-5 md:p-8 space-y-4 md:space-y-6 overflow-y-auto">
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('fullName')}</label>
                <input required type="text" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.name} onChange={e => setNewCustomer({...newCustomer, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('contactNo')}</label>
                  <input required type="tel" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.phone} onChange={e => setNewCustomer({...newCustomer, phone: e.target.value})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('startDate')}</label>
                  <input required type="date" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} onChange={e => setNewCustomer({...newCustomer, startDate: new Date(e.target.value).getTime()})} />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('interestRate')}</label>
                  <input required type="number" step="0.1" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.interestRate} onChange={e => setNewCustomer({...newCustomer, interestRate: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('autoDueDay')}</label>
                  <input required type="number" min="1" max="31" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.dueDate} onChange={e => setNewCustomer({...newCustomer, dueDate: parseInt(e.target.value)})} />
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('openingCapital')}</label>
                <input required type="number" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-violet-400 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-violet-600'}`} value={newCustomer.principal} onChange={e => setNewCustomer({...newCustomer, principal: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('address')}</label>
                <textarea rows={2} className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.address} onChange={e => setNewCustomer({...newCustomer, address: e.target.value})}></textarea>
              </div>
              <button type="submit" className="w-full bg-violet-600 text-white py-4 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 mt-2">
                {t('enrollBtn')}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Customers;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';
import { useApp } from '../App';
import { db } from '../firebase';
import { doc, onSnapshot, collection, addDoc, updateDoc } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js';
import { onSnapshot as onSnapshotDoc } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js';

const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { t, settings, user } = useApp();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  const [principalChange, setPrincipalChange] = useState({ 
    amount: 0, 
    reason: '', 
    type: 'increase',
    date: new Date().toISOString().split('T')[0]
  });

  const [paymentInput, setPaymentInput] = useState({ 
    amount: 0, 
    month: new Date().getMonth(), 
    year: new Date().getFullYear(),
    collectionDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    if (!user || !id) return;

    const customerRef = doc(db, 'users', user.uid, 'customers', id);
    const paymentsRef = collection(db, 'users', user.uid, 'payments');
    const logsRef = collection(db, 'users', user.uid, 'principalLogs');

    const unsubC = onSnapshotDoc(customerRef, (snap) => {
      if (snap.exists()) setCustomer({ id: snap.id, ...snap.data() } as Customer);
      else navigate('/customers');
    });

    const unsubP = onSnapshotDoc(paymentsRef, (snap) => {
      setPayments(snap.docs
        .map(doc => ({ id: doc.id, ...doc.data() } as Payment))
        .filter(p => p.customerId === id));
    });

    const unsubL = onSnapshotDoc(logsRef, (snap) => {
      setPrincipalLogs(snap.docs
        .map(doc => ({ id: doc.id, ...doc.data() } as PrincipalLog))
        .filter(l => l.customerId === id));
    });

    return () => { unsubC(); unsubP(); unsubL(); };
  }, [user, id, navigate]);

  const handleUpdatePrincipal = async () => {
    if (!customer || !user) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;

    const timestamp = new Date(principalChange.date).getTime();

    const logData = { 
      customerId: customer.id, 
      amountChange: diff, 
      newPrincipal: newP, 
      reason: principalChange.reason || 'Manual Adjustment', 
      timestamp: timestamp 
    };

    try {
      await updateDoc(doc(db, 'users', user.uid, 'customers', customer.id), { principal: newP });
      await addDoc(collection(db, 'users', user.uid, 'principalLogs'), logData);
      setShowPrincipalModal(false);
      setPrincipalChange({ ...principalChange, amount: 0, reason: '' });
    } catch (e) {
      console.error(e);
    }
  };

  const handleAddPayment = async () => {
    if (!customer || !user) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const timestamp = new Date(paymentInput.collectionDate).getTime();

    const paymentData = { 
      customerId: customer.id, 
      month: paymentInput.month, 
      year: paymentInput.year, 
      amountPaid: paymentInput.amount, 
      totalDue: totalDue, 
      status: status, 
      timestamp: timestamp 
    };

    try {
      await addDoc(collection(db, 'users', user.uid, 'payments'), paymentData);
      setShowPaymentModal(false);
      setPaymentInput({ ...paymentInput, amount: 0 });
    } catch (e) {
      console.error(e);
    }
  };

  const isDark = settings.themeMode === 'dark';

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4 px-1">
        <div className="space-y-1 md:space-y-2 w-full">
          <button 
            onClick={() => navigate('/customers')} 
            className={`text-[10px] font-black hover:bg-violet-50 px-3 py-1.5 rounded-xl uppercase tracking-widest transition-all mb-2 flex items-center w-fit ${isDark ? 'text-violet-400 hover:bg-slate-800' : 'text-violet-600'}`}
          >
            <i className="fas fa-arrow-left mr-2"></i> {t('ledger')}
          </button>
          <h2 className={`text-3xl md:text-4xl font-black tracking-tight truncate ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{customer.name}</h2>
          <p className={`${isDark ? 'text-slate-400' : 'text-slate-500'} text-sm font-medium flex items-center gap-2`}>
            <i className="fas fa-location-dot opacity-30"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a 
            href={`tel:${customer.phone}`} 
            className={`w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center transition-all shadow-lg shrink-0 ${isDark ? 'bg-slate-800 text-emerald-400 hover:bg-slate-700' : 'bg-emerald-100 text-emerald-700 hover:bg-emerald-200 shadow-emerald-50'}`}
          >
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button 
            onClick={() => setShowPrincipalModal(true)} 
            className="flex-1 md:flex-none bg-violet-600 text-white px-6 py-3.5 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-sm md:text-base active:scale-95"
          >
            <i className="fas fa-coins"></i> {t('adjustment')}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-6">
        <DetailCard isDark={isDark} label={t('capital')} value={`₹${customer.principal.toLocaleString()}`} />
        <DetailCard isDark={isDark} label={`Interest (${customer.interestRate}%)`} value={`₹${((customer.principal * customer.interestRate)/100).toLocaleString()}`} primary />
        <DetailCard isDark={isDark} label={t('due')} value={`Day ${customer.dueDate}`} badge />
        <DetailCard isDark={isDark} label={t('startDate')} value={customer.startDate ? new Date(customer.startDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' }) : 'N/A'} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100'} rounded-[1.5rem] md:rounded-[2rem] border shadow-sm overflow-hidden animate-in delay-2`}>
          <div className={`px-6 py-5 md:px-8 md:py-6 border-b flex justify-between items-center ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
            <h3 className={`font-black uppercase tracking-tighter text-sm md:text-base ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{t('interestLedger')}</h3>
            <button 
              onClick={() => setShowPaymentModal(true)} 
              className="bg-violet-600 text-white w-9 h-9 md:w-10 md:h-10 rounded-xl flex items-center justify-center shadow-lg shadow-violet-100 transition-all hover:scale-105 active:scale-95"
            >
              <i className="fas fa-plus text-xs"></i>
            </button>
          </div>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full text-left min-w-[450px]">
              <thead className={`text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-widest border-b ${isDark ? 'bg-slate-800/30 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
                <tr>
                  <th className="px-6 md:px-8 py-4">{t('month')}</th>
                  <th className="px-6 md:px-8 py-4">{t('amount')}</th>
                  <th className="px-6 md:px-8 py-4">Status</th>
                </tr>
              </thead>
              <tbody className={`divide-y ${isDark ? 'divide-slate-800' : 'divide-slate-50'}`}>
                {payments.sort((a,b) => b.timestamp - a.timestamp).map(p => {
                   const dueAmount = p.totalDue - p.amountPaid;
                   return (
                    <tr key={p.id} className={`text-xs md:text-sm transition-colors ${isDark ? 'hover:bg-slate-800/40' : 'hover:bg-slate-50/50'}`}>
                      <td className={`px-6 md:px-8 py-4 font-bold ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
                        {new Date(0, p.month).toLocaleString('default', { month: 'short' })} {p.year}
                      </td>
                      <td className="px-6 md:px-8 py-4">
                        <p className={`font-black ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>₹{p.amountPaid.toLocaleString()}</p>
                        <p className="text-[9px] text-slate-500 font-medium">Rec'd: {new Date(p.timestamp).toLocaleDateString()}</p>
                      </td>
                      <td className="px-6 md:px-8 py-4">
                        <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[9px] font-black uppercase tracking-tight ${
                          p.status === 'Paid' ? (isDark ? 'bg-emerald-900/30 text-emerald-400' : 'bg-emerald-50 text-emerald-600') : 
                          p.status === 'Partial' ? (isDark ? 'bg-amber-900/30 text-amber-400' : 'bg-amber-50 text-amber-600') : (isDark ? 'bg-rose-900/30 text-rose-400' : 'bg-rose-50 text-rose-600')
                        }`}>
                          {p.status}
                          {p.status !== 'Paid' && dueAmount > 0 && <span className="ml-1.5 opacity-80">(Due: ₹{dueAmount.toLocaleString()})</span>}
                        </span>
                      </td>
                    </tr>
                   );
                })}
                {payments.length === 0 && (
                  <tr>
                    <td colSpan={3} className="px-8 py-16 text-center text-slate-500 font-medium italic">No payments recorded.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100'} rounded-[1.5rem] md:rounded-[2rem] border shadow-sm overflow-hidden animate-in delay-3 flex flex-col min-h-[400px]`}>
           <div className={`px-6 py-5 md:px-8 md:py-6 border-b ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
            <h3 className={`font-black uppercase tracking-tighter text-sm md:text-base ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{t('audit')}</h3>
          </div>
          <div className="flex-1 overflow-y-auto scrollbar-hide">
            <div className="p-6 md:p-8 space-y-6">
              {principalLogs.sort((a,b) => b.timestamp - a.timestamp).map(log => (
                <div key={log.id} className={`relative pl-7 border-l-2 py-1 ${isDark ? 'border-slate-800' : 'border-slate-100'}`}>
                  <div className={`absolute left-[-9px] top-2.5 w-4 h-4 rounded-full border-4 shadow-sm ${isDark ? 'border-slate-900' : 'border-white'} ${log.amountChange > 0 ? 'bg-violet-600' : 'bg-rose-500'}`}></div>
                  <div className="flex justify-between items-start mb-0.5">
                    <p className={`text-xs md:text-sm font-black uppercase tracking-tight truncate mr-2 ${isDark ? 'text-slate-200' : 'text-slate-800'}`}>{log.reason}</p>
                    <p className="text-[9px] font-bold text-slate-500 whitespace-nowrap">{new Date(log.timestamp).toLocaleDateString()}</p>
                  </div>
                  <p className={`text-sm md:text-base font-black ${log.amountChange > 0 ? 'text-violet-400' : 'text-rose-400'}`}>
                    {log.amountChange > 0 ? '+' : ''}₹{Math.abs(log.amountChange).toLocaleString()}
                  </p>
                  <p className="text-[10px] text-slate-500 font-medium uppercase tracking-widest mt-0.5">New Balance: ₹{log.newPrincipal.toLocaleString()}</p>
                </div>
              ))}
              {principalLogs.length === 0 && (
                <div className="text-center py-20">
                  <i className={`fas fa-history text-5xl mb-4 ${isDark ? 'text-slate-800' : 'text-slate-100'}`}></i>
                  <p className="text-slate-500 italic text-sm">No adjustments logged yet.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {showPrincipalModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in">
          <div className={`${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-white'} rounded-[2rem] w-full max-w-sm shadow-2xl overflow-hidden border`}>
            <div className="p-6 bg-violet-600 text-white flex justify-between items-center">
              <h3 className="text-lg font-black uppercase tracking-tighter">{t('adjustment')}</h3>
              <button onClick={() => setShowPrincipalModal(false)} className="w-9 h-9 flex items-center justify-center rounded-xl bg-white/20">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 md:p-8 space-y-6">
              <div className={`flex p-1 rounded-2xl ${isDark ? 'bg-slate-800' : 'bg-slate-100'}`}>
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'increase'})}
                  className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${principalChange.type === 'increase' ? 'bg-violet-600 text-white shadow-sm' : 'text-slate-500'}`}
                >
                  {t('lend')}
                </button>
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'decrease'})}
                  className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${principalChange.type === 'decrease' ? 'bg-rose-600 text-white shadow-sm' : 'text-slate-500'}`}
                >
                  {t('recover')}
                </button>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">{t('amount')}</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 font-black text-slate-400">₹</span>
                  <input 
                    type="number" 
                    className={`w-full pl-9 pr-4 py-4 rounded-2xl font-black text-xl outline-none focus:ring-4 transition-all ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800 focus:ring-violet-50'}`}
                    value={principalChange.amount || ''} 
                    onChange={e => setPrincipalChange({...principalChange, amount: parseFloat(e.target.value) || 0})}
                  />
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">{t('notes')}</label>
                <input 
                  type="text" 
                  placeholder="Reason..."
                  className={`w-full px-4 py-4 rounded-2xl font-bold text-sm outline-none focus:ring-4 transition-all ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800 focus:ring-violet-50'}`}
                  value={principalChange.reason} 
                  onChange={e => setPrincipalChange({...principalChange, reason: e.target.value})}
                />
              </div>
              <button onClick={handleUpdatePrincipal} className="w-full bg-violet-600 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-violet-200 hover:bg-violet-700 active:scale-[0.98]">
                {t('submit')}
              </button>
            </div>
          </div>
        </div>
      )}

      {showPaymentModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in">
          <div className={`${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-white'} rounded-[2rem] w-full max-w-sm shadow-2xl overflow-hidden border`}>
            <div className="p-6 bg-violet-600 text-white flex justify-between items-center">
              <h3 className="text-lg font-black uppercase tracking-tighter">{t('collect')}</h3>
              <button onClick={() => setShowPaymentModal(false)} className="w-9 h-9 flex items-center justify-center rounded-xl bg-white/20">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 md:p-8 space-y-5">
              <div className={`p-5 rounded-[1.5rem] border ${isDark ? 'bg-violet-900/20 border-violet-900/40' : 'bg-violet-50 border-violet-100'}`}>
                <p className="text-[10px] font-black text-violet-400 uppercase tracking-[0.2em] mb-1">{t('expectedInterest')}</p>
                <p className="text-2xl font-black text-violet-500">₹{((customer.principal * customer.interestRate)/100).toLocaleString()}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">{t('month')}</label>
                  <select 
                    className={`w-full px-3 py-3.5 border rounded-2xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100' : 'bg-slate-50 border-slate-100 text-slate-700'}`}
                    value={paymentInput.month}
                    onChange={e => setPaymentInput({...paymentInput, month: parseInt(e.target.value)})}
                  >
                    {Array.from({length: 12}).map((_, i) => (
                      <option key={i} value={i}>{new Date(0, i).toLocaleString('default', { month: 'short' })}</option>
                    ))}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">{t('year')}</label>
                  <select 
                    className={`w-full px-3 py-3.5 border rounded-2xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100' : 'bg-slate-50 border-slate-100 text-slate-700'}`}
                    value={paymentInput.year}
                    onChange={e => setPaymentInput({...paymentInput, year: parseInt(e.target.value)})}
                  >
                    {[2024, 2025, 2026].map(y => (
                      <option key={y} value={y}>{y}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">{t('amount')}</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 font-black text-emerald-500">₹</span>
                  <input 
                    type="number" 
                    className={`w-full pl-9 pr-4 py-4 rounded-2xl font-black text-xl outline-none focus:ring-4 transition-all ${isDark ? 'bg-slate-800 border-slate-700 text-emerald-400 focus:ring-emerald-900/30' : 'bg-slate-50 border-slate-100 text-emerald-600 focus:ring-emerald-50'}`}
                    value={paymentInput.amount || ''} 
                    onChange={e => setPaymentInput({...paymentInput, amount: parseFloat(e.target.value) || 0})}
                  />
                </div>
              </div>
              <button onClick={handleAddPayment} className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-emerald-50 hover:bg-emerald-700 active:scale-[0.98]">
                {t('collect')}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const DetailCard: React.FC<{ label: string; value: string; primary?: boolean; badge?: boolean; isDark: boolean }> = ({ label, value, primary, badge, isDark }) => (
  <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100'} p-5 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border shadow-sm animate-in`}>
    <p className="text-[9px] md:text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-2">{label}</p>
    {badge ? (
      <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-xl font-black text-[10px] md:text-sm uppercase tracking-widest ${isDark ? 'bg-violet-900/30 text-violet-400' : 'bg-violet-50 text-violet-600'}`}>
        {value}
      </div>
    ) : (
      <p className={`text-xl md:text-3xl font-black leading-none truncate ${primary ? (isDark ? 'text-violet-400' : 'text-violet-600') : (isDark ? 'text-slate-100' : 'text-slate-900')}`}>{value}</p>
    )}
  </div>
);

export default CustomerDetails;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';
import { useApp } from '../App';
import { db } from '../firebase';
import { doc, collection, addDoc, updateDoc, onSnapshot } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js';

const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { t, settings, user } = useApp();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  const [principalChange, setPrincipalChange] = useState({ 
    amount: 0, 
    reason: '', 
    type: 'increase',
    date: new Date().toISOString().split('T')[0]
  });

  const [paymentInput, setPaymentInput] = useState({ 
    amount: 0, 
    month: new Date().getMonth(), 
    year: new Date().getFullYear(),
    collectionDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    if (!user || !id) return;

    const customerRef = doc(db, 'users', user.uid, 'customers', id);
    const paymentsRef = collection(db, 'users', user.uid, 'payments');
    const logsRef = collection(db, 'users', user.uid, 'principalLogs');

    const unsubC = onSnapshot(customerRef, (snap) => {
      if (snap.exists()) {
        setCustomer({ id: snap.id, ...snap.data() } as Customer);
      } else {
        navigate('/customers');
      }
    });

    const unsubP = onSnapshot(paymentsRef, (snap) => {
      setPayments(snap.docs
        .map(doc => ({ id: doc.id, ...doc.data() } as Payment))
        .filter(p => p.customerId === id));
    });

    const unsubL = onSnapshot(logsRef, (snap) => {
      setPrincipalLogs(snap.docs
        .map(doc => ({ id: doc.id, ...doc.data() } as PrincipalLog))
        .filter(l => l.customerId === id));
    });

    return () => { unsubC(); unsubP(); unsubL(); };
  }, [user, id, navigate]);

  const handleUpdatePrincipal = async () => {
    if (!customer || !user) return;
    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;

    const timestamp = new Date(principalChange.date).getTime();

    const logData = { 
      customerId: customer.id, 
      amountChange: diff, 
      newPrincipal: newP, 
      reason: principalChange.reason || 'Manual Adjustment', 
      timestamp: timestamp 
    };

    try {
      await updateDoc(doc(db, 'users', user.uid, 'customers', customer.id), { principal: newP });
      await addDoc(collection(db, 'users', user.uid, 'principalLogs'), logData);
      setShowPrincipalModal(false);
      setPrincipalChange({ ...principalChange, amount: 0, reason: '' });
    } catch (e) {
      console.error(e);
    }
  };

  const handleAddPayment = async () => {
    if (!customer || !user) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const timestamp = new Date(paymentInput.collectionDate).getTime();

    const paymentData = { 
      customerId: customer.id, 
      month: paymentInput.month, 
      year: paymentInput.year, 
      amountPaid: paymentInput.amount, 
      totalDue: totalDue, 
      status: status, 
      timestamp: timestamp 
    };

    try {
      await addDoc(collection(db, 'users', user.uid, 'payments'), paymentData);
      setShowPaymentModal(false);
      setPaymentInput({ ...paymentInput, amount: 0 });
    } catch (e) {
      console.error(e);
    }
  };

  const isDark = settings.themeMode === 'dark';

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4 px-1">
        <div className="space-y-1 md:space-y-2 w-full">
          <button 
            onClick={() => navigate('/customers')} 
            className={`text-[10px] font-black hover:bg-violet-50 px-3 py-1.5 rounded-xl uppercase tracking-widest transition-all mb-2 flex items-center w-fit ${isDark ? 'text-violet-400 hover:bg-slate-800' : 'text-violet-600'}`}
          >
            <i className="fas fa-arrow-left mr-2"></i> {t('ledger')}
          </button>
          <h2 className={`text-3xl md:text-4xl font-black tracking-tight truncate ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{customer.name}</h2>
          <p className={`${isDark ? 'text-slate-400' : 'text-slate-500'} text-sm font-medium flex items-center gap-2`}>
            <i className="fas fa-location-dot opacity-30"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a 
            href={`tel:${customer.phone}`} 
            className={`w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center transition-all shadow-lg shrink-0 ${isDark ? 'bg-slate-800 text-emerald-400 hover:bg-slate-700' : 'bg-emerald-100 text-emerald-700 hover:bg-emerald-200 shadow-emerald-50'}`}
          >
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button 
            onClick={() => setShowPrincipalModal(true)} 
            className="flex-1 md:flex-none bg-violet-600 text-white px-6 py-3.5 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-sm md:text-base active:scale-95"
          >
            <i className="fas fa-coins"></i> {t('adjustment')}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-6">
        <DetailCard isDark={isDark} label={t('capital')} value={`₹${customer.principal.toLocaleString()}`} />
        <DetailCard isDark={isDark} label={`Interest (${customer.interestRate}%)`} value={`₹${((customer.principal * customer.interestRate)/100).toLocaleString()}`} primary />
        <DetailCard isDark={isDark} label={t('due')} value={`Day ${customer.dueDate}`} badge />
        <DetailCard isDark={isDark} label={t('startDate')} value={customer.startDate ? new Date(customer.startDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' }) : 'N/A'} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100'} rounded-[1.5rem] md:rounded-[2rem] border shadow-sm overflow-hidden animate-in delay-2`}>
          <div className={`px-6 py-5 md:px-8 md:py-6 border-b flex justify-between items-center ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
            <h3 className={`font-black uppercase tracking-tighter text-sm md:text-base ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{t('interestLedger')}</h3>
            <button 
              onClick={() => setShowPaymentModal(true)} 
              className="bg-violet-600 text-white w-9 h-9 md:w-10 md:h-10 rounded-xl flex items-center justify-center shadow-lg shadow-violet-100 transition-all hover:scale-105 active:scale-95"
            >
              <i className="fas fa-plus text-xs"></i>
            </button>
          </div>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full text-left min-w-[450px]">
              <thead className={`text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-widest border-b ${isDark ? 'bg-slate-800/30 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
                <tr>
                  <th className="px-6 md:px-8 py-4">{t('month')}</th>
                  <th className="px-6 md:px-8 py-4">{t('amount')}</th>
                  <th className="px-6 md:px-8 py-4">Status</th>
                </tr>
              </thead>
              <tbody className={`divide-y ${isDark ? 'divide-slate-800' : 'divide-slate-50'}`}>
                {payments.sort((a,b) => b.timestamp - a.timestamp).map(p => {
                   const dueAmount = p.totalDue - p.amountPaid;
                   return (
                    <tr key={p.id} className={`text-xs md:text-sm transition-colors ${isDark ? 'hover:bg-slate-800/40' : 'hover:bg-slate-50/50'}`}>
                      <td className={`px-6 md:px-8 py-4 font-bold ${isDark ? 'text-slate-300' : 'text-slate-600'}`}>
                        {new Date(0, p.month).toLocaleString('default', { month: 'short' })} {p.year}
                      </td>
                      <td className="px-6 md:px-8 py-4">
                        <p className={`font-black ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>₹{p.amountPaid.toLocaleString()}</p>
                        <p className="text-[9px] text-slate-500 font-medium">Rec'd: {new Date(p.timestamp).toLocaleDateString()}</p>
                      </td>
                      <td className="px-6 md:px-8 py-4">
                        <span className={`inline-flex items-center px-2.5 py-1 rounded-lg text-[9px] font-black uppercase tracking-tight ${
                          p.status === 'Paid' ? (isDark ? 'bg-emerald-900/30 text-emerald-400' : 'bg-emerald-50 text-emerald-600') : 
                          p.status === 'Partial' ? (isDark ? 'bg-amber-900/30 text-amber-400' : 'bg-amber-50 text-amber-600') : (isDark ? 'bg-rose-900/30 text-rose-400' : 'bg-rose-50 text-rose-600')
                        }`}>
                          {p.status}
                          {p.status !== 'Paid' && dueAmount > 0 && <span className="ml-1.5 opacity-80">(Due: ₹{dueAmount.toLocaleString()})</span>}
                        </span>
                      </td>
                    </tr>
                   );
                })}
                {payments.length === 0 && (
                  <tr>
                    <td colSpan={3} className="px-8 py-16 text-center text-slate-500 font-medium italic">No payments recorded.</td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100'} rounded-[1.5rem] md:rounded-[2rem] border shadow-sm overflow-hidden animate-in delay-3 flex flex-col min-h-[400px]`}>
           <div className={`px-6 py-5 md:px-8 md:py-6 border-b ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
            <h3 className={`font-black uppercase tracking-tighter text-sm md:text-base ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{t('audit')}</h3>
          </div>
          <div className="flex-1 overflow-y-auto scrollbar-hide">
            <div className="p-6 md:p-8 space-y-6">
              {principalLogs.sort((a,b) => b.timestamp - a.timestamp).map(log => (
                <div key={log.id} className={`relative pl-7 border-l-2 py-1 ${isDark ? 'border-slate-800' : 'border-slate-100'}`}>
                  <div className={`absolute left-[-9px] top-2.5 w-4 h-4 rounded-full border-4 shadow-sm ${isDark ? 'border-slate-900' : 'border-white'} ${log.amountChange > 0 ? 'bg-violet-600' : 'bg-rose-500'}`}></div>
                  <div className="flex justify-between items-start mb-0.5">
                    <p className={`text-xs md:text-sm font-black uppercase tracking-tight truncate mr-2 ${isDark ? 'text-slate-200' : 'text-slate-800'}`}>{log.reason}</p>
                    <p className="text-[9px] font-bold text-slate-500 whitespace-nowrap">{new Date(log.timestamp).toLocaleDateString()}</p>
                  </div>
                  <p className={`text-sm md:text-base font-black ${log.amountChange > 0 ? 'text-violet-400' : 'text-rose-400'}`}>
                    {log.amountChange > 0 ? '+' : ''}₹{Math.abs(log.amountChange).toLocaleString()}
                  </p>
                  <p className="text-[10px] text-slate-500 font-medium uppercase tracking-widest mt-0.5">New Balance: ₹{log.newPrincipal.toLocaleString()}</p>
                </div>
              ))}
              {principalLogs.length === 0 && (
                <div className="text-center py-20">
                  <i className={`fas fa-history text-5xl mb-4 ${isDark ? 'text-slate-800' : 'text-slate-100'}`}></i>
                  <p className="text-slate-500 italic text-sm">No adjustments logged yet.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {showPrincipalModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in">
          <div className={`${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-white'} rounded-[2rem] w-full max-w-sm shadow-2xl overflow-hidden border`}>
            <div className="p-6 bg-violet-600 text-white flex justify-between items-center">
              <h3 className="text-lg font-black uppercase tracking-tighter">{t('adjustment')}</h3>
              <button onClick={() => setShowPrincipalModal(false)} className="w-9 h-9 flex items-center justify-center rounded-xl bg-white/20">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 md:p-8 space-y-6">
              <div className={`flex p-1 rounded-2xl ${isDark ? 'bg-slate-800' : 'bg-slate-100'}`}>
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'increase'})}
                  className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${principalChange.type === 'increase' ? 'bg-violet-600 text-white shadow-sm' : 'text-slate-500'}`}
                >
                  {t('lend')}
                </button>
                <button 
                  onClick={() => setPrincipalChange({...principalChange, type: 'decrease'})}
                  className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${principalChange.type === 'decrease' ? 'bg-rose-600 text-white shadow-sm' : 'text-slate-500'}`}
                >
                  {t('recover')}
                </button>
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">{t('amount')}</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 font-black text-slate-400">₹</span>
                  <input 
                    type="number" 
                    className={`w-full pl-9 pr-4 py-4 rounded-2xl font-black text-xl outline-none focus:ring-4 transition-all ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800 focus:ring-violet-50'}`}
                    value={principalChange.amount || ''} 
                    onChange={e => setPrincipalChange({...principalChange, amount: parseFloat(e.target.value) || 0})}
