);

export default CustomerDetails;

import React, { useState } from 'react';
import { useApp } from '../App';
import { auth } from '../firebase';
import { signInWithEmailAndPassword, sendPasswordResetEmail } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js';

interface LoginProps {
  onLogin: (success: boolean) => void;
}

const Login: React.FC<LoginProps> = () => {
  const { settings } = useApp();
  const [view, setView] = useState<'login' | 'reset'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isResetSent, setIsResetSent] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      if (view === 'login') {
        await signInWithEmailAndPassword(auth, email, password);
      } else {
        // Firebase Auth secure email-based reset flow
        await sendPasswordResetEmail(auth, email);
        setIsResetSent(true);
      }
    } catch (err: any) {
      let friendlyError = 'An error occurred. Please try again.';
      if (err.code === 'auth/user-not-found') friendlyError = 'No owner account found with this email.';
      if (err.code === 'auth/wrong-password') friendlyError = 'Incorrect password. Please try again.';
      if (err.code === 'auth/invalid-email') friendlyError = 'Please enter a valid email address.';
      if (err.code === 'auth/too-many-requests') friendlyError = 'Too many attempts. Access is temporarily locked.';

      setError(friendlyError);
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-transparent flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white/90 backdrop-blur-xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in border border-white/50">
        {/* Header Section */}
        <div className="bg-violet-600 p-8 md:p-12 text-center text-white relative">
          <div className="relative z-10">
            <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-inner overflow-hidden">
              {settings.logoUrl ? (
                <img src={settings.logoUrl} alt="Logo" className="w-full h-full object-cover" />
              ) : (
                <i className="fas fa-om text-3xl text-violet-600"></i>
              )}
            </div>
            <h1 className="text-2xl md:text-3xl font-black tracking-tighter mb-1 uppercase">
              {view === 'login' ? settings.name : 'Account Recovery'}
            </h1>
            <p className="text-violet-100 text-[10px] font-bold tracking-[0.2em] uppercase opacity-80">
              {view === 'login' ? 'Owner Access Only' : 'Password Reset Service'}
            </p>
          </div>
        </div>

        {/* Form Section */}
        <form onSubmit={handleSubmit} className="p-7 md:p-10 space-y-6">
          {error && (
            <div className="p-4 bg-rose-50 text-rose-600 text-xs rounded-xl border border-rose-100 flex items-center gap-3 font-bold animate-in">
              <i className="fas fa-circle-exclamation"></i>
              <span>{error}</span>
            </div>
          )}

          {isResetSent ? (
            <div className="text-center space-y-6 animate-in">
              <div className="w-16 h-16 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <i className="fas fa-paper-plane text-xl"></i>
              </div>
              <div>
                <h3 className="text-xl font-black text-slate-800">Check Your Email</h3>
                <p className="text-sm text-slate-500 mt-2 font-medium">
                  We've sent a secure reset link to <span className="font-bold text-slate-700">{email}</span>.
                </p>
              </div>
              <button 
                type="button" 
                onClick={() => { setView('login'); setIsResetSent(false); }} 
                className="w-full bg-slate-100 py-4 rounded-2xl font-black text-slate-600 hover:bg-slate-200 transition-colors"
              >
                Return to Login
              </button>
            </div>
          ) : (
            <>
              {/* Email Field */}
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">
                  Admin Email
                </label>
                <div className="relative">
                  <i className="fas fa-envelope absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
                  <input 
                    type="email" 
                    required 
                    className="w-full pl-11 pr-5 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-violet-100 font-bold text-sm transition-all" 
                    placeholder="owner@finance.com" 
                    value={email} 
                    onChange={e => setEmail(e.target.value)} 
                  />
                </div>
              </div>

              {/* Password Field (only for login) */}
              {view === 'login' && (
                <div className="space-y-2">
                  <div className="flex justify-between items-center px-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                      Access Key
                    </label>
                  </div>
                  <div className="relative">
                    <i className="fas fa-key absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
                    <input 
                      type="password" 
                      required 
                      className="w-full pl-11 pr-5 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-violet-100 font-bold text-sm transition-all" 
                      placeholder="••••••••" 
                      value={password} 
                      onChange={e => setPassword(e.target.value)} 
                    />
                  </div>
                </div>
              )}

              {/* Action Button */}
              <button 
                type="submit" 
                disabled={isLoading} 
                className="w-full bg-violet-600 text-white py-4 md:py-5 rounded-2xl font-black text-lg shadow-xl hover:bg-violet-700 active:scale-95 transition-all flex items-center justify-center gap-3 disabled:opacity-50"
              >
                {isLoading ? (
                  <i className="fas fa-circle-notch fa-spin"></i>
                ) : (
                  <>
                    <i className={`fas ${view === 'login' ? 'fa-sign-in-alt' : 'fa-unlock-alt'}`}></i>
                    {view === 'login' ? 'Authenticate' : 'Request Reset Link'}
                  </>
                )}
              </button>

              {/* Secondary Actions */}
              <div className="text-center pt-2">
                {view === 'login' ? (
                  <button 
                    type="button" 
                    onClick={() => setView('reset')} 
                    className="text-[10px] font-black text-slate-400 hover:text-violet-600 uppercase tracking-[0.2em] transition-colors"
                  >
                    Forgot Password?
                  </button>
                ) : (
                  <button 
                    type="button" 
                    onClick={() => { setView('login'); setError(''); }} 
                    className="text-[10px] font-black text-slate-400 hover:text-violet-600 uppercase tracking-[0.2em] transition-colors"
                  >
                    <i className="fas fa-arrow-left mr-2"></i>
                    Back to Sign In
                  </button>
                )}
              </div>
            </>
          )}
        </form>
      </div>
    </div>
  );
};

export default Login;

import React from 'react';
import { useApp } from '../App';

interface ConfirmationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  title: string;
  message: string;
  confirmLabel?: string;
  variant?: 'danger' | 'primary';
}

const ConfirmationModal: React.FC<ConfirmationModalProps> = ({ 
  isOpen, 
  onClose, 
  onConfirm, 
  title, 
  message, 
  confirmLabel,
  variant = 'primary'
}) => {
  const { settings, t } = useApp();
  const isDark = settings.themeMode === 'dark';

  if (!isOpen) return null;

  const confirmBg = variant === 'danger' ? 'bg-rose-600 hover:bg-rose-700' : 'bg-violet-600 hover:bg-violet-700';

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-[100] animate-in">
      <div className={`${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-white'} rounded-[2rem] w-full max-w-sm shadow-2xl overflow-hidden border p-8 text-center`}>
        <div className={`w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6 ${variant === 'danger' ? 'bg-rose-100 text-rose-600' : 'bg-violet-100 text-violet-600'}`}>
          <i className={`fas ${variant === 'danger' ? 'fa-trash-alt' : 'fa-exclamation-triangle'} text-xl`}></i>
        </div>

        <h3 className={`text-xl font-black mb-3 ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{title}</h3>
        <p className={`text-sm mb-8 font-medium leading-relaxed ${isDark ? 'text-slate-400' : 'text-slate-500'}`}>{message}</p>

        <div className="flex flex-col gap-3">
          <button 
            onClick={onConfirm}
            className={`w-full text-white py-4 rounded-2xl font-black text-base shadow-xl transition-all active:scale-95 ${confirmBg}`}
          >
            {confirmLabel || t('confirm')}
          </button>
          <button 
            onClick={onClose}
            className={`w-full py-4 rounded-2xl font-black text-sm uppercase tracking-widest transition-all ${isDark ? 'text-slate-500 hover:text-slate-300' : 'text-slate-400 hover:text-slate-600'}`}
          >
            {t('cancel')}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ConfirmationModal;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Customer, Payment, PrincipalLog } from '../types';
import { useApp } from '../App';
import { db } from '../firebase';
import { doc, collection, addDoc, updateDoc, onSnapshot, deleteDoc } from 'https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js';
import ConfirmationModal from '../components/ConfirmationModal';

const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { t, settings, user } = useApp();
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [principalLogs, setPrincipalLogs] = useState<PrincipalLog[]>([]);

  const [showPrincipalModal, setShowPrincipalModal] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [showAdjustmentConfirm, setShowAdjustmentConfirm] = useState(false);

  const [principalChange, setPrincipalChange] = useState({ 
    amount: 0, 
    reason: '', 
    type: 'increase',
    date: new Date().toISOString().split('T')[0]
  });

  const [paymentInput, setPaymentInput] = useState({ 
    amount: 0, 
    month: new Date().getMonth(), 
    year: new Date().getFullYear(),
    collectionDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    if (!user || !id) return;

    const customerRef = doc(db, 'users', user.uid, 'customers', id);
    const paymentsRef = collection(db, 'users', user.uid, 'payments');
    const logsRef = collection(db, 'users', user.uid, 'principalLogs');

    const unsubC = onSnapshot(customerRef, (snap) => {
      if (snap.exists()) {
        setCustomer({ id: snap.id, ...snap.data() } as Customer);
      } else {
        // Only navigate if we aren't already navigating (prevent loop on delete)
        if (window.location.hash.includes(id)) navigate('/customers');
      }
    });

    const unsubP = onSnapshot(paymentsRef, (snap) => {
      setPayments(snap.docs
        .map(doc => ({ id: doc.id, ...doc.data() } as Payment))
        .filter(p => p.customerId === id));
    });

    const unsubL = onSnapshot(logsRef, (snap) => {
      setPrincipalLogs(snap.docs
        .map(doc => ({ id: doc.id, ...doc.data() } as PrincipalLog))
        .filter(l => l.customerId === id));
    });

    return () => { unsubC(); unsubP(); unsubL(); };
  }, [user, id, navigate]);

  const handleUpdatePrincipal = async () => {
    if (!customer || !user) return;

    // Safety Guard: Large amount check (₹50,000 threshold)
    if (principalChange.amount > 50000 && !showAdjustmentConfirm) {
      setShowAdjustmentConfirm(true);
      return;
    }

    const diff = principalChange.type === 'increase' ? principalChange.amount : -principalChange.amount;
    const newP = customer.principal + diff;

    const timestamp = new Date(principalChange.date).getTime();

    const logData = { 
      customerId: customer.id, 
      amountChange: diff, 
      newPrincipal: newP, 
      reason: principalChange.reason || 'Manual Adjustment', 
      timestamp: timestamp 
    };

    try {
      await updateDoc(doc(db, 'users', user.uid, 'customers', customer.id), { principal: newP });
      await addDoc(collection(db, 'users', user.uid, 'principalLogs'), logData);
      setShowPrincipalModal(false);
      setShowAdjustmentConfirm(false);
      setPrincipalChange({ ...principalChange, amount: 0, reason: '' });
    } catch (e) {
      console.error(e);
    }
  };

  const handleDeleteCustomer = async () => {
    if (!customer || !user) return;
    try {
      await deleteDoc(doc(db, 'users', user.uid, 'customers', customer.id));
      navigate('/customers');
    } catch (e) {
      console.error(e);
      alert("Failed to delete account.");
    }
  };

  const handleAddPayment = async () => {
    if (!customer || !user) return;
    const totalDue = (customer.principal * customer.interestRate) / 100;
    const status = paymentInput.amount >= totalDue ? 'Paid' : (paymentInput.amount > 0 ? 'Partial' : 'Pending');

    const timestamp = new Date(paymentInput.collectionDate).getTime();

    const paymentData = { 
      customerId: customer.id, 
      month: paymentInput.month, 
      year: paymentInput.year, 
      amountPaid: paymentInput.amount, 
      totalDue: totalDue, 
      status: status, 
      timestamp: timestamp 
    };

    try {
      await addDoc(collection(db, 'users', user.uid, 'payments'), paymentData);
      setShowPaymentModal(false);
      setPaymentInput({ ...paymentInput, amount: 0 });
    } catch (e) {
      console.error(e);
    }
  };

  const isDark = settings.themeMode === 'dark';

  if (!customer) return <div className="p-12 md:p-20 text-center font-bold text-slate-300 animate-pulse">Accessing Secure Records...</div>;

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start gap-4 px-1">
        <div className="space-y-1 md:space-y-2 w-full">
          <button 
            onClick={() => navigate('/customers')} 
            className={`text-[10px] font-black hover:bg-violet-50 px-3 py-1.5 rounded-xl uppercase tracking-widest transition-all mb-2 flex items-center w-fit ${isDark ? 'text-violet-400 hover:bg-slate-800' : 'text-violet-600'}`}
          >
            <i className="fas fa-arrow-left mr-2"></i> {t('ledger')}
          </button>
          <h2 className={`text-3xl md:text-4xl font-black tracking-tight truncate ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{customer.name}</h2>
          <p className={`${isDark ? 'text-slate-400' : 'text-slate-500'} text-sm font-medium flex items-center gap-2`}>
            <i className="fas fa-location-dot opacity-30"></i>
            {customer.address || 'No location logged'}
          </p>
        </div>
        <div className="flex w-full md:w-auto gap-3">
          <a 
            href={`tel:${customer.phone}`} 
            className={`w-12 h-12 md:w-14 md:h-14 rounded-2xl flex items-center justify-center transition-all shadow-lg shrink-0 ${isDark ? 'bg-slate-800 text-emerald-400 hover:bg-slate-700' : 'bg-emerald-100 text-emerald-700 hover:bg-emerald-200 shadow-emerald-50'}`}
          >
            <i className="fas fa-phone text-lg"></i>
          </a>
          <button 
            onClick={() => setShowPrincipalModal(true)} 
            className="flex-1 md:flex-none bg-violet-600 text-white px-6 py-3.5 md:py-4 rounded-2xl font-black shadow-xl shadow-violet-100 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 text-sm md:text-base active:scale-95"
          >
            <i className="fas fa-coins"></i> {t('adjustment')}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-6">
        <DetailCard isDark={isDark} label={t('capital')} value={`₹${customer.principal.toLocaleString()}`} />
        <DetailCard isDark={isDark} label={`Interest (${customer.interestRate}%)`} value={`₹${((customer.principal * customer.interestRate)/100).toLocaleString()}`} primary />
        <DetailCard isDark={isDark} label={t('due')} value={`Day ${customer.dueDate}`} badge />
        <DetailCard isDark={isDark} label={t('startDate')} value={customer.startDate ? new Date(customer.startDate).toLocaleDateString(undefined, { day: 'numeric', month: 'short', year: 'numeric' }) : 'N/A'} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white border-slate-100'} rounded-[1.5rem] md:rounded-[2rem] border shadow-sm overflow-hidden animate-in delay-2`}>
          <div className={`px-6 py-5 md:px-8 md:py-6 border-b flex justify-between items-center ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
