import { initializeApp, getApps, getApp } from "firebase/app";
import { getAuth } from "firebase/auth";
import {
		getFirestore,
		collection as fbCollection,
		doc as fbDoc,
		CollectionReference,
		DocumentReference,
		Firestore
} from "firebase/firestore";

// Try Vite-style env first, then CRA-style, then fall back to previous hardcoded values (if any)
const firebaseConfig = {
  apiKey:
    (typeof import.meta !== "undefined" && (import.meta as any).env?.VITE_FIREBASE_API_KEY) ||
    process.env.REACT_APP_FIREBASE_API_KEY ||
    "AIzaSyCvzpsAsV2nJTTJu98PlP2ZK6AXXpPifII",
  authDomain:
    (typeof import.meta !== "undefined" && (import.meta as any).env?.VITE_FIREBASE_AUTH_DOMAIN) ||
    process.env.REACT_APP_FIREBASE_AUTH_DOMAIN ||
    "lendflow0718.firebaseapp.com",
  projectId:
    (typeof import.meta !== "undefined" && (import.meta as any).env?.VITE_FIREBASE_PROJECT_ID) ||
    process.env.REACT_APP_FIREBASE_PROJECT_ID ||
    "lendflow0718",
  storageBucket:
    (typeof import.meta !== "undefined" && (import.meta as any).env?.VITE_FIREBASE_STORAGE_BUCKET) ||
    process.env.REACT_APP_FIREBASE_STORAGE_BUCKET ||
    "lendflow0718.firebasestorage.app",
  messagingSenderId:
    (typeof import.meta !== "undefined" && (import.meta as any).env?.VITE_FIREBASE_MESSAGING_SENDER_ID) ||
    process.env.REACT_APP_FIREBASE_MESSAGING_SENDER_ID ||
    "688064700314",
  appId:
    (typeof import.meta !== "undefined" && (import.meta as any).env?.VITE_FIREBASE_APP_ID) ||
    process.env.REACT_APP_FIREBASE_APP_ID ||
    "1:688064700314:web:a015b66e3c88762e1a2423"
};

if (!firebaseConfig.apiKey) {
  // avoid throwing — log to console so page can still render; check console for details
  console.warn("Firebase API key missing. Check env vars (VITE_FIREBASE_* or REACT_APP_FIREBASE_*).");
}

// Initialize Firebase with runtime safety: if init fails, do not throw at import time.
let app: any = null;
let _auth: any = null;
let _db: any = null;
let isFirebaseAvailable = false;

try {
  app = getApps().length > 0 ? getApp() : initializeApp(firebaseConfig);
  _auth = getAuth(app);
  _db = getFirestore(app);
  isFirebaseAvailable = true;
  console.log("Firebase initialized:", app?.name || "(no-name)");
} catch (initErr) {
  // Do NOT rethrow — export safe proxies instead so UI can render and you can see runtime errors.
  console.error("Firebase initialization failed:", initErr);
  console.trace();

  // create a proxy that throws a friendly error on first access
  const makeStub = (name: string) =>
    new Proxy(
      {},
      {
        get() {
          throw new Error(
            `Firebase ${name} is not available. Initialization failed. Check console for details.`
          );
        },
        apply() {
          throw new Error(
            `Firebase ${name} is not available. Initialization failed. Check console for details.`
          );
        }
      }
    );

  _auth = makeStub("auth");
  _db = makeStub("firestore");
}

export const auth = _auth;
export const db = _db;
export const isFirebaseAvailableFlag = isFirebaseAvailable;

// debug log
try { console.log("Firebase initialized:", app?.name || "(no-name)"); } catch (e) { console.warn("Firebase init check failed:", e); }

// Helper: safe collection/doc creators with clearer errors
function isFirestoreLike(x: any): x is Firestore {
	return !!x && typeof x === "object" && ("_delegate" in x || "app" in x);
}

/**
 * Usage:
 * - getCollection("users")               // uses exported db
 * - getCollection(db, "users")          // explicit db
 * - getCollection(db, "users", "sub")   // forwarded to firebase collection()
 */
export function getCollection(...args: any[]): CollectionReference {
	if (!db) throw new Error("Firestore (db) is not initialized.");
	if (typeof args[0] === "string") {
		return fbCollection(db, ...args);
	}
	if (isFirestoreLike(args[0])) {
		return fbCollection(...args);
	}
	if (args[0] && typeof args[0] === "object" && ("id" in args[0] || "_key" in args[0] || "path" in args[0])) {
		return fbCollection(...args);
	}

	// stronger diagnostics to find callers passing wrong argument
	const errMsg = `Invalid first argument passed to getCollection(): ${String(args[0])}`;
	console.error(errMsg, { args });
	console.trace();
	throw new Error(
		'Invalid first argument to getCollection(). Use getCollection("collectionName") or getCollection(db, "collectionName"). ' +
		'If you have older calls like collection("users", ...), switch them to collectionSafe("users", ...) or update call sites.'
	);
}

/**
 * Similar helper for doc()
 * Usage:
 * - getDoc("users/myId") OR getDoc(db, "users", id)
 */
export function getDoc(...args: any[]): DocumentReference {
	if (!db) throw new Error("Firestore (db) is not initialized.");
	if (typeof args[0] === "string") {
		return fbDoc(db, ...args);
	}
	if (isFirestoreLike(args[0])) {
		return fbDoc(...args);
	}
	if (args[0] && typeof args[0] === "object" && ("id" in args[0] || "_key" in args[0] || "path" in args[0])) {
		return fbDoc(...args);
	}

	const errMsg = `Invalid first argument passed to getDoc(): ${String(args[0])}`;
	console.error(errMsg, { args });
	console.trace();
	throw new Error(
		'Invalid first argument to getDoc(). Use getDoc("collection/docId") or getDoc(db, "collection", "docId").'
	);
}

// Backwards-compatible wrappers: accept old signatures and forward to new helpers
export function collectionSafe(...args: any[]) {
	if (args.length === 0) {
		console.error("collectionSafe called with no arguments");
		console.trace();
		throw new Error("collectionSafe requires at least one argument.");
	}
	// ("collectionName", ...) -> use default db
	if (typeof args[0] === "string") return getCollection(...args);
	// (db, "collectionName", ...) -> forward
	if (isFirestoreLike(args[0])) return fbCollection(...args);
	// (ref, ...) -> forward
	if (args[0] && typeof args[0] === "object") return fbCollection(...args);

	console.error("collectionSafe invalid args:", args);
	console.trace();
	throw new Error("collectionSafe: invalid args. Use collectionSafe(db, 'col') or collectionSafe('col').");
}

export function docSafe(...args: any[]) {
	if (args.length === 0) {
		console.error("docSafe called with no arguments");
		console.trace();
		throw new Error("docSafe requires at least one argument.");
	}
	if (typeof args[0] === "string") return getDoc(...args);
	if (isFirestoreLike(args[0])) return fbDoc(...args);
	if (args[0] && typeof args[0] === "object") return fbDoc(...args);

	console.error("docSafe invalid args:", args);
	console.trace();
	throw new Error("docSafe: invalid args. Use docSafe(db, 'col', 'id') or docSafe('col/id').");
}

// New: explicit wrappers that always log arguments and stack trace to locate bad callers
export function collection(...args: any[]): CollectionReference {
	// Prefer default-db string signature
	if (typeof args[0] === "string") {
		return getCollection(...args);
	}
	try {
		// Attempt to forward to firebase's collection (works for db, ref, etc.)
		return fbCollection(...args);
	} catch (err) {
		console.error("collection(...) wrapper caught error. args:", args);
		console.trace();
		throw err;
	}
}

export function doc(...args: any[]): DocumentReference {
	if (typeof args[0] === "string") {
		return getDoc(...args);
	}
	try {
		return fbDoc(...args);
	} catch (err) {
		console.error("doc(...) wrapper caught error. args:", args);
		console.trace();
		throw err;
	}
}

// export helpers for convenience (include new wrappers)
export default { app, auth, db, isFirebaseAvailableFlag, getCollection, getDoc, collectionSafe, docSafe, collection, doc };

