    dueDate: new Date().getDate(),
    startDate: Date.now()
  });

  // Data Sanitization: Ensure Firestore objects (like Timestamps) are converted to plain primitives
  const sanitizeData = (data: any): any => {
    const sanitized = { ...data };
    for (const key in sanitized) {
      if (sanitized[key] && typeof sanitized[key] === 'object' && sanitized[key].toMillis) {
        sanitized[key] = sanitized[key].toMillis();
      }
    }
    return sanitized;
  };

  useEffect(() => {
    if (!user) return;
    const q = collection(db, 'users', user.uid, 'customers');
    const unsub = onSnapshot(q, (snap) => {
      // Mapping and sanitizing to prevent circular structure errors
      const data = snap.docs.map(doc => {
        const raw = doc.data();
        return { id: doc.id, ...sanitizeData(raw) } as Customer;
      });
      setCustomers(data);
    });
    return () => unsub();
  }, [user]);

  const handleAddCustomer = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    try {
      // Construct a clean object for Firestore
      const customerData = {
        name: newCustomer.name || '',
        phone: newCustomer.phone || '',
        address: newCustomer.address || '',
        principal: Number(newCustomer.principal) || 0,
        interestRate: Number(newCustomer.interestRate) || 0,
        dueDate: Number(newCustomer.dueDate) || 1,
        startDate: Number(newCustomer.startDate) || Date.now(),
        createdAt: Date.now()
      };

      await addDoc(collection(db, 'users', user.uid, 'customers'), customerData);

      setIsModalOpen(false);
      setNewCustomer({ 
        name: '', 
        phone: '', 
        address: '', 
        principal: 0, 
        interestRate: 5, 
        dueDate: new Date().getDate(),
        startDate: Date.now()
      });
    } catch (err) {
      console.error("Error adding customer:", err);
      alert("Failed to save borrower. Please check your connection.");
    }
  };

  const clearFilters = () => {
    setSearchTerm('');
    setMinPrincipal('');
    setMaxPrincipal('');
  };

  const handleSort = (key: SortKey) => {
    setSortConfig(prev => ({
      key,
      order: prev.key === key && prev.order === 'asc' ? 'desc' : 'asc'
    }));
  };

  const processedCustomers = useMemo(() => {
    // 1. Filter
    let result = customers.filter(c => {
      const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           c.phone.includes(searchTerm);
      const min = minPrincipal === '' ? 0 : parseFloat(minPrincipal);
      const max = maxPrincipal === '' ? Infinity : parseFloat(maxPrincipal);
      return matchesSearch && c.principal >= min && c.principal <= max;
    });

    // 2. Sort
    result.sort((a, b) => {
      let valA = a[sortConfig.key];
      let valB = b[sortConfig.key];

      if (typeof valA === 'string') valA = valA.toLowerCase();
      if (typeof valB === 'string') valB = valB.toLowerCase();

      if (valA < valB) return sortConfig.order === 'asc' ? -1 : 1;
      if (valA > valB) return sortConfig.order === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [customers, searchTerm, minPrincipal, maxPrincipal, sortConfig]);

  const isDark = settings.themeMode === 'dark';

  const SortIcon = ({ column }: { column: SortKey }) => {
    if (sortConfig.key !== column) return <i className="fas fa-sort ml-2 opacity-20"></i>;
    return sortConfig.order === 'asc' 
      ? <i className="fas fa-sort-up ml-2 text-violet-500"></i> 
      : <i className="fas fa-sort-down ml-2 text-violet-500"></i>;
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 px-1">
        <div>
          <h2 className={`text-2xl md:text-3xl font-black tracking-tight uppercase ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{t('ledger')}</h2>
          <p className={`${isDark ? 'text-slate-500' : 'text-slate-500'} font-medium text-xs md:text-sm`}>Manage borrowing accounts and portfolio health.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="w-full md:w-auto bg-violet-600 text-white px-6 py-3.5 rounded-2xl font-bold shadow-lg shadow-violet-200 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 active:scale-95 text-sm md:text-base"
        >
          <i className="fas fa-plus"></i> {t('newBorrower')}
        </button>
      </div>

      <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} rounded-2xl md:rounded-[2rem] border shadow-sm overflow-hidden animate-in delay-1`}>
        <div className={`p-4 md:p-6 border-b ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-100'}`}>
          <div className="flex flex-col md:flex-row gap-3 md:gap-4 items-center">
            <div className="relative flex-1 w-full">
              <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
              <input 
                type="text" 
                placeholder={t('searchPlaceholder')}
                className={`w-full pl-11 pr-4 py-3 rounded-xl border outline-none text-sm font-medium transition-all shadow-inner ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="flex gap-2 w-full md:w-auto">
              <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex-1 md:flex-none px-5 py-3 rounded-xl border font-bold text-[10px] md:text-xs uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${
                  showFilters 
                    ? (isDark ? 'bg-violet-900/40 border-violet-800 text-violet-400' : 'bg-violet-50 border-violet-200 text-violet-600') 
                    : (isDark ? 'bg-slate-800 border-slate-700 text-slate-400' : 'bg-white border-slate-200 text-slate-500')
                }`}
              >
                <i className="fas fa-sliders text-[10px]"></i>
                {t('filters')}
              </button>
              {(searchTerm || minPrincipal || maxPrincipal) && (
                <button onClick={clearFilters} className={`px-4 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-colors shrink-0 ${isDark ? 'text-slate-500 hover:text-rose-400' : 'text-slate-400 hover:text-rose-500'}`}>
                  {t('clear')}
                </button>
              )}
            </div>
          </div>

          {showFilters && (
            <div className={`mt-4 pt-4 border-t ${isDark ? 'border-slate-800' : 'border-slate-100'} grid grid-cols-1 md:grid-cols-2 gap-4 animate-in`}>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Min Principal (₹)</label>
                <input 
                  type="number" 
                  className={`w-full px-4 py-2.5 rounded-xl border outline-none text-xs font-bold ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                  value={minPrincipal}
                  onChange={(e) => setMinPrincipal(e.target.value)}
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Max Principal (₹)</label>
                <input 
                  type="number" 
                  className={`w-full px-4 py-2.5 rounded-xl border outline-none text-xs font-bold ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                  value={maxPrincipal}
                  onChange={(e) => setMaxPrincipal(e.target.value)}
                />
              </div>
            </div>
          )}
        </div>

        <div className="overflow-x-auto scrollbar-hide">
          <table className="w-full text-left min-w-[500px]">
            <thead className={`text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-[0.2em] border-b ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
              <tr>
                <th 
                  className="px-4 md:px-8 py-4 cursor-pointer hover:text-violet-500 transition-colors group"
                  onClick={() => handleSort('name')}
                >
                  <div className="flex items-center">
                    {t('borrower')}
                    <SortIcon column="name" />
                  </div>
                </th>
                <th 
                  className="px-4 md:px-8 py-4 cursor-pointer hover:text-violet-500 transition-colors group"
                  onClick={() => handleSort('principal')}
                >
                  <div className="flex items-center">
                    {t('capital')}
                    <SortIcon column="principal" />
                  </div>
                </th>
                <th 
                  className="px-4 md:px-8 py-4 cursor-pointer hover:text-violet-500 transition-colors group"
                  onClick={() => handleSort('dueDate')}
                >
                  <div className="flex items-center">
                    {t('due')}
                    <SortIcon column="dueDate" />
                  </div>
                </th>
                <th className="px-4 md:px-8 py-4 text-right">{t('action')}</th>
              </tr>
            </thead>
            <tbody className={`divide-y text-sm ${isDark ? 'divide-slate-800' : 'divide-slate-50'}`}>
              {processedCustomers.map(c => (
                <tr key={c.id} className={`transition-colors group ${isDark ? 'hover:bg-slate-800/40' : 'hover:bg-violet-50/30'}`}>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <div className="flex items-center gap-2 md:gap-3">
                      <div className={`w-8 h-8 md:w-10 md:h-10 rounded-xl flex items-center justify-center font-black text-xs shrink-0 ${isDark ? 'bg-violet-900/40 text-violet-400' : 'bg-violet-100 text-violet-600'}`}>
                        {c.name.charAt(0)}
                      </div>
                      <div className="min-w-0">
                        <p className={`font-bold text-xs md:text-sm truncate max-w-[120px] md:max-w-none ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{c.name}</p>
                        <p className={`text-[9px] md:text-[10px] font-medium ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>{c.phone}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <p className={`font-black text-xs md:text-sm ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>₹{c.principal.toLocaleString()}</p>
                    <p className={`text-[8px] md:text-[9px] font-bold uppercase tracking-widest ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>{c.interestRate}% Int.</p>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <span className={`border px-2 py-1 md:px-2.5 md:py-1.5 rounded-lg text-[8px] md:text-[10px] font-black uppercase tracking-tight whitespace-nowrap ${isDark ? 'bg-slate-800 text-violet-400 border-violet-900/30' : 'bg-white text-violet-600 border-violet-100'}`}>
                      {t('due')} {c.dueDate}
                    </span>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6 text-right">
                    <Link to={`/customers/${c.id}`} className={`inline-flex w-8 h-8 md:w-10 md:h-10 rounded-xl items-center justify-center transition-all shadow-sm border ${isDark ? 'bg-slate-800 border-slate-700 text-violet-400 hover:bg-violet-900/50' : 'bg-white border-slate-100 text-violet-600 hover:bg-violet-600 hover:text-white'}`}>
                      <i className="fas fa-eye text-xs md:text-sm"></i>
                    </Link>
                  </td>
                </tr>
              ))}
              {processedCustomers.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-8 py-16 text-center text-slate-300 font-medium italic">No borrowers found matching your search.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-3 md:p-4 z-50 animate-in overflow-y-auto">
          <div className={`${isDark ? 'bg-slate-900 border-slate-800' : 'bg-white border-white'} rounded-[1.5rem] md:rounded-[2rem] w-full max-w-lg shadow-2xl overflow-hidden border flex flex-col max-h-[95vh]`}>
            <div className="px-6 py-4 md:px-8 md:py-6 bg-violet-600 flex justify-between items-center text-white shrink-0">
              <h3 className="text-lg md:text-xl font-black uppercase tracking-tighter">{t('enrollment')}</h3>
              <button onClick={() => setIsModalOpen(false)} className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/20">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <form onSubmit={handleAddCustomer} className="p-5 md:p-8 space-y-4 md:space-y-6 overflow-y-auto">
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('fullName')}</label>
                <input required type="text" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.name} onChange={e => setNewCustomer({...newCustomer, name: e.target.value})} />
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('contactNo')}</label>
                  <input required type="tel" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.phone} onChange={e => setNewCustomer({...newCustomer, phone: e.target.value})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('startDate')}</label>
                  <input required type="date" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} onChange={e => setNewCustomer({...newCustomer, startDate: new Date(e.target.value).getTime()})} />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('interestRate')}</label>
                  <input required type="number" step="0.1" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.interestRate} onChange={e => setNewCustomer({...newCustomer, interestRate: parseFloat(e.target.value)})} />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('autoDueDay')}</label>
                  <input required type="number" min="1" max="31" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.dueDate} onChange={e => setNewCustomer({...newCustomer, dueDate: parseInt(e.target.value)})} />
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('openingCapital')}</label>
                <input required type="number" className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-violet-400 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-violet-600'}`} value={newCustomer.principal} onChange={e => setNewCustomer({...newCustomer, principal: parseFloat(e.target.value)})} />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">{t('address')}</label>
                <textarea rows={2} className={`w-full px-4 py-2.5 border rounded-xl font-bold text-sm outline-none ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800'}`} value={newCustomer.address} onChange={e => setNewCustomer({...newCustomer, address: e.target.value})}></textarea>
              </div>
              <button type="submit" className="w-full bg-violet-600 text-white py-4 rounded-2xl font-black text-base md:text-lg hover:bg-violet-700 transition-all shadow-xl shadow-violet-200 mt-2">
                {t('enrollBtn')}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

