      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
        <section className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-6 md:p-8 rounded-[2rem] border shadow-sm animate-in delay-2`}>
          <h3 className={`text-xl font-black mb-6 flex items-center gap-3 uppercase tracking-tight ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>
            <span className={`w-10 h-10 rounded-xl ${isDark ? 'bg-violet-900/40 text-violet-400' : 'bg-violet-100 text-violet-600'} flex items-center justify-center`}>
              <i className="fas fa-calendar-day text-sm"></i>
            </span>
            {t('dueToday')}
          </h3>
          <div className="space-y-3">
            {dueToday.length > 0 ? (
              dueToday.map(c => (
                <div key={c.id} className={`flex justify-between items-center p-4 rounded-2xl border border-transparent transition-all ${isDark ? 'hover:bg-slate-800 hover:border-slate-700' : 'hover:bg-slate-50 hover:border-slate-100'}`}>
                  <div className="min-w-0 flex-1 pr-2">
                    <p className={`font-black text-sm truncate ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{c.name}</p>
                    <p className={`text-[10px] font-bold uppercase ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>{c.phone}</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <a 
                      href={`tel:${c.phone}`}
                      className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all shadow-sm shrink-0 ${isDark ? 'bg-emerald-900/20 text-emerald-400 hover:bg-emerald-900/40' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'}`}
                      title="Call Borrower"
                    >
                      <i className="fas fa-phone text-xs"></i>
                    </a>
                    <div className="text-right shrink-0">
                      <p className="font-black text-violet-600 text-sm">₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                      <Link to={`/customers/${c.id}`} className="text-[10px] font-black uppercase text-violet-400 hover:text-violet-600">{t('details')}</Link>
                    </div>
                  </div>
                </div>
              ))
            ) : <div className="text-center py-12 text-slate-300 uppercase tracking-widest text-xs font-black">Clear for today!</div>}
          </div>
        </section>

        <section className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-6 md:p-8 rounded-[2rem] border shadow-sm animate-in delay-3`}>
          <h3 className={`text-xl font-black mb-6 flex items-center gap-3 uppercase tracking-tight ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>
            <span className={`w-10 h-10 rounded-xl ${isDark ? 'bg-rose-900/40 text-rose-400' : 'bg-rose-100 text-rose-600'} flex items-center justify-center`}>
              <i className="fas fa-exclamation-triangle text-sm"></i>
            </span>
            {t('overdue')}
          </h3>
          <div className="space-y-3">
            {overdue.length > 0 ? (
              overdue.map(c => (
                <div key={c.id} className={`flex justify-between items-center p-4 rounded-2xl border transition-all ${isDark ? 'bg-rose-900/20 border-rose-900/40' : 'bg-rose-50/40 border-rose-100'}`}>
                  <div className="min-w-0 flex-1 pr-2">
                    <p className={`font-black text-sm truncate ${isDark ? 'text-rose-100' : 'text-rose-900'}`}>{c.name}</p>
                    <p className={`text-[10px] font-black uppercase ${isDark ? 'text-rose-400/60' : 'text-rose-400'}`}>{t('due')}: {c.dueDate}th</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <a 
                      href={`tel:${c.phone}`}
                      className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all shadow-sm shrink-0 ${isDark ? 'bg-emerald-900/20 text-emerald-400 hover:bg-emerald-900/40' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'}`}
                      title="Call Borrower"
                    >
                      <i className="fas fa-phone text-xs"></i>
                    </a>
                    <div className="text-right shrink-0">
                      <p className={`font-black text-sm ${isDark ? 'text-rose-400' : 'text-rose-700'}`}>₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                      <Link to={`/customers/${c.id}`} className="text-[10px] font-black uppercase text-rose-500 hover:underline">{t('collect')}</Link>
                    </div>
                  </div>
                </div>
              ))
            ) : <div className="text-center py-12 text-slate-300 uppercase tracking-widest text-xs font-black">All caught up!</div>}
          </div>
        </section>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: string; color: string; delay?: string; isDark: boolean }> = ({ label, value, icon, color, delay, isDark }) => (
  <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-5 md:p-8 rounded-[1.5rem] md:rounded-[2.5rem] border shadow-sm flex flex-col items-center justify-center gap-3 animate-in ${delay} hover:shadow-xl transition-all group`}>
    <div className={`${color} w-12 h-12 md:w-16 rounded-2xl flex items-center justify-center text-white text-xl shadow-lg transition-transform group-hover:scale-110`}><i className={`fas ${icon}`}></i></div>
    <div className="text-center min-w-0 w-full">
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 truncate">{label}</p>
      <p className={`text-base md:text-2xl font-black leading-tight truncate ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{value}</p>
    </div>
  </div>
);

export default Dashboard;

import React, { useState, createContext, useContext, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Customers from './pages/Customers';
import AddCustomer from './pages/AddCustomer';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import Settings from './pages/Settings';
import Profile from './pages/Profile';
import Login from './pages/Login';
import { Language, translations } from './translations';
import { FinanceSettings, ProfileSettings } from './types';
import { auth, db } from './firebase';
import { onAuthStateChanged, signOut, User } from 'firebase/auth';
import { doc, getDoc, setDoc } from 'firebase/firestore';

interface AppContextType {
  user: User | null;
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: keyof typeof translations.en) => string;
  settings: FinanceSettings;
  updateSettings: (newSettings: FinanceSettings) => void;
  profile: ProfileSettings;
  updateProfile: (newProfile: ProfileSettings) => void;
  loading: boolean;
}

export const AppContext = createContext<AppContextType | undefined>(undefined);

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [language, setLanguageState] = useState<Language>(() => (localStorage.getItem('appLang') as Language) || 'en');

  const [settings, setSettings] = useState<FinanceSettings>({
    name: 'LendFlow Admin',
    logoUrl: '',
    backgroundUrl: 'https://images.unsplash.com/photo-1561059488-916d69792237?q=80&w=2600',
    themeMode: 'light',
    primaryColor: '#7c3aed'
  });

  const [profile, setProfile] = useState<ProfileSettings>({
    displayName: 'New Owner',
    email: '',
    avatarUrl: 'https://api.dicebear.com/7.x/avataaars/svg?seed=admin',
    role: 'Owner'
  });

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        const settingsRef = doc(db, 'users', currentUser.uid, 'config', 'settings');
        const profileRef = doc(db, 'users', currentUser.uid, 'config', 'profile');

        const [settingsSnap, profileSnap] = await Promise.all([
          getDoc(settingsRef),
          getDoc(profileRef)
        ]);

        if (settingsSnap.exists()) setSettings(settingsSnap.data() as FinanceSettings);
        if (profileSnap.exists()) setProfile(profileSnap.data() as ProfileSettings);
        else {
          const initProfile = { ...profile, email: currentUser.email || '' };
          await setDoc(profileRef, initProfile);
          setProfile(initProfile);
        }
      }
      setAuthLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    document.body.style.backgroundImage = `url('${settings.backgroundUrl}')`;
    document.body.className = `text-slate-900 selection:bg-violet-100 selection:text-violet-900 font-sans theme-${settings.themeMode}`;
    if (settings.themeMode === 'dark') {
      document.body.classList.add('text-slate-100');
      document.body.classList.remove('text-slate-900');
    } else {
      document.body.classList.add('text-slate-900');
      document.body.classList.remove('text-slate-100');
    }
  }, [settings.backgroundUrl, settings.themeMode]);

  const setLanguage = (lang: Language) => {
    setLanguageState(lang);
    localStorage.setItem('appLang', lang);
  };

  const updateSettings = async (newSettings: FinanceSettings) => {
    if (!user) return;
    setSettings(newSettings);
    await setDoc(doc(db, 'users', user.uid, 'config', 'settings'), newSettings);
  };

  const updateProfile = async (newProfile: ProfileSettings) => {
    if (!user) return;
    setProfile(newProfile);
    await setDoc(doc(db, 'users', user.uid, 'config', 'profile'), newProfile);
  };

  const t = (key: keyof typeof translations.en) => translations[language][key] || translations.en[key];

  const handleLogout = async () => {
    await signOut(auth);
  };

  if (authLoading) {
    return <div className="h-screen flex items-center justify-center bg-slate-50 text-violet-600 font-black animate-pulse uppercase tracking-[0.2em] text-xs">Initializing Security...</div>;
  }

  if (!user) {
    return (
      <AppContext.Provider value={{ user, language, setLanguage, t, settings, updateSettings, profile, updateProfile, loading: authLoading }}>
        <Login onLogin={() => {}} />
      </AppContext.Provider>
    );
  }

  return (
    <AppContext.Provider value={{ user, language, setLanguage, t, settings, updateSettings, profile, updateProfile, loading: authLoading }}>
      <HashRouter>
        <div className="flex h-screen bg-transparent overflow-hidden relative">
          <div className="fixed top-3 right-14 md:top-6 md:right-8 z-[60] flex items-center">
            <button
              onClick={() => setLanguage(language === 'en' ? 'ta' : 'en')}
              className={`${settings.themeMode === 'dark' ? 'bg-slate-800 border-slate-700 text-slate-100' : 'bg-white/90 border-slate-200 text-slate-600'} backdrop-blur-md border px-3 py-1.5 rounded-full shadow-lg hover:shadow-violet-200 transition-all flex items-center gap-2 group active:scale-95`}
            >
              <div className="w-5 h-5 rounded-full bg-violet-600 text-white flex items-center justify-center text-[8px] font-black">{language === 'en' ? 'EN' : 'TA'}</div>
              <span className="text-[10px] font-black uppercase tracking-widest hidden sm:inline">{language === 'en' ? 'தமிழ்' : 'English'}</span>
            </button>
          </div>

          <Sidebar onLogout={handleLogout} isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />

          <main className="flex-1 overflow-y-auto pt-20 md:pt-12 px-4 pb-12 md:px-8">
            <div className="max-w-7xl mx-auto">
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/customers" element={<Customers />} />
                <Route path="/customers/new" element={<AddCustomer />} />
                <Route path="/customers/:id" element={<CustomerDetails />} />
                <Route path="/reports" element={<Reports />} />
                <Route path="/settings" element={<Settings />} />
                <Route path="/profile" element={<Profile />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </div>
          </main>
        </div>
      </HashRouter>
    </AppContext.Provider>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Customer } from '../types';
import { useApp } from '../App';
import { db } from '../firebase';
import { collection, onSnapshot } from 'firebase/firestore';

type SortKey = 'name' | 'principal' | 'dueDate';
type SortOrder = 'asc' | 'desc';

interface SortConfig {
  key: SortKey;
  order: SortOrder;
}

const Customers: React.FC = () => {
  const { t, settings, user } = useApp();
  const navigate = useNavigate();
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [showFilters, setShowFilters] = useState(false);

  const [searchTerm, setSearchTerm] = useState('');
  const [minPrincipal, setMinPrincipal] = useState<string>('');
  const [maxPrincipal, setMaxPrincipal] = useState<string>('');

  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: 'name', order: 'asc' });

  // Data Sanitization: Convert Firestore objects to plain primitives to avoid circular errors
  const sanitizeData = (data: any): any => {
    const sanitized = { ...data };
    for (const key in sanitized) {
      if (sanitized[key] && typeof sanitized[key] === 'object' && sanitized[key].toMillis) {
        sanitized[key] = sanitized[key].toMillis();
      }
    }
    return sanitized;
  };

  useEffect(() => {
    if (!user) return;
    const q = collection(db, 'users', user.uid, 'customers');
    const unsub = onSnapshot(q, (snap) => {
      const data = snap.docs.map(doc => {
        const raw = doc.data();
        // Construct a clean, flat JS object
        return { id: doc.id, ...sanitizeData(raw) } as Customer;
      });
      setCustomers(data);
    });
    return () => unsub();
  }, [user]);

  const clearFilters = () => {
    setSearchTerm('');
    setMinPrincipal('');
    setMaxPrincipal('');
  };

  const handleSort = (key: SortKey) => {
    setSortConfig(prev => ({
      key,
      order: prev.key === key && prev.order === 'asc' ? 'desc' : 'asc'
    }));
  };

  const processedCustomers = useMemo(() => {
    let result = customers.filter(c => {
      const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           c.phone.includes(searchTerm);
      const min = minPrincipal === '' ? 0 : parseFloat(minPrincipal);
      const max = maxPrincipal === '' ? Infinity : parseFloat(maxPrincipal);
      return matchesSearch && c.principal >= min && c.principal <= max;
    });

    result.sort((a, b) => {
      let valA = a[sortConfig.key];
      let valB = b[sortConfig.key];
      if (typeof valA === 'string') valA = valA.toLowerCase();
      if (typeof valB === 'string') valB = valB.toLowerCase();
      if (valA < valB) return sortConfig.order === 'asc' ? -1 : 1;
      if (valA > valB) return sortConfig.order === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [customers, searchTerm, minPrincipal, maxPrincipal, sortConfig]);

  const isDark = settings.themeMode === 'dark';

  const SortIcon = ({ column }: { column: SortKey }) => {
    if (sortConfig.key !== column) return <i className="fas fa-sort ml-2 opacity-20 text-[8px]"></i>;
    return sortConfig.order === 'asc' 
      ? <i className="fas fa-sort-up ml-2 text-violet-500"></i> 
      : <i className="fas fa-sort-down ml-2 text-violet-500"></i>;
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in pb-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 px-1">
        <div>
          <h2 className={`text-2xl md:text-3xl font-black tracking-tight uppercase ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{t('ledger')}</h2>
          <p className={`${isDark ? 'text-slate-500' : 'text-slate-500'} font-medium text-xs md:text-sm`}>Manage borrowing accounts and portfolio health.</p>
        </div>
        <Link 
          to="/customers/new"
          className="w-full md:w-auto bg-violet-600 text-white px-6 py-3.5 rounded-2xl font-bold shadow-lg shadow-violet-200 hover:bg-violet-700 transition-all flex items-center justify-center gap-2 active:scale-95 text-sm md:text-base"
        >
          <i className="fas fa-plus"></i> {t('newBorrower')}
        </Link>
      </div>

      <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} rounded-2xl md:rounded-[2rem] border shadow-sm overflow-hidden animate-in delay-1`}>
        <div className={`p-4 md:p-6 border-b ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-100'}`}>
          <div className="flex flex-col md:flex-row gap-3 md:gap-4 items-center">
            <div className="relative flex-1 w-full">
              <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
              <input 
                type="text" 
                placeholder={t('searchPlaceholder')}
                className={`w-full pl-11 pr-4 py-3 rounded-xl border outline-none text-sm font-medium transition-all shadow-inner ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="flex gap-2 w-full md:w-auto">
              <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`flex-1 md:flex-none px-5 py-3 rounded-xl border font-bold text-[10px] md:text-xs uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${
                  showFilters 
                    ? (isDark ? 'bg-violet-900/40 border-violet-800 text-violet-400' : 'bg-violet-50 border-violet-200 text-violet-600') 
                    : (isDark ? 'bg-slate-800 border-slate-700 text-slate-400' : 'bg-white border-slate-200 text-slate-500')
                }`}
              >
                <i className="fas fa-sliders text-[10px]"></i>
                {t('filters')}
              </button>
              {(searchTerm || minPrincipal || maxPrincipal) && (
                <button onClick={clearFilters} className={`px-4 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-colors shrink-0 ${isDark ? 'text-slate-500 hover:text-rose-400' : 'text-slate-400 hover:text-rose-500'}`}>
                  {t('clear')}
                </button>
              )}
            </div>
          </div>

          {showFilters && (
            <div className={`mt-4 pt-4 border-t ${isDark ? 'border-slate-800' : 'border-slate-100'} grid grid-cols-1 md:grid-cols-2 gap-4 animate-in`}>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Min Principal (₹)</label>
                <input 
                  type="number" 
                  className={`w-full px-4 py-2.5 rounded-xl border outline-none text-xs font-bold ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                  value={minPrincipal}
                  onChange={(e) => setMinPrincipal(e.target.value)}
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Max Principal (₹)</label>
                <input 
                  type="number" 
                  className={`w-full px-4 py-2.5 rounded-xl border outline-none text-xs font-bold ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-white border-slate-200 focus:ring-violet-50 focus:border-violet-400'}`}
                  value={maxPrincipal}
                  onChange={(e) => setMaxPrincipal(e.target.value)}
                />
              </div>
            </div>
          )}
        </div>

        <div className="overflow-x-auto scrollbar-hide">
          <table className="w-full text-left min-w-[500px]">
            <thead className={`text-slate-400 font-black text-[9px] md:text-[10px] uppercase tracking-[0.2em] border-b ${isDark ? 'bg-slate-800/50 border-slate-800' : 'bg-slate-50/50 border-slate-50'}`}>
              <tr>
                <th className="px-4 md:px-8 py-4 cursor-pointer hover:text-violet-500 transition-colors group" onClick={() => handleSort('name')}>
                  <div className="flex items-center">
                    {t('borrower')}
                    <SortIcon column="name" />
                  </div>
                </th>
                <th className="px-4 md:px-8 py-4 cursor-pointer hover:text-violet-500 transition-colors group" onClick={() => handleSort('principal')}>
                  <div className="flex items-center">
                    {t('capital')}
                    <SortIcon column="principal" />
                  </div>
                </th>
                <th className="px-4 md:px-8 py-4 cursor-pointer hover:text-violet-500 transition-colors group" onClick={() => handleSort('dueDate')}>
                  <div className="flex items-center">
                    {t('due')}
                    <SortIcon column="dueDate" />
                  </div>
                </th>
                <th className="px-4 md:px-8 py-4 text-right">{t('action')}</th>
              </tr>
            </thead>
            <tbody className={`divide-y text-sm ${isDark ? 'divide-slate-800' : 'divide-slate-50'}`}>
              {processedCustomers.map(c => (
                <tr key={c.id} className={`transition-colors group ${isDark ? 'hover:bg-slate-800/40' : 'hover:bg-violet-50/30'}`}>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <div className="flex items-center gap-2 md:gap-3">
                      <div className={`w-8 h-8 md:w-10 md:h-10 rounded-xl flex items-center justify-center font-black text-xs shrink-0 ${isDark ? 'bg-violet-900/40 text-violet-400' : 'bg-violet-100 text-violet-600'}`}>
                        {c.name.charAt(0)}
                      </div>
                      <div className="min-w-0">
                        <p className={`font-bold text-xs md:text-sm truncate max-w-[120px] md:max-w-none ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{c.name}</p>
                        <p className={`text-[9px] md:text-[10px] font-medium ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>{c.phone}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <p className={`font-black text-xs md:text-sm ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>₹{c.principal.toLocaleString()}</p>
                    <p className={`text-[8px] md:text-[9px] font-bold uppercase tracking-widest ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>{c.interestRate}% Int.</p>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6">
                    <span className={`border px-2 py-1 md:px-2.5 md:py-1.5 rounded-lg text-[8px] md:text-[10px] font-black uppercase tracking-tight whitespace-nowrap ${isDark ? 'bg-slate-800 text-violet-400 border-violet-900/30' : 'bg-white text-violet-600 border-violet-100'}`}>
                      {t('due')} {c.dueDate}
                    </span>
                  </td>
                  <td className="px-4 md:px-8 py-4 md:py-6 text-right">
                    <Link to={`/customers/${c.id}`} className={`inline-flex w-8 h-8 md:w-10 md:h-10 rounded-xl items-center justify-center transition-all shadow-sm border ${isDark ? 'bg-slate-800 border-slate-700 text-violet-400 hover:bg-violet-900/50' : 'bg-white border-slate-100 text-violet-600 hover:bg-violet-600 hover:text-white'}`}>
                      <i className="fas fa-eye text-xs md:text-sm"></i>
                    </Link>
                  </td>
                </tr>
              ))}
              {processedCustomers.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-8 py-16 text-center text-slate-300 font-medium italic">No borrowers found matching your search.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

