    dueDate: new Date().getDate(),
    startDate: Date.now()
  });

  const handleAddCustomer = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    setIsSubmitting(true);

    try {
      // Data Sanitization before sending to Firestore
      const customerData = {
        name: (formData.name || '').trim(),
        phone: (formData.phone || '').trim(),
        address: (formData.address || '').trim(),
        principal: Number(formData.principal) || 0,
        interestRate: Number(formData.interestRate) || 0,
        dueDate: Number(formData.dueDate) || 1,
        startDate: Number(formData.startDate) || Date.now(),
        createdAt: Date.now()
      };

      await addDoc(collection(db, 'users', user.uid, 'customers'), customerData);
      navigate('/customers');
    } catch (err) {
      console.error("Error adding customer:", err);
      alert("Failed to save borrower. Please check your connection.");
    } finally {
      setIsSubmitting(false);
    }
  };

