                className={`w-full px-5 py-3.5 md:py-4 border rounded-xl md:rounded-2xl font-bold text-sm md:text-base outline-none transition-all ${isDark ? 'bg-slate-800 border-slate-700 text-slate-100 focus:ring-violet-900/30' : 'bg-slate-50 border-slate-100 text-slate-800 focus:ring-violet-50'}`} 
                value={formData.name} 
                onChange={e => setFormData({...formData, name: e.target.value})} 
                placeholder="Full Name" 
