import React, { useState, useEffect } from 'react';
import { Customer, Payment } from '../types';
import { Link } from 'react-router-dom';
import { useApp } from '../App';
import { db } from '../firebase';
import { collection, onSnapshot } from 'firebase/firestore';
// Import GoogleGenAI for intelligent portfolio summaries
import { GoogleGenAI } from "@google/genai";

const Dashboard: React.FC = () => {
  const { t, settings, user } = useApp();
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [payments, setPayments] = useState<Payment[]>([]);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Helper to map Firestore docs to plain objects immediately to avoid circular structure errors
  const mapDocs = (snap: any) => snap.docs.map((doc: any) => ({ id: doc.id, ...doc.data() }));

  useEffect(() => {
    if (!user) return;

    // Subscribe to isolated user collections
    const customersRef = collection(db, 'users', user.uid, 'customers');
    const paymentsRef = collection(db, 'users', user.uid, 'payments');

    const unsubC = onSnapshot(customersRef, (snap) => {
      setCustomers(mapDocs(snap) as Customer[]);
    });

    const unsubP = onSnapshot(paymentsRef, (snap) => {
      setPayments(mapDocs(snap) as Payment[]);
    });

    return () => { unsubC(); unsubP(); };
  }, [user]);

  const totalPrincipal = customers.reduce((sum, c) => sum + c.principal, 0);
  const currentMonth = new Date().getMonth();
  const currentYear = new Date().getFullYear();
  const today = new Date().getDate();

  const monthlyIncome = payments
    .filter(p => p.month === currentMonth && p.year === currentYear)
    .reduce((sum, p) => sum + p.amountPaid, 0);

  const dueToday = customers.filter(c => c.dueDate === today && c.principal > 0);
  const overdue = customers.filter(c => {
    const payment = payments.find(p => p.customerId === c.id && p.month === currentMonth && p.year === currentYear);
    return today > c.dueDate && (!payment || payment.status !== 'Paid') && c.principal > 0;
  });

  // Generate AI Portfolio Insight using Gemini 3
  useEffect(() => {
    const generateSummary = async () => {
      if (customers.length === 0 || !user) return;
      setIsAiLoading(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Use plain numbers/strings to ensure NO circular references in prompt construction
        const portfolioData = {
          count: customers.length,
          capital: totalPrincipal,
          income: monthlyIncome,
          overdueCount: overdue.length,
          dueTodayCount: dueToday.length
        };

        const prompt = `As a world-class financial analyst, analyze this lending portfolio and provide a 2-sentence strategic summary for the owner:
          - Total Active Borrowers: ${portfolioData.count}
          - Portfolio Capital: ₹${portfolioData.capital.toLocaleString()}
          - This Month's Collection: ₹${portfolioData.income.toLocaleString()}
          - Overdue Accounts: ${portfolioData.overdueCount}
          - Collection Targets Today: ${portfolioData.dueTodayCount}
          Focus on portfolio health, risk levels, and actionable steps. Keep it professional and encouraging.`;

        // Correctly setting both maxOutputTokens and thinkingBudget together as per guidelines
        const response = await ai.models.generateContent({
          model: 'gemini-3-pro-preview',
          contents: prompt,
          config: {
            maxOutputTokens: 1000,
            thinkingConfig: { thinkingBudget: 500 }
          }
        });

        setAiSummary(response.text || '');
      } catch (err) {
        console.error("AI Insight Error:", err);
      } finally {
        setIsAiLoading(false);
      }
    };

    const timer = setTimeout(generateSummary, 2000); 
    return () => clearTimeout(timer);
  }, [customers.length, totalPrincipal, monthlyIncome, overdue.length, dueToday.length, user]);

  const isDark = settings.themeMode === 'dark';

  return (
    <div className="space-y-6 md:space-y-10 animate-in pb-12">
      <header className="px-1 flex flex-col lg:flex-row lg:items-center justify-between gap-5">
        <div>
          <h2 className={`text-3xl md:text-5xl font-black tracking-tight uppercase ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{t('overview')}</h2>
          <p className={`${isDark ? 'text-slate-400' : 'text-slate-500'} font-medium text-sm md:text-lg`}>{t('portfolioSummary')}</p>
        </div>

        {/* AI Insight Section - RWD Optimized */}
        {(aiSummary || isAiLoading) && (
          <div className={`w-full lg:max-w-md p-5 rounded-2xl md:rounded-3xl border transition-all animate-in zoom-in-95 ${isDark ? 'bg-slate-900/60 border-slate-800' : 'bg-violet-50/50 border-violet-100 shadow-sm'}`}>
            <div className="flex items-center gap-2 mb-2">
              <i className="fas fa-brain text-violet-500 text-xs"></i>
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-violet-500">Portfolio Intelligence</span>
            </div>
            {isAiLoading ? (
              <div className="flex gap-1.5 py-1 items-center">
                <div className="w-2 h-2 bg-violet-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-violet-400 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-violet-400 rounded-full animate-bounce delay-150"></div>
                <span className="text-[10px] text-slate-400 font-bold ml-2">Calculating...</span>
              </div>
            ) : (
              <p className={`text-xs md:text-sm font-bold leading-relaxed ${isDark ? 'text-slate-300' : 'text-slate-700'}`}>{aiSummary}</p>
            )}
          </div>
        )}
      </header>

      {/* Responsive Stat Grid */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 md:gap-8">
        <StatCard isDark={isDark} label={t('active')} value={customers.length.toString()} icon="fa-users" color="bg-violet-600" delay="delay-1" />
        <StatCard isDark={isDark} label={t('capital')} value={`₹${totalPrincipal.toLocaleString()}`} icon="fa-money-bill-wave" color={isDark ? 'bg-slate-700' : 'bg-slate-900'} delay="delay-2" />
        <StatCard isDark={isDark} label={t('income')} value={`₹${monthlyIncome.toLocaleString()}`} icon="fa-hand-holding-dollar" color="bg-violet-500" delay="delay-3" />
        <StatCard isDark={isDark} label={t('action')} value={overdue.length.toString()} icon="fa-clock" color="bg-rose-500" delay="delay-1" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-10">
        <section className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-5 md:p-10 rounded-[2rem] border shadow-sm animate-in delay-2`}>
          <h3 className={`text-xl md:text-2xl font-black mb-6 md:mb-8 flex items-center gap-4 uppercase tracking-tight ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>
            <span className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl ${isDark ? 'bg-violet-900/40 text-violet-400' : 'bg-violet-100 text-violet-600'} flex items-center justify-center shadow-inner`}>
              <i className="fas fa-calendar-day text-sm md:text-lg"></i>
            </span>
            {t('dueToday')}
          </h3>
          <div className="space-y-4">
            {dueToday.length > 0 ? (
              dueToday.map(c => (
                <div key={c.id} className={`flex justify-between items-center p-4 md:p-6 rounded-2xl md:rounded-3xl border border-transparent transition-all ${isDark ? 'hover:bg-slate-800 hover:border-slate-700' : 'hover:bg-slate-50 hover:border-slate-100'}`}>
                  <div className="min-w-0 flex-1 pr-4">
                    <p className={`font-black text-sm md:text-base truncate ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>{c.name}</p>
                    <p className={`text-[10px] md:text-xs font-bold uppercase ${isDark ? 'text-slate-500' : 'text-slate-400'}`}>{c.phone}</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <a 
                      href={`tel:${c.phone}`}
                      className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center transition-all shadow-sm shrink-0 ${isDark ? 'bg-emerald-900/20 text-emerald-400 hover:bg-emerald-900/40' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'}`}
                      title="Call Borrower"
                    >
                      <i className="fas fa-phone text-xs md:text-sm"></i>
                    </a>
                    <div className="text-right shrink-0">
                      <p className="font-black text-violet-600 text-sm md:text-base">₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                      <Link to={`/customers/${c.id}`} className="text-[10px] md:text-xs font-black uppercase text-violet-400 hover:text-violet-600">{t('details')}</Link>
                    </div>
                  </div>
                </div>
              ))
            ) : <div className="text-center py-20 text-slate-300 uppercase tracking-widest text-xs font-black opacity-60">Nothing due today</div>}
          </div>
        </section>

        <section className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-5 md:p-10 rounded-[2rem] border shadow-sm animate-in delay-3`}>
          <h3 className={`text-xl md:text-2xl font-black mb-6 md:mb-8 flex items-center gap-4 uppercase tracking-tight ${isDark ? 'text-slate-100' : 'text-slate-800'}`}>
            <span className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl ${isDark ? 'bg-rose-900/40 text-rose-400' : 'bg-rose-100 text-rose-600'} flex items-center justify-center shadow-inner`}>
              <i className="fas fa-exclamation-triangle text-sm md:text-lg"></i>
            </span>
            {t('overdue')}
          </h3>
          <div className="space-y-4">
            {overdue.length > 0 ? (
              overdue.map(c => (
                <div key={c.id} className={`flex justify-between items-center p-4 md:p-6 rounded-2xl md:rounded-3xl border transition-all ${isDark ? 'bg-rose-900/20 border-rose-900/40' : 'bg-rose-50/40 border-rose-100'}`}>
                  <div className="min-w-0 flex-1 pr-4">
                    <p className={`font-black text-sm md:text-base truncate ${isDark ? 'text-rose-100' : 'text-rose-900'}`}>{c.name}</p>
                    <p className={`text-[10px] md:text-xs font-black uppercase ${isDark ? 'text-rose-400/60' : 'text-rose-400'}`}>{t('due')}: {c.dueDate}th</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <a 
                      href={`tel:${c.phone}`}
                      className={`w-10 h-10 md:w-12 md:h-12 rounded-xl md:rounded-2xl flex items-center justify-center transition-all shadow-sm shrink-0 ${isDark ? 'bg-emerald-900/20 text-emerald-400 hover:bg-emerald-900/40' : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'}`}
                      title="Call Borrower"
                    >
                      <i className="fas fa-phone text-xs md:text-sm"></i>
                    </a>
                    <div className="text-right shrink-0">
                      <p className={`font-black text-sm md:text-base ${isDark ? 'text-rose-400' : 'text-rose-700'}`}>₹{(c.principal * c.interestRate / 100).toLocaleString()}</p>
                      <Link to={`/customers/${c.id}`} className="text-[10px] md:text-xs font-black uppercase text-rose-500 hover:underline">{t('collect')}</Link>
                    </div>
                  </div>
                </div>
              ))
            ) : <div className="text-center py-20 text-slate-300 uppercase tracking-widest text-xs font-black opacity-60">All collections current</div>}
          </div>
        </section>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ label: string; value: string; icon: string; color: string; delay?: string; isDark: boolean }> = ({ label, value, icon, color, delay, isDark }) => (
  <div className={`${isDark ? 'bg-slate-900/50 border-slate-800' : 'bg-white'} p-5 md:p-10 rounded-[1.5rem] md:rounded-[3rem] border shadow-sm flex flex-col items-center justify-center gap-4 animate-in ${delay} hover:shadow-xl transition-all group active:scale-95`}>
    <div className={`${color} w-12 h-12 md:w-20 md:h-20 rounded-2xl md:rounded-3xl flex items-center justify-center text-white text-xl md:text-3xl shadow-lg transition-transform group-hover:scale-110`}><i className={`fas ${icon}`}></i></div>
    <div className="text-center min-w-0 w-full">
      <p className="text-[10px] md:text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-1 truncate">{label}</p>
      <p className={`text-sm md:text-2xl font-black leading-tight truncate ${isDark ? 'text-slate-100' : 'text-slate-900'}`}>{value}</p>
    </div>
  </div>
);

export default Dashboard;
